-- Generated by scripts/build-questions-seed.mjs
-- Idempotent: deletes existing rows before insert.
begin;
delete from practice_questions;
insert into practice_questions (external_key, subtest, topic_id, difficulty, stem, choices, correct_index, explanation, active) values
  ('GS-1', 'GS', 'gs.life-science', 2, 'Which organ is primarily responsible for filtering waste products from the blood and producing urine?', '["Liver","Kidney","Pancreas","Spleen"]'::jsonb, 1, 'The kidneys filter blood to remove waste products and excess water, which are excreted as urine. The liver processes nutrients and detoxifies chemicals but does not produce urine.', true),
  ('GS-2', 'GS', 'gs.physical-science', 2, 'Water (H₂O) is best classified as which of the following?', '["An element","A compound","A mixture","An isotope"]'::jsonb, 1, 'Water is a compound because it consists of two different elements — hydrogen and oxygen — chemically bonded in a fixed ratio. An element contains only one type of atom.', true),
  ('GS-3', 'GS', 'gs.earth-space-science', 2, 'Which layer of Earth''s atmosphere contains the ozone layer that absorbs most of the sun''s ultraviolet radiation?', '["Troposphere","Mesosphere","Stratosphere","Thermosphere"]'::jsonb, 2, 'The stratosphere, roughly 10–50 km above Earth''s surface, contains the ozone layer. The troposphere is the lowest layer where most weather occurs.', true),
  ('AR-1', 'AR', 'ar.rate-distance-time', 2, 'A car travels at 55 miles per hour. How many miles will it travel in 3 hours and 30 minutes?', '["165 miles","182.5 miles","192.5 miles","198 miles"]'::jsonb, 2, '3 hours 30 minutes = 3.5 hours. Distance = 55 × 3.5 = 192.5 miles.', true),
  ('AR-2', 'AR', 'ar.percent', 2, 'A store marks up an item by 40% from its wholesale cost of $35. What is the retail selling price?', '["$14.00","$45.50","$49.00","$52.50"]'::jsonb, 2, 'Markup = 40% × $35 = $14. Retail price = $35 + $14 = $49.00.', true),
  ('AR-3', 'AR', 'ar.ratio-proportion', 2, 'A recipe calls for flour and sugar in a ratio of 5:2. If you use 20 cups of flour, how many cups of sugar are needed?', '["4 cups","6 cups","8 cups","10 cups"]'::jsonb, 2, 'With a 5:2 ratio, sugar = (2/5) × 20 = 8 cups.', true),
  ('AR-4', 'AR', 'ar.percent', 2, 'A soldier earns $2,400 per month and saves 15% of that amount. After 6 months, how much has the soldier saved?', '["$1,440","$2,160","$2,400","$3,600"]'::jsonb, 1, 'Monthly savings = 15% × $2,400 = $360. Over 6 months: $360 × 6 = $2,160.', true),
  ('WK-1', 'WK', 'wk.synonyms', 1, 'ARID most nearly means:', '["Damp","Stormy","Dry","Fertile"]'::jsonb, 2, 'Arid means extremely dry, with little or no rain. It is commonly used to describe deserts or climates with very low precipitation.', true),
  ('WK-2', 'WK', 'wk.synonyms', 2, 'PRUDENT most nearly means:', '["Reckless","Cautious","Generous","Stubborn"]'::jsonb, 1, 'Prudent means acting with care and good judgment to avoid risk. It is the opposite of reckless.', true),
  ('WK-3', 'WK', 'wk.synonyms', 1, 'CONCISE most nearly means:', '["Wordy","Unclear","Brief","Detailed"]'::jsonb, 2, 'Concise means expressing information clearly in few words. It contrasts with wordy or verbose communication.', true),
  ('WK-4', 'WK', 'wk.synonyms', 2, 'OMINOUS most nearly means:', '["Cheerful","Threatening","Ordinary","Surprising"]'::jsonb, 1, 'Ominous means giving the impression that something bad or unpleasant is going to happen; it is synonymous with threatening or foreboding.', true),
  ('PC-1', 'PC', 'pc.main-idea', 2, 'Read the following passage and answer the question.

"Solar panels convert sunlight directly into electricity using photovoltaic cells. Unlike fossil fuels, solar energy produces no emissions during operation, making it one of the cleanest energy sources available."

What is the main idea of this passage?', '["Fossil fuels are harmful to the environment.","Solar panels require no maintenance.","Solar energy is a clean electricity source that uses photovoltaic cells.","Photovoltaic cells are expensive to manufacture."]'::jsonb, 2, 'The passage introduces how solar panels work and emphasizes that solar energy is clean and emission-free — that combination is the central point.', true),
  ('PC-2', 'PC', 'pc.inference', 2, 'Read the following passage and answer the question.

"The base commander issued new physical fitness standards requiring all personnel to complete a 2-mile run in under 18 minutes. Soldiers who fail to meet the standard will be enrolled in a remedial training program."

What can be inferred about soldiers who complete the run in exactly 18 minutes?', '["They will receive an award.","They will be enrolled in remedial training.","They have exceeded the standard.","They will be exempt from future tests."]'::jsonb, 1, 'The standard requires completing the run in under 18 minutes. Exactly 18 minutes does not meet the ''under 18'' requirement, so those soldiers would be enrolled in remedial training.', true),
  ('PC-3', 'PC', 'pc.detail-recall', 2, 'Read the following passage and answer the question.

"Dehydration impairs both physical and cognitive performance. Even a 2% loss of body water can reduce a person''s ability to concentrate and make decisions. Military personnel operating in hot climates must monitor fluid intake closely."

According to the passage, what effect does mild dehydration have?', '["It causes permanent cognitive damage.","It has no effect below 5% fluid loss.","It reduces the ability to concentrate and make decisions.","It only affects physical performance, not mental performance."]'::jsonb, 2, 'The passage explicitly states that a 2% loss of body water can reduce concentration and decision-making ability, affecting both physical and cognitive performance.', true),
  ('MK-1', 'MK', 'mk.geometry', 2, 'A rectangular room measures 14 feet long and 9 feet wide. What is the area of the room?', '["46 square feet","92 square feet","126 square feet","132 square feet"]'::jsonb, 2, 'Area of a rectangle = length × width = 14 × 9 = 126 square feet.', true),
  ('MK-2', 'MK', 'mk.algebra-linear', 1, 'Solve for x: 3x − 7 = 14', '["x = 3","x = 5","x = 7","x = 9"]'::jsonb, 2, 'Add 7 to both sides: 3x = 21. Divide by 3: x = 7.', true),
  ('MK-3', 'MK', 'mk.exponents-polynomials', 1, 'What is the value of 2⁵?', '["10","16","25","32"]'::jsonb, 3, '2⁵ = 2 × 2 × 2 × 2 × 2 = 32.', true),
  ('MK-4', 'MK', 'mk.fractions-decimals', 2, 'What is ³⁄₄ divided by ³⁄₈?', '["½","1","2","9⁄32"]'::jsonb, 2, 'Dividing by a fraction means multiplying by its reciprocal: ³⁄₄ × ⁸⁄₃ = 24⁄12 = 2.', true),
  ('EI-1', 'EI', 'ei.ohms-law-power', 2, 'A circuit has a voltage of 12 volts and a resistance of 4 ohms. According to Ohm''s Law, what is the current flowing through the circuit?', '["0.33 amperes","3 amperes","8 amperes","48 amperes"]'::jsonb, 1, 'Ohm''s Law: I = V ÷ R = 12 ÷ 4 = 3 amperes.', true),
  ('EI-2', 'EI', 'ei.circuit-types', 2, 'In a series circuit with three light bulbs, one bulb burns out. What happens to the other two bulbs?', '["They burn brighter.","They continue operating normally.","They also go out.","They flicker but stay on."]'::jsonb, 2, 'In a series circuit, all components share a single path for current. If one bulb fails (opens the circuit), current cannot flow and all other bulbs go out.', true),
  ('EI-3', 'EI', 'ei.components-devices', 1, 'What unit is used to measure electrical resistance?', '["Volt","Ampere","Watt","Ohm"]'::jsonb, 3, 'Resistance is measured in ohms (Ω). Volts measure voltage, amperes measure current, and watts measure power.', true),
  ('AS-1', 'AS', 'as.hand-tools', 2, 'Which tool is best suited for tightening a bolt that is in a recessed or hard-to-reach location?', '["Open-end wrench","Socket wrench with extension","Adjustable pliers","Torque screwdriver"]'::jsonb, 1, 'A socket wrench with an extension bar allows a technician to reach fasteners in deep or confined spaces where an open-end wrench cannot fit.', true),
  ('AS-2', 'AS', 'as.vehicle-systems', 2, 'What is the primary function of a vehicle''s radiator?', '["Filter engine oil","Regulate fuel mixture","Dissipate heat from the engine coolant","Reduce exhaust emissions"]'::jsonb, 2, 'The radiator removes heat from the engine coolant by passing it through thin fins where air flow carries the heat away, preventing engine overheating.', true),
  ('AS-3', 'AS', 'as.shop-safety', 1, 'Before operating a power saw in a shop, you should FIRST:', '["Test the blade on scrap wood","Put on appropriate eye protection","Plug in the saw and let it warm up","Check the sharpness of the blade by touch"]'::jsonb, 1, 'Personal protective equipment — especially eye protection — must be donned before any shop operation begins. Blade fragments and sawdust present immediate eye hazards.', true),
  ('MC-1', 'MC', 'mc.levers-pulleys', 2, 'A 10-pound weight is placed 6 feet from the fulcrum of a lever. To balance it, how far from the fulcrum must a 15-pound weight be placed on the opposite side?', '["2 feet","4 feet","6 feet","9 feet"]'::jsonb, 1, 'Lever balance: W₁ × D₁ = W₂ × D₂ → 10 × 6 = 15 × D₂ → D₂ = 60 ÷ 15 = 4 feet.', true),
  ('MC-2', 'MC', 'mc.gears-wheels', 3, 'If a small gear with 10 teeth meshes with a large gear with 40 teeth, and the small gear rotates at 200 RPM, how fast does the large gear rotate?', '["25 RPM","50 RPM","100 RPM","800 RPM"]'::jsonb, 1, 'Gear ratio = 10/40 = 1/4. Large gear RPM = 200 × (10/40) = 200 × 0.25 = 50 RPM.', true),
  ('MC-3', 'MC', 'mc.forces-friction', 2, 'A 200-pound crate is resting on a flat surface. If you push it horizontally with a force of 50 pounds and it does not move, what is the force of friction acting on the crate?', '["0 pounds","50 pounds","150 pounds","200 pounds"]'::jsonb, 1, 'Since the crate is stationary (not accelerating), the net force is zero. Static friction exactly opposes the applied force, so friction = 50 pounds.', true),
  ('AO-1', 'AO', 'ao.3d-visualization', 3, 'A flat piece of material is cut into four identical right triangles, each with legs of equal length. If all four triangles are arranged so their right-angle corners meet at a center point, what shape do they form?', '["A circle","A rectangle","A square","A hexagon"]'::jsonb, 2, 'Four identical isosceles right triangles placed with their right angles at a common center and hypotenuses facing outward form a perfect square.', true),
  ('AO-2', 'AO', 'ao.paper-folding-nets', 1, 'A rectangular piece of paper is folded in half along its longest axis, then folded in half again along the same axis. When unfolded, how many equal sections does the paper have?', '["2","3","4","6"]'::jsonb, 2, 'Each fold doubles the number of sections. One fold → 2 sections; two folds → 4 equal sections.', true),
  ('AO-3', 'AO', 'ao.spatial-counting', 4, 'A cube is painted red on all six faces and then cut into 27 equal smaller cubes (a 3×3×3 grid). How many of the small cubes have paint on exactly two faces?', '["6","8","12","24"]'::jsonb, 2, 'Cubes with paint on exactly two faces sit along the edges (not corners) of the larger cube. A 3×3×3 cube has 12 edges, each contributing 1 such cube, giving 12 total.', true),
  ('GS-4', 'GS', 'gs.earth-space-science', 2, 'Which type of rock is formed when molten magma cools and solidifies?', '["Sedimentary","Metamorphic","Igneous","Organic"]'::jsonb, 2, 'Igneous rocks form from the cooling of molten rock (magma or lava). Sedimentary rocks form from compacted sediments, and metamorphic rocks form under heat and pressure.', true),
  ('GS-5', 'GS', 'gs.life-science', 2, 'Which of the following best describes the function of red blood cells?', '["Fight infection by producing antibodies","Transport oxygen throughout the body","Regulate blood clotting","Produce hormones"]'::jsonb, 1, 'Red blood cells (erythrocytes) contain hemoglobin, which binds to oxygen in the lungs and delivers it to tissues throughout the body.', true),
  ('GS-6', 'GS', 'gs.physics-mechanics', 2, 'Newton''s Third Law of Motion states that for every action there is:', '["An equal but delayed reaction","A greater and opposite reaction","An equal and opposite reaction","A proportional and parallel reaction"]'::jsonb, 2, 'Newton''s Third Law states that for every action force, there is an equal in magnitude and opposite in direction reaction force. This explains recoil, rocket propulsion, and walking.', true),
  ('AR-5', 'AR', 'ar.word-problems', 3, 'A tank holds 500 gallons of water. It drains at a rate of 25 gallons per minute and fills at 10 gallons per minute simultaneously. Starting with a full tank, how many minutes will it take to empty?', '["20 minutes","25 minutes","33 minutes","50 minutes"]'::jsonb, 2, 'Net drain rate = 25 − 10 = 15 gallons per minute. Time = 500 ÷ 15 ≈ 33.3, so approximately 33 minutes.', true),
  ('AR-6', 'AR', 'ar.arithmetic-fundamentals', 1, 'A platoon of 40 soldiers must carry 480 pounds of equipment equally. How many pounds does each soldier carry?', '["10 pounds","12 pounds","14 pounds","16 pounds"]'::jsonb, 1, '480 ÷ 40 = 12 pounds per soldier.', true),
  ('AR-7', 'AR', 'ar.percent', 2, 'A shirt originally priced at $60 is on sale for 25% off. What is the sale price?', '["$15","$40","$45","$50"]'::jsonb, 2, 'Discount = 25% × $60 = $15. Sale price = $60 − $15 = $45.', true),
  ('AR-8', 'AR', 'ar.word-problems', 4, 'Two workers can paint a room in 6 hours working together. If one worker can complete the job alone in 10 hours, how long would the second worker take alone?', '["12 hours","15 hours","16 hours","20 hours"]'::jsonb, 1, 'Combined rate = 1/6 room/hr. Worker 1 rate = 1/10. Worker 2 rate = 1/6 − 1/10 = 5/30 − 3/30 = 2/30 = 1/15. So Worker 2 takes 15 hours.', true),
  ('WK-5', 'WK', 'wk.synonyms', 2, 'TENACIOUS most nearly means:', '["Fragile","Persistent","Timid","Generous"]'::jsonb, 1, 'Tenacious means holding firmly to a purpose or position; persistent and determined. It implies stubbornness in a positive sense.', true),
  ('WK-6', 'WK', 'wk.synonyms', 2, 'AMBIGUOUS most nearly means:', '["Certain","Unclear","Ambitious","Honest"]'::jsonb, 1, 'Ambiguous means open to more than one interpretation; not having a clear meaning. It is distinct from ambitious, which relates to goals.', true),
  ('WK-7', 'WK', 'wk.synonyms', 1, 'VALIDATE most nearly means:', '["Deny","Confirm","Improve","Replace"]'::jsonb, 1, 'To validate means to confirm or check the accuracy or legitimacy of something. It is synonymous with verify or confirm.', true),
  ('WK-8', 'WK', 'wk.synonyms', 2, 'AUSTERE most nearly means:', '["Luxurious","Severe","Colorful","Warm"]'::jsonb, 1, 'Austere means severe or strict in manner or appearance; lacking comfort or ornament. It describes a plain, unadorned quality.', true),
  ('PC-4', 'PC', 'pc.inference', 2, 'Read the following passage and answer the question.

"The bald eagle was removed from the Endangered Species List in 2007, a success story for wildlife conservation. Once nearly extinct due to hunting and pesticide use, the population rebounded after DDT was banned in 1972 and legal protections were enacted."

What was the primary cause of the bald eagle''s recovery?', '["Captive breeding programs introduced thousands of new birds.","A ban on DDT and legal protections allowed the population to rebound.","Bald eagles adapted to living in urban environments.","Congress funded a national eagle relocation program."]'::jsonb, 1, 'The passage directly credits the banning of DDT and legal protections as the reasons for the population''s recovery.', true),
  ('PC-5', 'PC', 'pc.detail-recall', 2, 'Read the following passage and answer the question.

"Hypothermia occurs when the body loses heat faster than it can produce it, causing core body temperature to fall below 95°F. Symptoms progress from shivering and confusion to loss of coordination and, eventually, unconsciousness. Immediate warming and medical attention are critical."

According to the passage, which symptom appears first?', '["Unconsciousness","Loss of coordination","Shivering and confusion","Cardiac arrest"]'::jsonb, 2, 'The passage states that symptoms ''progress from shivering and confusion,'' meaning those are the earliest symptoms listed.', true),
  ('PC-6', 'PC', 'pc.detail-recall', 1, 'Read the following passage and answer the question.

"A convoy must maintain a 100-meter interval between vehicles at all times. Closing the gap increases the risk of collision if the lead vehicle stops suddenly. Drivers are responsible for maintaining their own interval regardless of road conditions."

Who is responsible for maintaining the correct vehicle interval?', '["The convoy commander","The lead vehicle driver","Each individual driver","The vehicle navigator"]'::jsonb, 2, 'The passage explicitly states that ''drivers are responsible for maintaining their own interval,'' making each individual driver responsible.', true),
  ('MK-5', 'MK', 'mk.geometry', 1, 'What is the perimeter of a square with a side length of 11 inches?', '["22 inches","33 inches","44 inches","121 inches"]'::jsonb, 2, 'Perimeter of a square = 4 × side = 4 × 11 = 44 inches.', true),
  ('MK-6', 'MK', 'mk.algebra-linear', 2, 'Solve for y: 5y + 3 = 2y + 18', '["y = 3","y = 5","y = 7","y = 9"]'::jsonb, 1, 'Subtract 2y from both sides: 3y + 3 = 18. Subtract 3: 3y = 15. Divide: y = 5.', true),
  ('MK-7', 'MK', 'mk.geometry', 2, 'A right triangle has legs measuring 6 cm and 8 cm. What is the length of the hypotenuse?', '["7 cm","10 cm","12 cm","14 cm"]'::jsonb, 1, 'By the Pythagorean theorem: c² = 6² + 8² = 36 + 64 = 100. c = √100 = 10 cm.', true),
  ('MK-8', 'MK', 'mk.fractions-decimals', 1, 'What is 15% of 240?', '["30","36","40","42"]'::jsonb, 1, '15% × 240 = 0.15 × 240 = 36.', true),
  ('EI-4', 'EI', 'ei.components-devices', 2, 'Which component in an electrical circuit allows current to flow in only one direction?', '["Resistor","Capacitor","Diode","Transformer"]'::jsonb, 2, 'A diode is a semiconductor device that permits current to flow in one direction only. It is commonly used to convert AC to DC in rectifier circuits.', true),
  ('EI-5', 'EI', 'ei.ohms-law-power', 2, 'A 60-watt light bulb operates on a 120-volt circuit. What is the current drawn by the bulb?', '["0.25 amperes","0.5 amperes","2 amperes","7,200 amperes"]'::jsonb, 1, 'Power (P) = Voltage (V) × Current (I). Solving for I: I = P ÷ V = 60 ÷ 120 = 0.5 amperes.', true),
  ('EI-6', 'EI', 'ei.components-devices', 2, 'What is the purpose of a fuse in an electrical circuit?', '["Increase voltage to components","Store electrical charge","Protect the circuit by breaking if current exceeds a safe level","Regulate alternating current frequency"]'::jsonb, 2, 'A fuse contains a thin metal element that melts and breaks the circuit if current exceeds its rated value, protecting wiring and components from damage.', true),
  ('AS-4', 'AS', 'as.vehicle-systems', 2, 'What does a vehicle''s alternator do while the engine is running?', '["Starts the engine by cranking it","Recharges the battery and powers electrical systems","Controls fuel injection timing","Regulates engine coolant temperature"]'::jsonb, 1, 'The alternator converts mechanical energy from the engine into electrical energy, recharging the battery and supplying power to the vehicle''s electrical systems while the engine runs.', true),
  ('AS-5', 'AS', 'as.hand-tools', 1, 'Which type of screwdriver is designed to fit a screw head with an X-shaped slot?', '["Flathead screwdriver","Torx screwdriver","Phillips screwdriver","Hex screwdriver"]'::jsonb, 2, 'A Phillips screwdriver has a cross-shaped tip designed to fit X-shaped (Phillips) screw head recesses, providing better torque than a flathead.', true),
  ('AS-6', 'AS', 'as.maintenance-repair', 2, 'When should a vehicle''s engine oil be replaced most regularly, according to general maintenance practice?', '["Only when the oil pressure warning light activates","At every fuel fill-up","At intervals recommended by the manufacturer, typically based on mileage or time","Once per year regardless of mileage"]'::jsonb, 2, 'Manufacturers specify oil change intervals (commonly every 3,000–7,500 miles or more with synthetic oil) based on engineering data. Following these intervals prevents engine wear.', true),
  ('MC-4', 'MC', 'mc.gears-wheels', 2, 'A wheel and axle system has a wheel with a radius of 12 inches and an axle with a radius of 3 inches. What is the mechanical advantage of this system?', '["2","3","4","6"]'::jsonb, 2, 'Mechanical advantage of a wheel and axle = wheel radius ÷ axle radius = 12 ÷ 3 = 4.', true),
  ('MC-5', 'MC', 'mc.levers-pulleys', 2, 'A fixed pulley changes the direction of force but does NOT change the amount of force required. Which statement about a fixed pulley is correct?', '["It reduces the force needed by half.","It multiplies the force by the number of rope segments.","It redirects the force without any mechanical advantage.","It eliminates the effect of gravity on the load."]'::jsonb, 2, 'A single fixed pulley only redirects the pulling force; it does not reduce the effort required to lift the load. Mechanical advantage = 1.', true),
  ('MC-6', 'MC', 'mc.forces-friction', 2, 'Which of the following changes would increase the pressure exerted by a block resting on a table?', '["Tilting the block at a 45-degree angle","Increasing the surface area in contact with the table","Placing the block on a smaller face so less area contacts the table","Moving the block to the center of the table"]'::jsonb, 2, 'Pressure = Force ÷ Area. Reducing the contact area while keeping the weight the same increases the pressure, since the same force is concentrated on a smaller surface.', true),
  ('AO-4', 'AO', 'ao.paper-folding-nets', 2, 'A square piece of cardboard has a small square cut from each of its four corners. When the sides are folded up along the cut lines, what shape is formed?', '["A pyramid","An open-top box","A cylinder","A cone"]'::jsonb, 1, 'Cutting squares from each corner and folding up the resulting flaps creates an open-top rectangular box — a standard net-folding construction.', true),
  ('AO-5', 'AO', 'ao.3d-visualization', 2, 'A solid cylinder is sliced straight down through its center from top to bottom (a vertical cut through the axis). What shape is the cross-section?', '["Circle","Ellipse","Rectangle","Triangle"]'::jsonb, 2, 'Cutting a cylinder along its axis (lengthwise through the center) produces a rectangular cross-section whose width equals the cylinder''s diameter and height equals its length.', true),
  ('AO-6', 'AO', 'ao.spatial-counting', 3, 'Three identical equilateral triangles are placed so that one vertex of each meets at a common center point and the triangles do not overlap. What is the total interior angle at the center point?', '["180 degrees","240 degrees","270 degrees","360 degrees"]'::jsonb, 0, 'Three equilateral triangles meeting at a vertex contribute their three 60° interior corners. Total angle contribution = 3 × 60° = 180°. The ‘angles around a point sum to 360°’ rule applies only when shapes tile the entire space around the point — here they don’t, since 180° leaves 180° of the surrounding plane uncovered.', true),
  ('GS-7', 'GS', 'gs.life-science', 2, 'Photosynthesis in plants primarily uses which two resources to produce glucose?', '["Oxygen and nitrogen","Carbon dioxide and water","Glucose and oxygen","Nitrogen and phosphorus"]'::jsonb, 1, 'Plants use carbon dioxide (CO₂) from the air and water (H₂O) from the soil, along with sunlight energy, to produce glucose through photosynthesis.', true),
  ('GS-8', 'GS', 'gs.earth-space-science', 1, 'Which planet in our solar system is largest by diameter?', '["Saturn","Neptune","Jupiter","Uranus"]'::jsonb, 2, 'Jupiter is the largest planet in the solar system, with a diameter of about 143,000 km — more than 11 times the diameter of Earth.', true),
  ('GS-9', 'GS', 'gs.physical-science', 2, 'In an acid-base reaction, the pH of a neutral solution is:', '["0","7","10","14"]'::jsonb, 1, 'The pH scale runs from 0 (most acidic) to 14 (most basic/alkaline). A pH of 7 represents a neutral solution, such as pure water.', true),
  ('AR-9', 'AR', 'ar.ratio-proportion', 2, 'If 5 pens cost $3.75, what is the cost of 8 pens at the same price?', '["$5.00","$5.60","$6.00","$6.25"]'::jsonb, 2, 'Price per pen = $3.75 ÷ 5 = $0.75. Cost of 8 pens = 8 × $0.75 = $6.00.', true),
  ('AR-10', 'AR', 'ar.arithmetic-fundamentals', 2, 'A rectangular field is 120 yards long and 80 yards wide. What is its area in square yards?', '["4,800","8,400","9,600","10,400"]'::jsonb, 2, 'Area = length × width = 120 × 80 = 9,600 square yards.', true),
  ('AR-11', 'AR', 'ar.rate-distance-time', 3, 'A train leaves a station at 9:00 AM traveling at 60 mph. A second train leaves the same station at 10:00 AM traveling in the same direction at 90 mph. At what time does the second train catch up to the first?', '["11:00 AM","12:00 PM","12:30 PM","1:00 PM"]'::jsonb, 1, 'After 1 hour, Train 1 is 60 miles ahead. Closing rate = 90 − 60 = 30 mph. Time to close gap = 60 ÷ 30 = 2 hours after 10:00 AM = 12:00 PM.', true),
  ('AR-12', 'AR', 'ar.ratio-proportion', 2, 'A map has a scale of 1 inch = 50 miles. Two cities are 3.5 inches apart on the map. What is the actual distance between them?', '["150 miles","175 miles","200 miles","225 miles"]'::jsonb, 1, 'Actual distance = 3.5 × 50 = 175 miles.', true),
  ('WK-9', 'WK', 'wk.synonyms', 2, 'DILIGENT most nearly means:', '["Lazy","Careful","Hardworking","Honest"]'::jsonb, 2, 'Diligent means showing steady, earnest effort in one''s work or duties. It is closest in meaning to hardworking or industrious.', true),
  ('WK-10', 'WK', 'wk.synonyms', 2, 'VOLATILE most nearly means:', '["Stable","Unstable","Heavy","Silent"]'::jsonb, 1, 'Volatile describes something that is liable to change rapidly and unpredictably, especially for the worse. It suggests instability or explosiveness.', true),
  ('WK-11', 'WK', 'wk.synonyms', 2, 'EXPEDITE most nearly means:', '["Delay","Organize","Accelerate","Evaluate"]'::jsonb, 2, 'To expedite means to speed up the process of something; to cause it to happen more quickly. It is synonymous with accelerate or hasten.', true),
  ('WK-12', 'WK', 'wk.synonyms', 2, 'METICULOUS most nearly means:', '["Careless","Precise","Modest","Flexible"]'::jsonb, 1, 'Meticulous means showing great attention to detail; very careful and precise. It describes someone who is thorough and exact.', true),
  ('PC-7', 'PC', 'pc.inference', 3, 'Read the following passage and answer the question.

"Antibiotics are effective against bacterial infections but have no effect on viral illnesses such as the common cold or influenza. Overuse of antibiotics has led to the emergence of drug-resistant bacteria, which pose a significant public health threat."

What conclusion can be drawn from this passage?', '["Antibiotics should be prescribed for all infections to prevent complications.","Viral and bacterial infections require the same treatment.","Using antibiotics unnecessarily contributes to antibiotic resistance.","The common cold can be cured with the right antibiotic."]'::jsonb, 2, 'The passage states that overuse of antibiotics leads to drug-resistant bacteria, implying that using them when unnecessary worsens the resistance problem.', true),
  ('PC-8', 'PC', 'pc.detail-recall', 2, 'Read the following passage and answer the question.

"Night vision devices amplify existing light, such as moonlight or starlight, to allow soldiers to see in low-light environments. Unlike infrared thermal devices, which detect heat signatures, night vision devices cannot function in complete darkness."

What is one limitation of night vision devices mentioned in the passage?', '["They are too heavy for field use.","They detect heat signatures rather than light.","They cannot function in complete darkness.","They can only be used by specially trained soldiers."]'::jsonb, 2, 'The passage explicitly states that night vision devices cannot function in complete darkness because they amplify existing light and require some ambient light to work.', true),
  ('PC-9', 'PC', 'pc.main-idea', 2, 'Read the following passage and answer the question.

"The Army''s supply chain relies on a system known as LOGCAP (Logistics Civil Augmentation Program), which contracts civilian companies to provide support services in combat zones. This allows military units to focus on combat operations rather than logistics management."

What is the main purpose of LOGCAP according to the passage?', '["To replace all military logistics units with civilian workers","To allow military units to concentrate on combat by outsourcing support services","To reduce the overall size of the military budget","To train civilian contractors in military combat tactics"]'::jsonb, 1, 'The passage states that LOGCAP contracts civilian companies for support services specifically so that military units can focus on combat operations.', true),
  ('MK-9', 'MK', 'mk.exponents-polynomials', 2, 'Simplify: (3x²)(4x³)', '["7x⁵","12x⁵","12x⁶","7x⁶"]'::jsonb, 1, 'Multiply coefficients: 3 × 4 = 12. Add exponents: x² × x³ = x⁵. Result: 12x⁵.', true),
  ('MK-10', 'MK', 'mk.geometry', 2, 'What is the circumference of a circle with a diameter of 10 inches? (Use π ≈ 3.14)', '["15.7 inches","31.4 inches","78.5 inches","314 inches"]'::jsonb, 1, 'Circumference = π × diameter = 3.14 × 10 = 31.4 inches.', true),
  ('MK-11', 'MK', 'mk.fractions-decimals', 2, 'If the ratio of boys to girls in a class is 3:5 and there are 24 boys, how many girls are in the class?', '["32","36","40","48"]'::jsonb, 2, 'Girls = (5/3) × 24 = 40.', true),
  ('MK-12', 'MK', 'mk.number-properties', 1, 'Evaluate: |−18| + |5|', '["−13","13","23","−23"]'::jsonb, 2, 'Absolute value removes the sign: |−18| = 18, |5| = 5. Sum = 18 + 5 = 23.', true),
  ('EI-7', 'EI', 'ei.circuit-types', 3, 'Two resistors of 6 ohms each are connected in parallel. What is the total resistance of the combination?', '["12 ohms","6 ohms","3 ohms","1 ohm"]'::jsonb, 2, 'For two equal resistors (R) in parallel, total resistance = R ÷ 2 = 6 ÷ 2 = 3 ohms. Formula: 1/Rt = 1/6 + 1/6 = 2/6, so Rt = 3 ohms.', true),
  ('EI-8', 'EI', 'ei.conductors-insulators', 1, 'Which material is the BEST electrical conductor?', '["Rubber","Glass","Copper","Wood"]'::jsonb, 2, 'Copper is one of the best electrical conductors available and is widely used in wiring. Rubber, glass, and wood are insulators that resist current flow.', true),
  ('EI-9', 'EI', 'ei.components-devices', 3, 'A transformer has 100 turns on its primary coil and 400 turns on its secondary coil. If the primary voltage is 120 volts, what is the secondary voltage?', '["30 volts","120 volts","480 volts","600 volts"]'::jsonb, 2, 'Transformer ratio: Vs/Vp = Ns/Np → Vs = 120 × (400/100) = 120 × 4 = 480 volts.', true),
  ('AS-7', 'AS', 'as.vehicle-systems', 3, 'What is the purpose of a vehicle''s timing belt or timing chain?', '["Transfer power from the transmission to the wheels","Synchronize the rotation of the crankshaft and camshaft","Connect the steering column to the front wheels","Regulate fuel pressure in the injection system"]'::jsonb, 1, 'The timing belt/chain synchronizes the crankshaft and camshaft so that engine valves open and close at the correct times during each piston stroke.', true),
  ('AS-8', 'AS', 'as.hand-tools', 3, 'Which hand tool would you use to measure the outside diameter of a cylindrical metal rod precisely?', '["Tape measure","Inside caliper","Outside micrometer","Combination square"]'::jsonb, 2, 'An outside micrometer provides precise measurements of the outer dimensions of cylindrical objects, with accuracy to thousandths of an inch.', true),
  ('AS-9', 'AS', 'as.shop-safety', 3, 'When welding, the primary purpose of a ground clamp attached to the workpiece is to:', '["Prevent the metal from warping","Complete the electrical circuit for the welding arc","Cool the metal after welding","Indicate the direction of welding travel"]'::jsonb, 1, 'The ground clamp completes the electrical circuit from the welder through the workpiece, allowing current to flow and create the arc needed for welding.', true),
  ('MC-7', 'MC', 'mc.forces-friction', 2, 'If a hydraulic jack applies 10 pounds of force over a piston with an area of 2 square inches, what is the pressure transmitted through the hydraulic fluid?', '["2 psi","5 psi","12 psi","20 psi"]'::jsonb, 1, 'Pressure = Force ÷ Area = 10 ÷ 2 = 5 pounds per square inch (psi). This pressure is transmitted equally throughout the fluid.', true),
  ('MC-8', 'MC', 'mc.motion-projectile', 2, 'A ball rolls off a horizontal table and follows a curved path to the ground. This curved path is an example of which type of motion?', '["Circular motion","Simple harmonic motion","Projectile motion","Linear motion"]'::jsonb, 2, 'When an object has a horizontal velocity and is acted on by gravity, it follows a curved (parabolic) path called projectile motion — a combination of horizontal and vertical components.', true),
  ('MC-9', 'MC', 'mc.inclined-plane-hydraulics', 3, 'In an inclined plane, increasing the length of the ramp while keeping the height constant will:', '["Increase the effort force needed to move the load","Decrease the mechanical advantage","Increase the mechanical advantage by reducing effort force","Have no effect on mechanical advantage"]'::jsonb, 2, 'Mechanical advantage of an inclined plane = ramp length ÷ height. A longer ramp with the same height produces a larger mechanical advantage, reducing the effort force required.', true),
  ('AO-7', 'AO', 'ao.3d-visualization', 1, 'A standard six-sided die is held so that the 1 faces up. Which number is on the face directly opposite the 1?', '["2","4","6","5"]'::jsonb, 2, 'On a standard die, opposite faces always sum to 7. The face opposite the 1 is 6 (1 + 6 = 7).', true),
  ('AO-9', 'AO', 'ao.spatial-counting', 2, 'A 12-inch ruler is broken into two pieces. One piece is twice as long as the other. What are the lengths of the two pieces?', '["3 inches and 9 inches","4 inches and 8 inches","5 inches and 7 inches","6 inches and 6 inches"]'::jsonb, 1, 'Let the shorter piece = x. Then 2x = longer piece. x + 2x = 12 → 3x = 12 → x = 4. The pieces are 4 inches and 8 inches.', true),
  ('WK-CTX-1', 'WK', 'wk.context-clues', 3, 'In the sentence ''The senator''s VERBOSE reply frustrated reporters who needed a simple yes or no,'' the word VERBOSE most nearly means:', '["enthusiastic","evasive","using more words than necessary","difficult to hear"]'::jsonb, 2, 'Verbose means using an unnecessarily large number of words. The clue ''needed a simple yes or no'' signals that the reply was overly wordy, not merely evasive or hard to hear.', true),
  ('WK-CTX-2', 'WK', 'wk.context-clues', 3, 'In the sentence ''After three sleepless days on patrol, the soldiers were so TORPID they could barely lift their rifles,'' the word TORPID most nearly means:', '["alert","sluggish","angry","well-trained"]'::jsonb, 1, 'Torpid means sluggish or mentally/physically inactive. The context clue ''sleepless days'' and ''could barely lift their rifles'' points directly to extreme sluggishness, not anger or alertness.', true),
  ('WK-CTX-4', 'WK', 'wk.context-clues', 4, 'In the sentence ''The commander''s TACITURN nature meant that junior soldiers rarely received direct feedback, leaving them to interpret his single nods as either praise or disapproval,'' the word TACITURN most nearly means:', '["stern and demanding","reluctant to speak","unpredictable in mood","fair but strict"]'::jsonb, 1, 'Taciturn means habitually saying very little. The sentence''s clue is that soldiers got no verbal feedback at all, only nods — indicating a person who rarely speaks, not one who is merely stern or moody.', true),
  ('WK-CTX-5', 'WK', 'wk.context-clues', 3, 'In the sentence ''The hiking trail was so ARDUOUS that even the most experienced climbers needed rest breaks every half mile,'' the word ARDUOUS most nearly means:', '["scenic","demanding","well-marked","narrow"]'::jsonb, 1, 'Arduous means requiring great effort and endurance. ''Even the most experienced climbers needed rest breaks'' signals extreme difficulty, not just narrowness or poor signage.', true),
  ('WK-CTX-6', 'WK', 'wk.context-clues', 4, 'In the sentence ''Her SARDONIC smile told the interviewer she found the question absurd, though she answered politely,'' the word SARDONIC most nearly means:', '["warm and welcoming","mocking or grimly humorous","nervous and tense","bright and enthusiastic"]'::jsonb, 1, 'Sardonic means grimly mocking or cynically humorous. The clue ''found the question absurd'' while still being outwardly polite is characteristic of sardonic expression. Warm or enthusiastic contradicts the implied disdain.', true),
  ('WK-CTX-8', 'WK', 'wk.context-clues', 3, 'In the sentence ''Despite losing power for three days, the team remained RESILIENT and rebuilt the network faster than expected,'' the word RESILIENT most nearly means:', '["resourceful","quick to recover from setbacks","highly trained","well-funded"]'::jsonb, 1, 'Resilient means able to recover quickly from difficulties. ''Despite losing power'' sets up the adversity, and ''rebuilt faster than expected'' confirms swift recovery — the core meaning of resilience.', true),
  ('WK-CTX-9', 'WK', 'wk.context-clues', 4, 'In the sentence ''The general''s IMPERIOUS tone left no doubt that his orders were not suggestions — they were commands,'' the word IMPERIOUS most nearly means:', '["calm and measured","domineering and commanding","persuasive and logical","vague and uncertain"]'::jsonb, 1, 'Imperious means arrogantly domineering. The contrast between ''not suggestions'' and ''commands'' reinforces a tone that expects immediate obedience. Persuasive implies reasoning and choice, which contradicts the passage''s meaning.', true),
  ('WK-CTX-10', 'WK', 'wk.context-clues', 3, 'In the sentence ''The scientist''s HYPOTHESIS, though TENUOUS at first, grew stronger as more experimental data came in,'' the word TENUOUS most nearly means:', '["widely accepted","poorly worded","weak or lacking support","based on observation"]'::jsonb, 2, 'Tenuous means thin or weak, often used to describe an argument or idea with little supporting evidence. The phrase ''grew stronger as more data came in'' confirms it started from a position of minimal support.', true),
  ('WK-CTX-11', 'WK', 'wk.context-clues', 4, 'In the sentence ''The judge''s IMPARTIAL ruling satisfied both sides because neither could claim favoritism,'' the word IMPARTIAL most nearly means:', '["biased toward the defendant","based on strict law","treating all sides equally without favoritism","delivered quickly"]'::jsonb, 2, 'Impartial means not favoring one side over another. ''Neither could claim favoritism'' is the direct context clue. ''Based on strict law'' is tempting but describes method rather than the fairness quality the word captures.', true),
  ('WK-CTX-12', 'WK', 'wk.context-clues', 5, 'In the sentence ''His PERFUNCTORY review of the safety checklist — glancing at it for seconds before signing — nearly cost the crew their lives,'' the word PERFUNCTORY most nearly means:', '["thorough and systematic","done as a formality without real care","delayed and overdue","conducted by a supervisor"]'::jsonb, 1, 'Perfunctory means carried out with minimal effort and as a routine duty, not with genuine care. ''Glancing at it for seconds before signing'' is the exact clue; the near-catastrophe underscores how inadequate it was.', true),
  ('WK-PFX-1', 'WK', 'wk.prefixes-suffixes', 3, 'The word ANTECEDENT contains the prefix ANTE-. Based on that prefix, ANTECEDENT most nearly means:', '["something that comes after","something that came before","something that contradicts","something that repeats"]'::jsonb, 1, 'ANTE- means before or preceding (compare: antebellum, anteroom). An antecedent is a thing or event that came before another. ANTI- (against) is the common confusion, but the spelling here is ANTE-.', true),
  ('WK-PFX-2', 'WK', 'wk.prefixes-suffixes', 3, 'The word BENEVOLENT contains the root VOL (wish, will) and the prefix BENE-. BENEVOLENT most nearly means:', '["well-wishing or kind","all-powerful","voluntary","truthful"]'::jsonb, 0, 'BENE- means well or good (benefit, benefactor). Combined with -VOL- (wish), benevolent means well-wishing or kindly disposed. Voluntary shares the same root but a different prefix.', true),
  ('WK-PFX-3', 'WK', 'wk.prefixes-suffixes', 3, 'The suffix -LOGY means the study of. CHRONOLOGY is therefore best defined as:', '["the science of timekeeping devices","the arrangement of events in time order","a record of weather patterns","the study of ancient languages"]'::jsonb, 1, 'CHRONO- means time; -LOGY means study or systematic knowledge. Chronology is the arrangement and study of events in time sequence. A chronograph measures time but -GRAPH means write or record, not study.', true),
  ('WK-PFX-4', 'WK', 'wk.prefixes-suffixes', 4, 'The word CIRCUMSPECT contains the prefix CIRCUM- (around) and the root SPECT (look). CIRCUMSPECT most nearly means:', '["easily distracted","wary and considering all possibilities","surrounded by obstacles","quick to decide"]'::jsonb, 1, 'Circumspect literally means ''looking around'' — considering all circumstances before acting, hence wary and careful. Quick to decide is the opposite. ''Surrounded by obstacles'' misreads CIRCUM- as a physical description.', true),
  ('WK-PFX-5', 'WK', 'wk.prefixes-suffixes', 3, 'The prefix TRANS- means across or through. A TRANSOCEANIC voyage is therefore a voyage:', '["below the ocean surface","along the coastline","across an ocean","within a single ocean region"]'::jsonb, 2, 'TRANS- means across or through, as in transport, transfer, transatlantic. Transoceanic means crossing an ocean from one side to the other.', true),
  ('WK-PFX-6', 'WK', 'wk.prefixes-suffixes', 4, 'The word EQUIVOCAL contains the prefix EQUI- (equal) and the root VOC (voice/call). EQUIVOCAL most nearly means:', '["equally loud","open to two interpretations","fair and balanced","clearly stated"]'::jsonb, 1, 'Equivocal literally means ''equal voices'' — a statement that calls equally in two directions, making it deliberately ambiguous or unclear. Clearly stated is the antonym. Fair and balanced is a trap that uses EQUI- in isolation.', true),
  ('WK-PFX-7', 'WK', 'wk.prefixes-suffixes', 4, 'The suffix -OLOGY means the study of, while -OLOGIST means one who studies. A SEISMOLOGIST studies:', '["the structure of the atmosphere","earthquake activity","ocean currents","ancient fossils"]'::jsonb, 1, 'SEISMO- derives from the Greek seismos, meaning earthquake or shaking. A seismologist studies earthquakes and seismic waves. Fossils (paleontology) and ocean currents (oceanography) involve different prefixes.', true),
  ('WK-PFX-8', 'WK', 'wk.prefixes-suffixes', 5, 'The word MAGNANIMOUS contains the roots MAGN- (great) and ANIM- (spirit/soul). MAGNANIMOUS most nearly means:', '["physically large and imposing","generous in forgiving insults or injuries","highly educated","emotionally volatile"]'::jsonb, 1, 'Magnanimous means ''great-spirited'' — generous, noble, and especially forgiving toward rivals or those who have wronged you. Physically large (magnitude) uses the same root but the ANIM- component shifts meaning toward character, not size.', true),
  ('WK-ROOT-1', 'WK', 'wk.root-words', 3, 'The word AUDIBLE shares its root with AUDITORIUM and AUDIENCE. The root AUD- means:', '["to speak","to hear","to see","to gather"]'::jsonb, 1, 'AUD- comes from the Latin audire, to hear. Audible means capable of being heard; an auditorium is a place for hearing performances; an audience is a group of listeners.', true),
  ('WK-ROOT-2', 'WK', 'wk.root-words', 3, 'The root CHRON appears in CHRONIC, CHRONOMETER, and ANACHRONISM. CHRON means:', '["color","time","order","distance"]'::jsonb, 1, 'CHRON comes from the Greek chronos, meaning time. A chronometer measures time precisely; an anachronism is something placed in the wrong time period; chronic means persisting over a long time.', true),
  ('WK-ROOT-3', 'WK', 'wk.root-words', 3, 'The root TERRA appears in TERRITORY, TERRAIN, and MEDITERRANEAN. TERRA most nearly means:', '["water","sky","earth or land","boundary"]'::jsonb, 2, 'TERRA comes from Latin meaning earth or land. Mediterranean literally means ''middle of the earth (land)''; terrain refers to the features of a stretch of land; territory is a defined area of land.', true),
  ('WK-ROOT-4', 'WK', 'wk.root-words', 4, 'The root SCRIB/SCRIPT appears in PRESCRIBE, DESCRIBE, INSCRIPTION, and MANUSCRIPT. This root most nearly means:', '["to speak","to write","to order","to carve"]'::jsonb, 1, 'SCRIB/SCRIPT comes from the Latin scribere, to write. Manuscript means handwritten; inscription is writing carved into a surface; prescribe originally meant to write before (instructions). ''To carve'' is a trap because inscriptions are carved, but the root itself means write.', true),
  ('WK-ROOT-5', 'WK', 'wk.root-words', 4, 'The root RUPT appears in INTERRUPT, DISRUPT, ERUPT, and RUPTURE. RUPT most nearly means:', '["to flow","to break or burst","to begin","to connect"]'::jsonb, 1, 'RUPT comes from the Latin rumpere, to break. Interrupt means to break into; disrupt means to break apart; erupt means to burst out; rupture is a break or tear. ''To flow'' is a trap because eruptions involve flow, but the root captures the breaking action.', true),
  ('WK-ROOT-6', 'WK', 'wk.root-words', 5, 'The root LOQUI/LOCUT appears in ELOQUENT, COLLOQUIAL, LOQUACIOUS, and SOLILOQUY. This root most nearly means:', '["to listen","to write formally","to speak","to persuade"]'::jsonb, 2, 'LOQUI/LOCUT comes from the Latin loqui, to speak. Eloquent means speaking with fluency and force; loquacious means very talkative; colloquial refers to everyday spoken language; a soliloquy is speaking alone. ''To persuade'' is tempting for eloquent, but persuasion is an effect, not the root''s meaning.', true),
  ('PC-ATP-1', 'PC', 'pc.author-tone-purpose', 3, 'Read the passage below and answer the question.

"Every year, thousands of young people sign contracts they do not fully understand, binding themselves to financial obligations that can follow them for a decade. Financial literacy is not a luxury — it is a survival skill. Schools that skip personal finance education are not saving curriculum space; they are failing their students."

The author''s primary purpose is to:', '["explain how financial contracts work","argue that financial education should be required in schools","describe the difficulties young people face after graduation","compare different methods of teaching personal finance"]'::jsonb, 1, 'The passage makes a direct argument: schools that skip financial literacy are ''failing their students.'' The word ''failing'' signals advocacy, not neutral description. The author is not explaining contract mechanics or comparing teaching methods.', true),
  ('PC-ATP-2', 'PC', 'pc.author-tone-purpose', 3, 'Read the passage below and answer the question.

"The old lighthouse stood at the edge of the cliff, its white paint peeling, its lamp long dark. Fishermen who once depended on its beam now navigated by GPS coordinates that glowed on small screens below the wheelhouse. Progress, it seemed, had made the lighthouse beautiful again — no longer a tool, just a memory."

The author''s tone toward the lighthouse can best be described as:', '["angry at the march of technology","nostalgic and somewhat wistful","proud of modern navigation advances","indifferent to the lighthouse''s fate"]'::jsonb, 1, '''Beautiful again — no longer a tool, just a memory'' expresses a wistful, nostalgic view of something that has outlived its usefulness. The author is not angry — progress is accepted — but there is a gentle sense of loss, not pride or indifference.', true),
  ('PC-ATP-3', 'PC', 'pc.author-tone-purpose', 4, 'Read the passage below and answer the question.

"The study followed 400 adults over 20 years and found that those who slept fewer than six hours per night had a 35 percent higher incidence of cardiovascular events than those who slept seven to eight hours. Researchers controlled for diet, exercise, and body mass index. The correlation was consistent across age groups and geographic regions."

The author''s tone is best described as:', '["alarmed and warning readers to change habits","objective and informative","persuasive, urging policy reform","skeptical of the study''s methodology"]'::jsonb, 1, 'The passage reports data and controlled variables without emotional language or calls to action. ''Controlled for diet, exercise, and BMI'' signals scientific rigor, not alarm or advocacy. Skeptical would involve questioning the methods, which the author does not do.', true),
  ('PC-ATP-4', 'PC', 'pc.author-tone-purpose', 3, 'Read the passage below and answer the question.

"If you have ever watched a skilled carpenter fit two pieces of wood together without a visible gap, you have witnessed craftsmanship at its best. It is not magic — it is patience, the right tools, and a refusal to accept ''good enough.'' Anyone who calls woodworking a dying art has never stood in a shop full of sawdust and purpose."

The author''s attitude toward woodworking is best described as:', '["defensive and insecure about the craft''s future","enthusiastic and admiring","neutral and informational","critical of beginners who rush their work"]'::jsonb, 1, '''Craftsmanship at its best,'' ''patience,'' and ''sawdust and purpose'' all express genuine admiration. The author does mention critics but counters them confidently rather than defensively, and offers no criticism of beginners specifically.', true),
  ('PC-ATP-5', 'PC', 'pc.author-tone-purpose', 4, 'Read the passage below and answer the question.

"The proposal to expand the highway through the wetland was approved in 72 hours — a process that typically takes months of environmental review. Local conservation groups were not notified until after the vote. Three federal agencies later noted that proper procedure had not been followed, yet construction began on schedule."

The author''s implied attitude toward the approval process is:', '["supportive of faster infrastructure decisions","critical of the rushed and irregular process","neutral, simply reporting a timeline","uncertain about whether the wetland matters"]'::jsonb, 1, 'The author selects details that expose procedural shortcuts: a 72-hour decision on a months-long process, no public notification, federal agencies noting violations. This pattern of detail selection signals criticism even without explicit judgment words.', true),
  ('PC-ATP-6', 'PC', 'pc.author-tone-purpose', 4, 'Read the passage below and answer the question.

"Wolves were reintroduced to Yellowstone in 1995. Within a decade, the elk population shifted its grazing patterns away from riverbanks, allowing willows and aspens to regrow. Beavers returned; their dams slowed erosion; streambeds narrowed and deepened. A single predator had changed the rivers."

The author''s primary purpose is to:', '["argue that wolf populations should be expanded throughout the country","illustrate how the reintroduction of one species can reshape an entire ecosystem","criticize the original removal of wolves from Yellowstone","describe the daily behavior of wolves in the wild"]'::jsonb, 1, 'The passage traces a chain of ecological effects from one decision, building to ''a single predator had changed the rivers.'' This is an illustrative, cause-and-effect purpose. The author does not call for expanded wolf populations or criticize past decisions.', true),
  ('PC-ATP-7', 'PC', 'pc.author-tone-purpose', 5, 'Read the passage below and answer the question.

"Efficiency, we are often told, is the highest virtue of a modern organization. But efficiency is a tool, not a goal. A surgeon who operates faster does not thereby become a better surgeon; a teacher who covers content faster is not necessarily teaching. When organizations optimize processes without asking what those processes are for, they risk becoming very good at doing the wrong thing."

The author''s attitude toward efficiency is best described as:', '["strongly opposed to using efficiency in any professional context","cautiously skeptical — useful in the right place, but easily misapplied","fully supportive if efficiency is paired with speed","indifferent; the author is presenting both sides without a position"]'::jsonb, 1, 'The author calls efficiency ''a tool, not a goal'' and uses examples to show how misapplied efficiency backfires — but never argues against efficiency itself. This is cautious skepticism, not wholesale opposition. The author clearly has a position, ruling out indifference.', true),
  ('PC-ATP-8', 'PC', 'pc.author-tone-purpose', 5, 'Read the passage below and answer the question.

"The recruits arrived in October — cocky, loud, certain they were ready for anything. By December, most had stopped talking about what they thought training would be like. They had learned something that cannot be taught in a classroom: that confidence earned is different from confidence assumed."

The author''s tone toward the recruits at the end of the passage is best described as:', '["contemptuous of their early arrogance","approving of the growth they experienced","pessimistic about their long-term prospects","amused by their naivety throughout"]'::jsonb, 1, '''Confidence earned is different from confidence assumed'' is the author''s conclusion — framing the change as meaningful growth, not humiliation. Contemptuous would suggest the author mocks them; the passage instead presents the transformation with respect.', true),
  ('AS-MNT-1', 'AS', 'as.maintenance-repair', 3, 'Engine oil should be changed at regular intervals primarily to:', '["increase fuel octane rating","remove contaminants and restore lubricating properties","cool the transmission fluid","maintain proper tire pressure"]'::jsonb, 1, 'Over time, engine oil accumulates metal particles, carbon deposits, and acids that degrade its lubricating ability. Regular changes remove these contaminants and restore proper protection. Oil does not affect fuel octane or tire pressure.', true),
  ('AS-MNT-2', 'AS', 'as.maintenance-repair', 3, 'A vehicle''s brake pedal sinks slowly to the floor when held with steady pressure. This most likely indicates:', '["worn brake pads","a failing master cylinder or brake fluid leak","air in the fuel line","a loose wheel bearing"]'::jsonb, 1, 'A pedal that sinks under steady pressure (called brake fade or pedal drop) is a classic sign of a failing master cylinder or a leak allowing fluid to bypass the seals. Worn pads change stopping distance but do not cause the pedal to drop under held pressure.', true),
  ('AS-MNT-3', 'AS', 'as.maintenance-repair', 3, 'Tire rotation is recommended every 5,000–7,000 miles primarily because:', '["it resets the tire pressure monitoring system","front and rear tires wear at different rates due to different loads and steering forces","it prevents the tires from developing flat spots when parked","rotating tires improves fuel octane combustion"]'::jsonb, 1, 'Front tires handle steering forces and often support more weight from the engine, causing them to wear faster — especially on front-wheel-drive vehicles. Rotation equalizes wear across all four tires, extending overall tire life.', true),
  ('AS-MNT-4', 'AS', 'as.maintenance-repair', 4, 'When checking tire pressure, a technician should check it when the tires are:', '["hot, immediately after a long drive, for the most accurate reading","cold, before driving or after sitting for at least three hours","warm, after a short drive of about five miles","at any temperature, because modern gauges automatically adjust"]'::jsonb, 1, 'Tire pressure is specified for cold tires because driving heats air inside the tire, raising pressure by 4–8 psi. Checking hot tires gives a falsely high reading; the industry standard is to check cold tires. Modern gauges measure pressure but do not compensate for temperature.', true),
  ('AS-MNT-5', 'AS', 'as.maintenance-repair', 3, 'A vehicle pulls consistently to the right when driving on a straight, level road. The most likely cause is:', '["a clogged fuel filter","uneven tire pressure or a wheel alignment problem","a worn timing belt","low windshield washer fluid"]'::jsonb, 1, 'Pulling to one side is the classic symptom of uneven tire pressure or wheel misalignment. A low right-side tire or toe misalignment causes the vehicle to drift toward the low-pressure or angled side. Fuel and timing issues cause performance problems, not directional pull.', true),
  ('AS-MNT-6', 'AS', 'as.maintenance-repair', 4, 'A grinding noise that occurs only when the brakes are applied most likely indicates:', '["a failing alternator","brake pads worn down to the metal backing plate","loose lug nuts on the wheel","low power steering fluid"]'::jsonb, 1, 'When brake pad friction material wears away completely, the metal backing plate contacts the rotor directly, producing a grinding noise under braking. Alternator failure and low power steering fluid cause distinct, unrelated symptoms.', true),
  ('AS-MNT-7', 'AS', 'as.maintenance-repair', 4, 'The purpose of a vehicle''s PCV (Positive Crankcase Ventilation) valve is to:', '["regulate fuel injection timing","route blow-by gases from the crankcase back into the intake manifold for combustion","control coolant flow to the heater core","measure exhaust oxygen content for the fuel management system"]'::jsonb, 1, 'The PCV valve draws unburned gases (blow-by) that slip past piston rings back into the intake manifold where they are reburned. A stuck-closed PCV valve can build crankcase pressure and force oil past seals. The oxygen sensor (not PCV) measures exhaust oxygen.', true),
  ('AS-MNT-8', 'AS', 'as.maintenance-repair', 5, 'An engine runs rough at idle but smoothly at higher RPM. Disconnecting one spark plug wire at a time, you find that one cylinder makes no change to idle quality when its wire is removed. This means:', '["that cylinder is firing too often at idle","that cylinder is not contributing to engine power — it is misfiring or dead","the ignition coil for that cylinder is delivering extra voltage","all cylinders are sharing load equally"]'::jsonb, 1, 'Removing a plug wire from a healthy cylinder will cause idle to noticeably worsen. If removing a wire causes no change, that cylinder was already not contributing — it was misfiring. This test isolates the dead cylinder.', true),
  ('MC-IPH-1', 'MC', 'mc.inclined-plane-hydraulics', 3, 'A 300-pound crate is slid up a frictionless ramp that is 15 feet long and rises 5 feet vertically. How many pounds of force are required to push it up the ramp?', '["60 pounds","100 pounds","150 pounds","300 pounds"]'::jsonb, 1, 'Mechanical advantage of an inclined plane = length / height = 15 / 5 = 3. Required force = load / MA = 300 / 3 = 100 pounds. Using the full 300 pounds ignores the ramp''s advantage; 60 pounds would require MA of 5.', true),
  ('MC-IPH-2', 'MC', 'mc.inclined-plane-hydraulics', 3, 'In a hydraulic system, a small piston with an area of 2 square inches is pushed down with 50 pounds of force. What force does the large piston with an area of 10 square inches exert?', '["10 pounds","100 pounds","250 pounds","500 pounds"]'::jsonb, 2, 'Pascal''s principle: F₂/A₂ = F₁/A₁, so F₂ = F₁ × (A₂/A₁) = 50 × (10/2) = 50 × 5 = 250 pounds. The hydraulic system multiplies force in proportion to the area ratio.', true),
  ('MC-IPH-3', 'MC', 'mc.inclined-plane-hydraulics', 4, 'A block-and-tackle pulley system uses 4 rope segments supporting the load. If you pull the free end with 75 pounds of force, how heavy a load can you lift (ignoring friction)?', '["75 pounds","150 pounds","225 pounds","300 pounds"]'::jsonb, 3, 'With 4 supporting rope segments, the mechanical advantage is 4. Lift capacity = effort × MA = 75 × 4 = 300 pounds. Each supporting strand shares the load equally, so more strands mean more force multiplication.', true),
  ('MC-IPH-4', 'MC', 'mc.inclined-plane-hydraulics', 4, 'A hydraulic lift has an input piston area of 4 square inches and an output piston area of 20 square inches. If you need to lift 1,000 pounds, how much input force is required?', '["50 pounds","200 pounds","400 pounds","5,000 pounds"]'::jsonb, 1, 'Hydraulic MA = output area / input area = 20 / 4 = 5. Input force = load / MA = 1,000 / 5 = 200 pounds. Selecting 50 pounds corresponds to an MA of 20 (confusing areas with MA directly).', true),
  ('MC-IPH-5', 'MC', 'mc.inclined-plane-hydraulics', 4, 'A wedge is driven under one edge of a 500-pound boulder. The wedge is 8 inches long and 2 inches thick at its widest point. What is the mechanical advantage of this wedge?', '["2","4","6","250"]'::jsonb, 1, 'Mechanical advantage of a wedge = length / thickness = 8 / 2 = 4. A longer, thinner wedge provides greater advantage; the 500-pound load is the object being moved, not a factor in calculating MA.', true),
  ('MC-IPH-6', 'MC', 'mc.inclined-plane-hydraulics', 5, 'A 400-pound object must be raised 6 feet. You can use either a single fixed pulley, a ramp 18 feet long, or a hydraulic jack with a 5:1 area ratio. Ignoring friction, which requires the least input force?', '["single fixed pulley","the 18-foot ramp","the hydraulic jack","all three require identical force"]'::jsonb, 2, 'Single fixed pulley: MA = 1, force = 400 lbs. Ramp: MA = 18/6 = 3, force = 400/3 ≈ 133 lbs. Hydraulic jack: MA = 5, force = 400/5 = 80 lbs. The hydraulic jack requires the least force at 80 lbs.', true),
  ('MC-MOT-1', 'MC', 'mc.motion-projectile', 3, 'A 5-kg ball moving at 6 m/s collides with a stationary 5-kg ball and comes to a complete stop. What is the velocity of the second ball after the collision?', '["0 m/s","3 m/s","6 m/s","12 m/s"]'::jsonb, 2, 'Conservation of momentum: total momentum before = total momentum after. (5 × 6) + (5 × 0) = 30 kg·m/s. After: first ball stops, so second ball carries all momentum: 5 × v = 30, v = 6 m/s.', true),
  ('MC-MOT-2', 'MC', 'mc.motion-projectile', 3, 'An object is dropped from a height and falls freely under gravity (9.8 m/s²). After 3 seconds, its velocity is approximately:', '["9.8 m/s","19.6 m/s","29.4 m/s","44.1 m/s"]'::jsonb, 2, 'Velocity under free fall = g × t = 9.8 × 3 = 29.4 m/s. Each second adds 9.8 m/s of downward velocity; after 3 seconds the object is moving at 29.4 m/s.', true),
  ('MC-MOT-3', 'MC', 'mc.motion-projectile', 4, 'A net force of 20 N is applied to a 4-kg object. What is the object''s acceleration?', '["0.2 m/s²","5 m/s²","16 m/s²","80 m/s²"]'::jsonb, 1, 'Newton''s Second Law: a = F/m = 20/4 = 5 m/s². Dividing mass by force (4/20 = 0.2) inverts the formula, a common error. Multiplying gives 80, which misapplies the relationship.', true),
  ('MC-MOT-4', 'MC', 'mc.motion-projectile', 4, 'A ball is launched horizontally from a cliff at 20 m/s. Ignoring air resistance, what happens to the ball''s horizontal speed as it falls?', '["it increases because gravity accelerates it forward","it decreases because gravity slows horizontal motion","it stays constant because horizontal and vertical motions are independent","it reaches zero at peak height"]'::jsonb, 2, 'In projectile motion, horizontal and vertical components are independent. Gravity acts only vertically, so the horizontal speed remains 20 m/s throughout the flight. There is no peak height for a horizontally launched projectile — it only falls.', true),
  ('MC-MOT-5', 'MC', 'mc.motion-projectile', 4, 'Two identical hockey pucks rest on frictionless ice. Puck A is pushed with twice the force of Puck B for the same amount of time. Compared to Puck B, Puck A will have:', '["the same final velocity","twice the final velocity","four times the final velocity","half the final velocity"]'::jsonb, 1, 'Impulse = F × t = change in momentum. Same time, twice the force → twice the impulse → twice the change in momentum. Since masses are equal, twice the momentum means twice the velocity.', true),
  ('MC-MOT-6', 'MC', 'mc.motion-projectile', 5, 'A 10-kg object traveling at 4 m/s east collides and sticks to a 6-kg object traveling at 4 m/s west. What is the velocity of the combined mass after the collision?', '["4 m/s east","1 m/s east","0 m/s (they stop)","2.5 m/s west"]'::jsonb, 1, 'Momentum is a vector. Taking east as positive: p = (10 × 4) + (6 × −4) = 40 − 24 = 16 kg·m/s east. Combined mass = 16 kg. v = 16/16 = 1 m/s east. They don''t stop because the heavier object''s eastward momentum exceeds the lighter one''s westward momentum.', true),
  ('GS-PHY-1', 'GS', 'gs.physics-mechanics', 3, 'A book rests on a table without moving. According to Newton''s First Law, the book remains at rest because:', '["gravity is not acting on it","the table exerts an upward normal force that balances gravity","the book has no mass","friction from the table pushes the book upward"]'::jsonb, 1, 'Newton''s First Law states that an object at rest stays at rest when net force is zero. The table''s normal force (upward) exactly balances gravity (downward), producing zero net force. Friction acts horizontally and does not support the book''s weight.', true),
  ('GS-PHY-2', 'GS', 'gs.physics-mechanics', 3, 'Which simple machine is a screw most closely related to?', '["lever","wheel and axle","inclined plane","pulley"]'::jsonb, 2, 'A screw is essentially an inclined plane wrapped around a cylinder. The threads create a continuous spiral ramp, converting rotational force into linear motion. This is the same mechanical principle as a ramp, just in a circular form.', true),
  ('GS-PHY-3', 'GS', 'gs.physics-mechanics', 4, 'A person lifts a 60-Newton box 2 meters off the ground. How much work is done?', '["30 joules","62 joules","120 joules","240 joules"]'::jsonb, 2, 'Work = Force × Distance = 60 N × 2 m = 120 joules. Work is measured in joules (newton-meters). Dividing instead of multiplying gives 30 — a common sign-flip error. Adding (60 + 2 = 62) confuses the formula.', true),
  ('GS-PHY-4', 'GS', 'gs.physics-mechanics', 4, 'A compressed spring stores energy as:', '["kinetic energy","thermal energy","potential energy","chemical energy"]'::jsonb, 2, 'A compressed or stretched spring stores elastic potential energy — energy stored due to the object''s position or deformation. When released, potential energy converts to kinetic energy. Thermal energy would imply the spring heated up.', true),
  ('GS-PHY-5', 'GS', 'gs.physics-mechanics', 4, 'Two balls of different mass are dropped from the same height at the same time in a vacuum. Which hits the ground first?', '["the heavier ball, because gravity pulls it harder","the lighter ball, because it has less air resistance","they hit at the same time","it depends on the shape of each ball"]'::jsonb, 2, 'In a vacuum there is no air resistance. Gravity accelerates all objects equally regardless of mass (9.8 m/s²). This is what Galileo demonstrated — the common misconception is that heavier objects fall faster because gravity ''pulls harder,'' but acceleration is mass-independent.', true),
  ('GS-PHY-6', 'GS', 'gs.physics-mechanics', 5, 'A 500-W electric motor lifts a 200-N load vertically. How high can it lift the load in 4 seconds (ignoring friction)?', '["2.5 meters","5 meters","10 meters","40 meters"]'::jsonb, 2, 'Power = Work / Time, so Work = Power × Time = 500 × 4 = 2,000 joules. Work = Force × Distance, so Distance = Work / Force = 2,000 / 200 = 10 meters. Using 4 seconds as the distance (40 m) is a unit confusion error.', true),
  ('EI-CON-2', 'EI', 'ei.conductors-insulators', 3, 'A semiconductor differs from a conductor because a semiconductor:', '["conducts electricity under all conditions","never allows current to flow","conducts electricity only under certain conditions (such as added heat or doping)","has the same resistance as an insulator"]'::jsonb, 2, 'Semiconductors (like silicon and germanium) have electrical properties between conductors and insulators. Their conductivity can be controlled by temperature, light, or adding impurities (doping), which is why they are the basis of transistors and computer chips.', true),
  ('EI-CON-3', 'EI', 'ei.conductors-insulators', 4, 'Which of the following best explains why aluminum wire requires a larger gauge than copper wire to carry the same current safely?', '["aluminum is magnetic, which resists current flow","aluminum has higher resistivity than copper, so a larger cross-section is needed to reduce resistance","aluminum melts at a lower temperature and must be thicker for safety","aluminum has lower resistivity, making it harder for electrons to move"]'::jsonb, 1, 'Aluminum has about 1.6 times the resistivity of copper. To achieve the same resistance (and carry the same current without excessive heat), aluminum wire must have a larger cross-sectional area. This is why aluminum wiring uses larger gauges.', true),
  ('EI-CON-4', 'EI', 'ei.conductors-insulators', 4, 'Wet wood does not normally conduct electricity well, but wet wood with dissolved salts conducts much better. This demonstrates that:', '["wood becomes a semiconductor when cut","dissolved ions in water create charge carriers that enable conduction","heat from the salt lowers electrical resistance","salt acts as an insulator that traps electrons"]'::jsonb, 1, 'Pure water is a poor conductor, but dissolved salts (ionic compounds) break into positive and negative ions that can carry charge through the liquid. This is why saltwater and moist soil are better conductors than pure water alone.', true),
  ('EI-CON-5', 'EI', 'ei.conductors-insulators', 5, 'A technician handles a live wire while standing on a dry rubber mat. Why does the rubber mat protect the technician?', '["rubber absorbs excess electrical current and releases it as heat","rubber is an insulator that blocks the flow of current from the technician to ground","rubber becomes positively charged and repels electrons","rubber stores electrical charge, reducing voltage at the technician''s feet"]'::jsonb, 1, 'Electrical current flows along a complete circuit — from source, through a conductor, and back to ground. Rubber is an insulator; standing on it breaks the path to ground, preventing current from flowing through the technician''s body. This is why insulated footwear is required in electrical work.', true),
  ('EI-OHM-1', 'EI', 'ei.ohms-law-power', 3, 'A light bulb operates on 120 volts and draws 2 amperes. What is the power consumption of the bulb?', '["60 watts","122 watts","240 watts","480 watts"]'::jsonb, 2, 'Power = Voltage × Current = P = IV = 120 × 2 = 240 watts. Dividing (120/2 = 60) is the most common error — students confuse the power formula with Ohm''s Law for resistance.', true),
  ('EI-OHM-2', 'EI', 'ei.ohms-law-power', 3, 'Three resistors of 4 ohms, 6 ohms, and 2 ohms are connected in series. What is the total resistance of the circuit?', '["1 ohm","6 ohms","12 ohms","48 ohms"]'::jsonb, 2, 'In a series circuit, total resistance = R₁ + R₂ + R₃ = 4 + 6 + 2 = 12 ohms. The parallel formula (1/R) is often mistakenly applied here; in series, resistances simply add together.', true),
  ('EI-OHM-3', 'EI', 'ei.ohms-law-power', 4, 'A 12-volt battery powers a circuit with two resistors in series: 3 ohms and 1 ohm. What is the power dissipated by the 3-ohm resistor?', '["9 watts","12 watts","27 watts","36 watts"]'::jsonb, 2, 'Total resistance = 3 + 1 = 4 ohms. Current = V/R = 12/4 = 3 amperes. Power in the 3-ohm resistor: P = I²R = 3² × 3 = 9 × 3 = 27 watts. Using total voltage instead of calculating current first gives 48 W — a two-step problem requiring correct sequencing.', true),
  ('EI-OHM-4', 'EI', 'ei.ohms-law-power', 4, 'Two resistors are connected in parallel: one is 6 ohms and one is 3 ohms. What is the combined resistance?', '["9 ohms","4.5 ohms","2 ohms","1 ohm"]'::jsonb, 2, 'Parallel resistance formula: 1/R_total = 1/6 + 1/3 = 1/6 + 2/6 = 3/6 = 1/2. So R_total = 2 ohms. A common error is adding resistances as in series (6 + 3 = 9). In parallel, total resistance is always less than the smallest individual resistor.', true),
  ('EI-OHM-5', 'EI', 'ei.ohms-law-power', 5, 'A 9-volt battery powers a parallel circuit. Branch 1 has a 9-ohm resistor; Branch 2 has an 18-ohm resistor. What is the total current drawn from the battery?', '["0.5 amperes","1 ampere","1.5 amperes","3 amperes"]'::jsonb, 2, 'In parallel circuits, voltage across each branch equals source voltage. Branch 1 current: I₁ = 9/9 = 1 A. Branch 2 current: I₂ = 9/18 = 0.5 A. Total current = I₁ + I₂ = 1.5 A. Students who use combined parallel resistance alone often get the right answer but skip confirming via branch currents — here either method works.', true),
  ('AR-WRD-1', 'AR', 'ar.word-problems', 4, 'A supply truck can carry 4,800 pounds. It is loaded with boxes weighing 60 pounds each and crates weighing 120 pounds each. If there are 20 crates, how many boxes can also be loaded without exceeding the limit?', '["20 boxes","40 boxes","48 boxes","56 boxes"]'::jsonb, 1, 'Crates use: 20 × 120 = 2,400 lbs. Remaining capacity: 4,800 − 2,400 = 2,400 lbs. Number of boxes: 2,400 / 60 = 40 boxes. Dividing remaining capacity by 120 (crate weight) gives 20 — the error of using the wrong unit weight.', true),
  ('AR-WRD-2', 'AR', 'ar.word-problems', 4, 'A fuel tank is 3/4 full and holds 24 gallons at that level. How many total gallons does the tank hold when completely full?', '["18 gallons","30 gallons","32 gallons","36 gallons"]'::jsonb, 2, 'If 3/4 of the tank = 24 gallons, then 1/4 = 8 gallons, and the full tank = 4 × 8 = 32 gallons. Multiplying 24 × (3/4) = 18 gallons is the reverse error — treating the fraction as a multiplier instead of recognizing it represents the current fill level.', true),
  ('AR-PCT-1', 'AR', 'ar.percent', 4, 'A piece of equipment originally cost $800. After a 15% discount it was purchased, then later sold for 10% more than the purchase price. What was the final selling price?', '["$748.00","$756.00","$770.00","$792.00"]'::jsonb, 0, 'Apply percentages sequentially: $800 × (1 − 0.15) = $680, then $680 × (1 + 0.10) = $748. Common error: netting the percentages to −5% gives $760, which is wrong because each percent applies to a different base.', true),
  ('AR-RAT-1', 'AR', 'ar.ratio-proportion', 4, 'A military convoy travels 120 miles in 2.5 hours. At the same rate, how far will it travel in 4 hours?', '["160 miles","192 miles","200 miles","240 miles"]'::jsonb, 1, 'Speed = 120 / 2.5 = 48 mph. Distance in 4 hours = 48 × 4 = 192 miles. Multiplying 120 × 4 = 480 ignores the rate calculation; 200 miles results from rounding 48 to 50 mph.', true),
  ('AR-ALG-1', 'AR', 'ar.arithmetic-fundamentals', 5, 'A storage room has 3 shelves. Each shelf holds twice as many items as the shelf below it. The bottom shelf holds 15 items. How many items are in the storage room in total?', '["45 items","90 items","105 items","120 items"]'::jsonb, 2, 'Bottom shelf: 15. Middle shelf: 15 × 2 = 30. Top shelf: 30 × 2 = 60. Total = 15 + 30 + 60 = 105 items. Adding 15 three times (45) misses the doubling; multiplying all by 2 once (30 × 3 = 90) misapplies the doubling pattern.', true),
  ('MK-ALG-1', 'MK', 'mk.algebra-linear', 4, 'If 5(x − 3) = 2x + 6, what is the value of x?', '["x = 3","x = 5","x = 7","x = 9"]'::jsonb, 2, 'Distribute: 5x − 15 = 2x + 6. Subtract 2x: 3x − 15 = 6. Add 15: 3x = 21. x = 7. A common error is failing to distribute the 5 to −3, giving 5x − 3 = 2x + 6 and solving to x = 3.', true),
  ('MK-GEO-1', 'MK', 'mk.geometry', 4, 'A cylindrical water tank has a radius of 3 feet and a height of 10 feet. What is its volume? (Use π ≈ 3.14)', '["94.2 cubic feet","188.4 cubic feet","282.6 cubic feet","942 cubic feet"]'::jsonb, 2, 'Volume of a cylinder = π × r² × h = 3.14 × 9 × 10 = 282.6 cubic feet. Using diameter (6) instead of radius (3) gives 3.14 × 36 × 10 = 1,130.4 — squaring the diameter is the most common error. Using r = 3 without squaring gives 3.14 × 3 × 10 = 94.2.', true),
  ('MK-FRC-1', 'MK', 'mk.fractions-decimals', 5, 'A fuel mixture is 2/5 diesel and the rest is gasoline. If the tank holds 60 liters, how many more liters of gasoline than diesel does it contain?', '["12 liters more gasoline","24 liters more gasoline","12 liters more diesel","36 liters more gasoline"]'::jsonb, 0, 'Diesel = (2/5) × 60 = 24 liters. Gasoline = 60 − 24 = 36 liters. Difference = 36 − 24 = 12 liters more gasoline. Choosing 24 liters confuses the diesel volume with the difference; choosing 36 liters is the gasoline volume, not the difference between the two.', true),
  ('WK-CTX-HARD-1', 'WK', 'wk.context-clues', 5, 'In the sentence ''The politician''s OBSEQUIOUS deference to every donor in the room struck journalists as calculated rather than genuine,'' the word OBSEQUIOUS most nearly means:', '["bold and outspoken","excessively eager to please or serve","professionally courteous","openly hostile"]'::jsonb, 1, 'Obsequious means servilely compliant or fawning — behaving in an excessively eager-to-please way. The clue that it ''struck journalists as calculated'' confirms it goes beyond normal professional courtesy, ruling out choice C. Bold or hostile are direct opposites.', true),
  ('WK-SYN-HARD-1', 'WK', 'wk.synonyms', 4, 'EPHEMERAL most nearly means:', '["ancient","lasting only a short time","extraordinarily rare","deeply emotional"]'::jsonb, 1, 'Ephemeral means lasting for a very short time (from Greek ephemeros, ''for a day''). Ancient is essentially its opposite. Rare and emotional are unrelated to its core meaning of brevity.', true),
  ('WK-SYN-HARD-2', 'WK', 'wk.synonyms', 5, 'VERACIOUS most nearly means:', '["extremely hungry","truthful","speedy","aggressive"]'::jsonb, 1, 'Veracious means habitually speaking the truth. It is commonly confused with voracious (extremely hungry), which sounds similar. The VER- root relates to truth (verify, veracity), while VOR- relates to eating (devour).', true),
  ('PC-INF-HARD-1', 'PC', 'pc.inference', 4, 'Read the passage below and answer the question.

"The lab''s results were submitted three times before the review board accepted them. Each submission included additional documentation requested by the board, yet the board raised new objections with each round. When the research was finally published, it overturned a theory the board''s chair had authored fifteen years earlier. The chair did not recuse himself from the review."

What can most reasonably be inferred from this passage?', '["The research contained significant methodological flaws that required correction.","The board''s repeated objections may have been influenced by a conflict of interest.","Government agencies routinely require three rounds of submission for new research.","The board chair ultimately supported the research once it was explained clearly."]'::jsonb, 1, 'The detail that the board kept finding new objections — and that the final research contradicted the chair''s own published theory — strongly implies a conflict of interest. Choice A is contradicted by the research''s eventual publication. Choices C and D are not supported by any passage detail.', true),
  ('PC-MAIN-HARD-1', 'PC', 'pc.main-idea', 4, 'Read the passage below and answer the question.

"Maps are not neutral documents. Every map involves choices: what to include, what to omit, which areas to enlarge, and which projection to use. The Mercator projection, still common in classrooms, inflates the size of land near the poles — making Greenland appear as large as Africa, when Africa is actually fourteen times larger. A map teaches not just geography but a way of seeing the world."

What is the main idea of this passage?', '["The Mercator projection is the most accurate map projection available.","Maps reflect decisions and assumptions that shape how people perceive the world.","Africa is fourteen times larger than Greenland.","Classroom maps should be replaced with digital navigation tools."]'::jsonb, 1, 'The passage opens and closes with the argument that maps embed choices and teach a ''way of seeing.'' The Greenland/Africa fact is supporting evidence, not the main point. Choice D is never mentioned; Choice A contradicts the passage''s argument.', true),
  ('MK-ALG-HARD-1', 'MK', 'mk.algebra-linear', 5, 'Depot A charges a $40 setup fee plus $12 per unit ordered. Depot B charges no setup fee but $16 per unit. At exactly how many units do the two depots cost the same?', '["5 units","8 units","10 units","12 units"]'::jsonb, 2, 'Set costs equal: 40 + 12n = 16n. Subtract 12n from both sides: 40 = 4n. Divide: n = 10 units. At 10 units: Depot A = 40 + 120 = $160; Depot B = 16 × 10 = $160. Confirm equal. A common error is setting up the equation as 40 + 16n = 12n, which gives a negative n because the student reverses which depot has the base fee.', true),
  ('MK-GEO-HARD-1', 'MK', 'mk.geometry', 4, 'A right triangle has legs of 9 and 12. What is the length of the hypotenuse?', '["13","15","17","21"]'::jsonb, 1, 'Pythagorean theorem: c² = 9² + 12² = 81 + 144 = 225. c = √225 = 15. This is a classic 3-4-5 triple scaled by 3 (9-12-15). Adding the legs (9 + 12 = 21) or averaging them are common wrong approaches.', true),
  ('AR-PCT-HARD-1', 'AR', 'ar.percent', 5, 'A soldier scores 72 on a first test and 88 on a second test. What is the percent increase from the first score to the second score, rounded to the nearest whole percent?', '["16%","18%","22%","25%"]'::jsonb, 2, 'Percent increase = (new − old) / old × 100 = (88 − 72) / 72 × 100 = 16/72 × 100 ≈ 22.2%, rounded to 22%. Dividing by the new score (16/88 ≈ 18%) is the most common error — percent change always uses the original value as the base.', true),
  ('WK-CTX-D2-1', 'WK', 'wk.context-clues', 2, 'In the sentence ''The trail looked safe but proved TREACHEROUS, with hidden drop-offs and unstable footing,'' the word TREACHEROUS most nearly means:', '["deceptively dangerous","exhausting","remote","unfamiliar"]'::jsonb, 0, 'Treacherous means deceptively dangerous — something that appears safe but conceals serious hazards. The new stem reinforces this with ''hidden drop-offs and unstable footing.'' Exhausting, remote, and unfamiliar describe possible trail qualities but do not capture the deceptive, unpredictable danger that treacherous conveys.', true),
  ('WK-PFX-D2-1', 'WK', 'wk.prefixes-suffixes', 2, 'The prefix MIS- means wrongly or badly. MISJUDGE therefore means:', '["to judge again","to judge fairly","to judge wrongly","to refuse to judge"]'::jsonb, 2, 'MIS- attaches to a verb and means wrongly or badly — as in mislead (lead wrongly), misfire (fire at wrong time), misuse. Misjudge means to form an incorrect judgment.', true),
  ('AS-MNT-D2-1', 'AS', 'as.maintenance-repair', 2, 'Why is it important to check the coolant level in a vehicle''s radiator regularly?', '["Low coolant improves fuel economy","Low coolant can cause the engine to overheat","Coolant affects the transmission shift points","Coolant level determines oil viscosity"]'::jsonb, 1, 'Engine coolant carries heat away from the engine block to the radiator. If the level drops too low, there is insufficient fluid to absorb engine heat, and the engine can overheat — causing serious damage such as a warped head gasket.', true),
  ('GS-PHY-D2-1', 'GS', 'gs.physics-mechanics', 2, 'Which of the following is an example of potential energy?', '["a spinning fan blade","a rock sitting on a high cliff","a car moving at 60 mph","sound traveling through air"]'::jsonb, 1, 'Potential energy is stored energy due to an object''s position or condition. A rock on a cliff has gravitational potential energy because of its height. The other options describe energy in motion (kinetic) or wave energy.', true),
  ('MC-MOT-D2-1', 'MC', 'mc.motion-projectile', 2, 'Newton''s First Law states that an object in motion stays in motion unless acted on by an outside force. Which of the following best demonstrates this law?', '["a ball speeding up as it rolls downhill","a hockey puck sliding across frictionless ice at constant speed","a rocket accelerating after launch","a pendulum slowing down due to air resistance"]'::jsonb, 1, 'Newton''s First Law describes inertia: no net force means no change in motion. A puck on frictionless ice has no friction or other horizontal force acting on it, so it maintains constant speed — the purest illustration of the law. The pendulum example actually shows the law being violated by air resistance.', true),
  ('EI-OHM-D2-1', 'EI', 'ei.ohms-law-power', 2, 'A circuit has a resistance of 8 ohms and a current of 3 amperes flowing through it. What is the voltage across the circuit?', '["2.7 volts","11 volts","24 volts","64 volts"]'::jsonb, 2, 'Ohm''s Law: V = I × R = 3 × 8 = 24 volts. Dividing instead of multiplying (8 / 3 ≈ 2.7) is the most common error. Adding (3 + 8 = 11) confuses the formula entirely.', true),
  ('MK-GEO-D2-1', 'MK', 'mk.geometry', 2, 'What is the perimeter of a rectangle that is 8 feet long and 5 feet wide?', '["13 feet","26 feet","40 feet","80 feet"]'::jsonb, 1, 'Perimeter = 2 × (length + width) = 2 × (8 + 5) = 2 × 13 = 26 feet. A common error is adding all four sides without doubling (8 + 5 = 13) or multiplying length by width to get area (40 square feet) instead of perimeter.', true),
  ('AR-AF-1', 'AR', 'ar.arithmetic-fundamentals', 3, 'A crate holds 24 bottles. A store receives 15 crates. After selling 120 bottles, how many bottles remain?', '["120","180","240","300"]'::jsonb, 2, 'Total = 24 × 15 = 360 bottles. 360 − 120 = 240 remain. The trap is computing 24 × 12 = 288 by misreading the crate count.', true),
  ('AR-AF-2', 'AR', 'ar.arithmetic-fundamentals', 3, 'A soldier buys 4 notebooks at $3 each and 6 pens at $1.25 each. What is the total cost?', '["$16.50","$17.50","$18.75","$19.50"]'::jsonb, 3, 'Notebooks: 4 × $3 = $12. Pens: 6 × $1.25 = $7.50. Total = $12 + $7.50 = $19.50.', true),
  ('AR-AF-3', 'AR', 'ar.arithmetic-fundamentals', 4, 'A truck can carry 850 pounds. A soldier loads 10 boxes at 75 pounds each. How many pounds of capacity remain?', '["75","100","125","150"]'::jsonb, 1, '10 boxes × 75 lb = 750 lb loaded. Remaining capacity = 850 − 750 = 100 lb.', true),
  ('AR-AF-4', 'AR', 'ar.arithmetic-fundamentals', 3, 'A barracks has 6 rooms, each holding 4 soldiers. If 14 soldiers are currently assigned, how many empty beds remain?', '["6","8","10","14"]'::jsonb, 2, 'Total beds = 6 × 4 = 24. Empty = 24 − 14 = 10.', true),
  ('AR-AF-5', 'AR', 'ar.arithmetic-fundamentals', 4, 'A soldier earns $2,880 per month. After paying $720 in rent and $340 in other bills, she saves the rest. How much does she save over 4 months?', '["$1,820","$6,400","$7,280","$11,520"]'::jsonb, 2, 'Monthly savings = $2,880 − $720 − $340 = $1,820. Over 4 months: $1,820 × 4 = $7,280.', true),
  ('AR-RP-1', 'AR', 'ar.ratio-proportion', 3, 'A recipe uses 3 cups of flour for every 2 cups of sugar. How many cups of sugar are needed if you use 12 cups of flour?', '["6","8","9","18"]'::jsonb, 1, 'Flour:Sugar = 3:2. Sugar = (2/3) × 12 = 8 cups. The trap is flipping the ratio and using 3/2 × 12 = 18.', true),
  ('AR-RP-2', 'AR', 'ar.ratio-proportion', 3, 'The exchange rate is 1 U.S. dollar = 0.85 euros. A soldier converts $240 to euros. How many euros does she receive?', '["180","196","204","282"]'::jsonb, 2, 'Euros = 240 × 0.85 = 204. The trap answer 282 comes from dividing 240 ÷ 0.85, which is converting in the wrong direction.', true),
  ('AR-RP-4', 'AR', 'ar.ratio-proportion', 5, 'A squad of 12 soldiers can build a wall in 8 hours. How long will it take a squad of 16 soldiers to build the same wall at the same work rate?', '["4 hours","5 hours","6 hours","7 hours"]'::jsonb, 2, 'Total work = 12 × 8 = 96 soldier-hours. With 16 soldiers: 96 ÷ 16 = 6 hours. This is inverse proportion — more workers means less time.', true),
  ('AR-RP-5', 'AR', 'ar.ratio-proportion', 4, 'A kitchen uses oil and vinegar in a 5:3 ratio to make dressing. A cook needs 64 ounces of dressing total. How many ounces of vinegar are needed?', '["16","20","24","40"]'::jsonb, 2, 'Vinegar = (3/8) × 64 = 24 ounces. The trap is using 3/5 of 64 = 38.4, or thinking vinegar is the larger portion.', true),
  ('AR-RP-6', 'AR', 'ar.ratio-proportion', 3, 'A kitchen uses salt and pepper in a ratio of 4:1 by weight. If a cook uses 20 grams of salt, how many grams of pepper are needed?', '["4","5","8","16"]'::jsonb, 1, 'Pepper = (1/4) × 20 = 5 grams.', true),
  ('AR-RP-7', 'AR', 'ar.ratio-proportion', 4, 'A supply truck carries canned goods and dry goods in a 3:5 ratio by weight. The total shipment weighs 640 pounds. How many pounds of canned goods are delivered?', '["160","200","240","400"]'::jsonb, 2, 'Total parts = 3 + 5 = 8. Each part = 640 ÷ 8 = 80 lb. Canned goods = 3 × 80 = 240 lb. The trap is using 3/5 of 640 = 384.', true),
  ('AR-PC-1', 'AR', 'ar.percent', 3, 'A jacket originally costs $80. It is on sale for 25% off. What is the sale price?', '["$20","$55","$60","$65"]'::jsonb, 2, 'Discount = 25% × $80 = $20. Sale price = $80 − $20 = $60.', true),
  ('AR-PC-2', 'AR', 'ar.percent', 3, 'A soldier''s physical fitness score increased from 60 to 75. What is the percent increase?', '["15%","20%","25%","30%"]'::jsonb, 2, 'Percent increase = (75 − 60) / 60 × 100 = 15/60 × 100 = 25%. The trap is dividing by the new value 75 to get 20%.', true),
  ('AR-PC-3', 'AR', 'ar.percent', 4, 'A meal costs $36. A 15% tip and a separate 10% service fee are both applied to the original $36 bill. What is the total amount paid?', '["$40.68","$43.20","$45.00","$45.36"]'::jsonb, 2, 'Tip = 15% × $36 = $5.40. Service fee = 10% × $36 = $3.60. Total = $36 + $5.40 + $3.60 = $45.00. The trap is compounding the service fee onto the tipped price.', true),
  ('AR-PC-4', 'AR', 'ar.percent', 3, 'A soldier invests $1,000 at 6% simple annual interest. How much interest is earned after 3 years?', '["$60","$180","$191","$600"]'::jsonb, 1, 'Simple interest = Principal × Rate × Time = $1,000 × 0.06 × 3 = $180. The trap is computing only 1 year''s interest ($60) or applying compound interest.', true),
  ('AR-PC-5', 'AR', 'ar.percent', 4, 'A store marks up a $50 item by 20%, then offers a 10% discount on the marked-up price. What is the final selling price?', '["$50.00","$54.00","$55.00","$58.00"]'::jsonb, 1, 'Marked-up price = $50 × 1.20 = $60. After 10% discount: $60 × 0.90 = $54. The trap is thinking +20% then −10% nets +10%, giving $55.', true),
  ('AR-PC-6', 'AR', 'ar.percent', 3, 'A town''s population grew from 4,000 to 4,600 in one year. What was the percent increase?', '["12.5%","13%","15%","16%"]'::jsonb, 2, 'Percent increase = (600 ÷ 4,000) × 100 = 15%.', true),
  ('AR-RD-1', 'AR', 'ar.rate-distance-time', 3, 'A soldier runs at 6 miles per hour. How far does she run in 45 minutes?', '["3.5 miles","4 miles","4.5 miles","5 miles"]'::jsonb, 2, '45 minutes = 0.75 hours. Distance = 6 × 0.75 = 4.5 miles.', true),
  ('AR-RD-2', 'AR', 'ar.rate-distance-time', 4, 'Two convoys leave the same base traveling in opposite directions. One travels at 45 mph and the other at 55 mph. How far apart are they after 2 hours?', '["90 miles","110 miles","180 miles","200 miles"]'::jsonb, 3, 'Combined separation rate = 45 + 55 = 100 mph. Distance apart = 100 × 2 = 200 miles. The trap is using only one convoy''s speed.', true),
  ('AR-RD-3', 'AR', 'ar.rate-distance-time', 4, 'Pump A fills a tank at 40 gallons per minute. Pump B drains it at 15 gallons per minute. Starting empty, how many minutes until a 1,000-gallon tank is full with both pumps running?', '["25 minutes","33 minutes","40 minutes","67 minutes"]'::jsonb, 2, 'Net fill rate = 40 − 15 = 25 gal/min. Time = 1,000 ÷ 25 = 40 minutes.', true),
  ('AR-RD-4', 'AR', 'ar.rate-distance-time', 3, 'A vehicle travels 180 miles in 3 hours. At the same speed, how long will it take to travel 270 miles?', '["3.5 hours","4 hours","4.5 hours","5 hours"]'::jsonb, 2, 'Speed = 180 ÷ 3 = 60 mph. Time for 270 miles = 270 ÷ 60 = 4.5 hours.', true),
  ('AR-RD-5', 'AR', 'ar.rate-distance-time', 5, 'Soldier A can complete a course in 4 hours alone. Soldier B can complete the same course in 6 hours alone. Working together, how long do they take?', '["2 hours","2 hours 24 minutes","3 hours","3 hours 20 minutes"]'::jsonb, 1, 'Combined rate = 1/4 + 1/6 = 3/12 + 2/12 = 5/12 per hour. Time = 12/5 = 2.4 hours = 2 hours 24 minutes.', true),
  ('AR-RD-6', 'AR', 'ar.rate-distance-time', 3, 'A helicopter flies 420 miles at 140 mph. How long does the flight take?', '["2 hours","2.5 hours","3 hours","3.5 hours"]'::jsonb, 2, 'Time = Distance ÷ Speed = 420 ÷ 140 = 3 hours.', true),
  ('AR-WP-1', 'AR', 'ar.word-problems', 4, 'A soldier spends 1/3 of his monthly pay on rent and 1/4 on food, and saves the rest. His monthly pay is $2,400. How much does he save each month?', '["$400","$600","$800","$1,000"]'::jsonb, 3, 'Rent = 1/3 × $2,400 = $800. Food = 1/4 × $2,400 = $600. Savings = $2,400 − $800 − $600 = $1,000.', true),
  ('AR-WP-2', 'AR', 'ar.word-problems', 5, 'Three soldiers share a $420 supply order. One soldier pays twice as much as each of the other two. How much does the soldier paying more contribute?', '["$105","$140","$168","$210"]'::jsonb, 3, 'Let each of the two pay x. The third pays 2x. Equation: x + x + 2x = 4x = $420, so x = $105. The larger share = 2x = $210.', true),
  ('AR-WP-3', 'AR', 'ar.word-problems', 3, 'A base has 480 personnel. If 35% are on leave, how many are currently on base?', '["148","168","288","312"]'::jsonb, 3, 'On leave = 35% × 480 = 168. On base = 480 − 168 = 312. The trap is selecting 168 (those on leave) rather than those remaining.', true),
  ('AR-WP-4', 'AR', 'ar.word-problems', 4, 'A mess hall serves breakfast for 2 hours at 80 soldiers per hour and lunch for 3 hours at 120 soldiers per hour. What is the total number of soldiers served?', '["400","500","520","600"]'::jsonb, 2, 'Breakfast = 80 × 2 = 160. Lunch = 120 × 3 = 360. Total = 160 + 360 = 520.', true),
  ('AR-WP-5', 'AR', 'ar.word-problems', 4, 'A soldier drives 3 legs of a trip: 60 miles at 30 mph, then 120 miles at 60 mph, then 90 miles at 45 mph. What is the total driving time?', '["5 hours","5.5 hours","6 hours","6.5 hours"]'::jsonb, 2, 'Leg 1: 60 ÷ 30 = 2 hrs. Leg 2: 120 ÷ 60 = 2 hrs. Leg 3: 90 ÷ 45 = 2 hrs. Total = 6 hours.', true),
  ('AR-WP-6', 'AR', 'ar.word-problems', 3, 'A soldier''s monthly pay is $3,000. She receives a 5% pay raise. What is her new monthly pay?', '["$3,050","$3,100","$3,150","$3,200"]'::jsonb, 2, 'Raise = 5% × $3,000 = $150. New pay = $3,000 + $150 = $3,150.', true),
  ('MK-AL-1', 'MK', 'mk.algebra-linear', 3, 'Solve for x: 3x + 7 = 22', '["x = 3","x = 5","x = 7","x = 9"]'::jsonb, 1, '3x = 22 − 7 = 15. x = 15 ÷ 3 = 5.', true),
  ('MK-AL-2', 'MK', 'mk.algebra-linear', 3, 'Solve for x: 4x − 9 = 23', '["x = 3.5","x = 7","x = 8","x = 32"]'::jsonb, 2, '4x = 23 + 9 = 32. x = 32 ÷ 4 = 8.', true),
  ('MK-AL-3', 'MK', 'mk.algebra-linear', 5, 'Solve the system: 2x + y = 11 and x − y = 1. What is the value of x?', '["x = 2","x = 3","x = 4","x = 5"]'::jsonb, 2, 'Add both equations: (2x + y) + (x − y) = 11 + 1 → 3x = 12 → x = 4. Then y = x − 1 = 3. Verify: 2(4) + 3 = 11 ✓.', true),
  ('MK-AL-4', 'MK', 'mk.algebra-linear', 4, 'Which value of x satisfies the inequality 5x − 4 > 16?', '["x = 3","x = 4","x = 4.5","x = 5"]'::jsonb, 3, '5x > 16 + 4 = 20, so x > 4. Among the choices, only x = 5 satisfies x > 4.', true),
  ('MK-AL-5', 'MK', 'mk.algebra-linear', 3, 'If 2(x + 3) = 18, what is x?', '["x = 6","x = 7","x = 9","x = 12"]'::jsonb, 0, 'Distribute: 2x + 6 = 18. 2x = 12. x = 6.', true),
  ('MK-AL-6', 'MK', 'mk.algebra-linear', 4, 'A soldier earns $d per day. After 5 days he has earned $650. He spends $200. Which expression correctly gives his remaining money?', '["5d − 200","d/5 − 200","650 − 5d","5(d − 200)"]'::jsonb, 0, 'Total earned after 5 days = 5d. Since 5d = $650, he then spends $200, leaving 5d − 200 = 650 − 200 = $450. The expression 5d − 200 models earning then spending.', true),
  ('MK-FR-1', 'MK', 'mk.fractions-decimals', 3, 'What is 3/4 + 2/3?', '["5/7","5/12","1 5/12","1 7/12"]'::jsonb, 2, 'Common denominator is 12. 3/4 = 9/12; 2/3 = 8/12. Sum = 17/12 = 1 5/12. The trap is adding numerators and denominators directly to get 5/7.', true),
  ('MK-FR-2', 'MK', 'mk.fractions-decimals', 3, 'Which fraction is largest: 5/8, 2/3, 3/5, or 7/12?', '["5/8","2/3","3/5","7/12"]'::jsonb, 1, 'Convert to a common denominator of 120: 5/8 = 75/120, 2/3 = 80/120, 3/5 = 72/120, 7/12 = 70/120. Largest is 2/3.', true),
  ('MK-FR-3', 'MK', 'mk.fractions-decimals', 4, 'A soldier runs 2.75 miles on Monday and 1 3/4 miles on Tuesday. What is the combined distance?', '["4.00 miles","4.25 miles","4.50 miles","4.75 miles"]'::jsonb, 2, '1 3/4 = 1.75 miles. Total = 2.75 + 1.75 = 4.50 miles.', true),
  ('MK-FR-4', 'MK', 'mk.fractions-decimals', 3, 'What is (3/5) × (10/9)?', '["1/3","2/3","6/5","5/3"]'::jsonb, 1, 'Multiply numerators and denominators: (3 × 10) / (5 × 9) = 30/45 = 2/3 in lowest terms. The trap ‘5/3’ is what students get when they invert the wrong fraction and multiply — flipping 10/9 to 9/10 then computing (3/5) × (9/10)? No: the inversion error is treating multiplication like division, giving 3/5 ÷ 10/9 = (3/5) × (9/10) = 27/50, or more simply, students who flip both fractions get (5/3) × (9/10) and then lose track. The key takeaway: multiply straight across, then simplify.', true),
  ('MK-FR-5', 'MK', 'mk.fractions-decimals', 4, 'Express 0.625 as a fraction in lowest terms.', '["5/8","6/10","25/40","3/5"]'::jsonb, 0, '0.625 = 625/1000. Divide by GCF 125: 5/8. Options 6/10 and 25/40 are equivalent but not fully reduced; 3/5 = 0.60 ≠ 0.625.', true),
  ('MK-EP-1', 'MK', 'mk.exponents-polynomials', 3, 'Simplify: 2³ × 2⁴', '["2⁶","2⁷","4⁷","8⁷"]'::jsonb, 1, 'When multiplying powers with the same base, add the exponents: 2³ × 2⁴ = 2^(3+4) = 2⁷ = 128.', true),
  ('MK-EP-2', 'MK', 'mk.exponents-polynomials', 3, 'What is (3²)³?', '["3⁵","3⁶","9³","27²"]'::jsonb, 1, 'Power of a power rule: multiply the exponents. (3²)³ = 3^(2×3) = 3⁶ = 729. The trap is adding instead of multiplying to get 3⁵.', true),
  ('MK-EP-3', 'MK', 'mk.exponents-polynomials', 4, 'Expand and simplify: (x + 4)(x − 3)', '["x² − 12","x² + x − 12","x² − x − 12","x² + 7x − 12"]'::jsonb, 1, 'FOIL: x·x + x·(−3) + 4·x + 4·(−3) = x² − 3x + 4x − 12 = x² + x − 12.', true),
  ('MK-EP-4', 'MK', 'mk.exponents-polynomials', 4, 'Factor: x² − 9', '["(x − 3)²","(x + 3)(x − 3)","(x − 9)(x + 1)","(x + 9)(x − 1)"]'::jsonb, 1, 'This is a difference of squares: x² − 9 = x² − 3² = (x + 3)(x − 3). The trap (x − 3)² expands to x² − 6x + 9, not x² − 9.', true),
  ('MK-EP-5', 'MK', 'mk.exponents-polynomials', 4, 'Simplify: (4x³y²) ÷ (2xy)', '["2x²y","2x³y","4x²y","2x²y²"]'::jsonb, 0, 'Coefficients: 4 ÷ 2 = 2. x-terms: x³ ÷ x = x². y-terms: y² ÷ y = y. Result: 2x²y.', true),
  ('MK-GE-1', 'MK', 'mk.geometry', 3, 'A rectangular field is 80 meters long and 35 meters wide. What is its perimeter?', '["115 m","230 m","270 m","2,800 m"]'::jsonb, 1, 'Perimeter = 2(l + w) = 2(80 + 35) = 2(115) = 230 m. The trap is computing l + w once (115 m) without multiplying by 2.', true),
  ('MK-GE-2', 'MK', 'mk.geometry', 3, 'A triangle has a base of 14 cm and a height of 9 cm. What is its area?', '["46 cm²","63 cm²","126 cm²","252 cm²"]'::jsonb, 1, 'Area = (1/2) × base × height = (1/2) × 14 × 9 = 63 cm². The trap is omitting the 1/2 factor, giving 126 cm².', true),
  ('MK-GE-3', 'MK', 'mk.geometry', 4, 'A cylinder has a radius of 5 cm and a height of 10 cm. What is its volume? (Use π ≈ 3.14)', '["157 cm³","314 cm³","785 cm³","1,570 cm³"]'::jsonb, 2, 'V = πr²h = 3.14 × 5² × 10 = 3.14 × 25 × 10 = 785 cm³. Using the diameter (10) as the radius gives 3.14 × 100 × 10 = 3,140 — a common error.', true),
  ('MK-GE-4', 'MK', 'mk.geometry', 3, 'A circle has a diameter of 10 cm. What is its area? (Use π ≈ 3.14)', '["31.4 cm²","62.8 cm²","78.5 cm²","314 cm²"]'::jsonb, 2, 'Radius = diameter ÷ 2 = 5 cm. Area = πr² = 3.14 × 25 = 78.5 cm². Using the diameter as the radius gives 3.14 × 100 = 314 — a classic trap.', true),
  ('MK-NP-1', 'MK', 'mk.number-properties', 3, 'Which of the following is a prime number?', '["51","57","61","91"]'::jsonb, 2, '51 = 3 × 17; 57 = 3 × 19; 91 = 7 × 13. Only 61 has no factors besides 1 and itself, so it is prime.', true),
  ('MK-NP-2', 'MK', 'mk.number-properties', 3, 'What is the greatest common factor (GCF) of 36 and 48?', '["6","9","12","18"]'::jsonb, 2, 'Factors of 36 include 1, 2, 3, 4, 6, 9, 12, 18, 36. Factors of 48 include 1, 2, 3, 4, 6, 8, 12, 16, 24, 48. The largest common factor is 12.', true),
  ('MK-NP-3', 'MK', 'mk.number-properties', 4, 'The product of two consecutive even integers is 48. What is the smaller integer?', '["4","6","8","10"]'::jsonb, 1, 'Let the integers be n and n + 2. n(n + 2) = 48. Try n = 6: 6 × 8 = 48. ✓ The smaller integer is 6.', true),
  ('MK-NP-4', 'MK', 'mk.number-properties', 4, 'A number N is divisible by both 6 and 10. What is the smallest positive value N can be?', '["16","30","60","120"]'::jsonb, 1, 'The least common multiple (LCM) of 6 and 10 is found using prime factors: 6 = 2 × 3, 10 = 2 × 5. LCM = 2 × 3 × 5 = 30. The trap is multiplying 6 × 10 = 60.', true),
  ('WK-SN-2', 'WK', 'wk.synonyms', 2, 'TRANQUIL most nearly means:', '["Noisy","Peaceful","Rushed","Dangerous"]'::jsonb, 1, 'Tranquil means free from disturbance; calm and peaceful.', true),
  ('WK-SN-5', 'WK', 'wk.synonyms', 3, 'LETHARGIC most nearly means:', '["Energetic","Sluggish","Aggressive","Focused"]'::jsonb, 1, 'Lethargic means lacking energy or enthusiasm; sluggish. Energetic is its antonym.', true),
  ('WK-SN-6', 'WK', 'wk.synonyms', 4, 'INSCRUTABLE most nearly means:', '["Mysterious","Obvious","Unreliable","Talkative"]'::jsonb, 0, 'Inscrutable means impossible to understand or interpret; mysterious. The root ''scrutin-'' means to examine — inscrutable means it cannot be read through.', true),
  ('WK-SN-10', 'WK', 'wk.synonyms', 5, 'RECALCITRANT most nearly means:', '["Obedient","Defiant","Cautious","Calculating"]'::jsonb, 1, 'Recalcitrant means stubbornly resistant to authority or control. ''Calculating'' is a common wrong answer due to visual similarity. From Latin calcitrare, to kick.', true),
  ('AO-3D-1', 'AO', 'ao.3d-visualization', 3, 'A solid cube rests flat on a table. The top face is painted red. The cube is rotated 90° forward — tilting toward you, pivoting around its front bottom edge. After this rotation, which face is now on top?', '["The original top face (red)","The original front face","The original back face","The original bottom face"]'::jsonb, 1, 'Rotating 90° forward around the front bottom edge lifts the front face up to become the new top. The red original top now faces toward you (the new front).', true),
  ('AO-3D-3', 'AO', 'ao.3d-visualization', 4, 'A cube''s faces are colored: top = white, bottom = black, front = red, back = green, left = blue, right = yellow. The cube is rotated 90° to the right (around the vertical axis — the right side swings to the front). What color is now on top?', '["White","Black","Yellow","Blue"]'::jsonb, 0, 'Rotating around the vertical axis does not change the top or bottom faces — only the four side faces rotate. The top remains white.', true),
  ('AO-3D-4', 'AO', 'ao.3d-visualization', 3, 'Using the same colored cube (top = white, front = red, right = yellow, bottom = black, back = green, left = blue): after rotating 90° to the right around the vertical axis, what color is now facing you (front)?', '["Red","Green","Yellow","Blue"]'::jsonb, 2, 'Rotating the cube 90° to the right (vertical axis) brings the right face (yellow) to the front. Red rotates to the left, green to the right, and blue to the back.', true),
  ('AO-3D-5', 'AO', 'ao.3d-visualization', 5, 'A cube is sliced by a flat plane that passes through exactly three vertices of the cube, one vertex on each of three different faces that share no common edge. What shape is the cross-section?', '["Square","Rectangle","Equilateral triangle","Right triangle"]'::jsonb, 2, 'A plane through three mutually non-adjacent vertices of a cube cuts through three face diagonals of equal length, forming an equilateral triangle cross-section.', true),
  ('AO-PF-1', 'AO', 'ao.paper-folding-nets', 3, 'A flat net consists of 1 center square with 4 squares attached, one to each side (forming a plus/cross shape — 5 squares total). When folded, what 3D shape does it create?', '["A cube","A square pyramid","An open-top box (box without a lid)","A triangular prism"]'::jsonb, 2, 'Five squares form a base plus four walls but no top. You need 6 squares to close a cube. This net creates an open-top box.', true),
  ('AO-PF-3', 'AO', 'ao.paper-folding-nets', 3, 'A flat net consists of a square in the center with 4 equilateral triangles attached to each of the square''s edges. When folded, what shape does it form?', '["A cube","A rectangular prism","A square pyramid","A triangular prism"]'::jsonb, 2, 'The four triangles fold upward and their free vertices meet at a single point above the square base, forming a square pyramid.', true),
  ('AO-PF-4', 'AO', 'ao.paper-folding-nets', 4, 'A cube net: face A is in the center; face B is directly above A; face C is directly below A; face D is to the left of A; face E is to the right of A; face F is directly below C. When folded into a cube, which face is directly opposite face B?', '["Face A","Face C","Face F","Face D"]'::jsonb, 1, 'With face A as the base of the cube, B folds up to be the back wall and C folds up to be the front wall — making B and C opposite faces. D and E become the left and right sides (also opposite). F, attached to C’s far edge, folds over to become the top — making F opposite A. Therefore the face opposite B is C.', true),
  ('AO-PF-5', 'AO', 'ao.paper-folding-nets', 5, 'A square sheet of paper is folded in half by bringing the bottom edge up to meet the top edge (a horizontal fold). The resulting rectangle is then folded in half by bringing the right edge over to meet the left edge (a vertical fold). The paper is then fully unfolded. How many rectangular sections does the paper have?', '["2","4","6","8"]'::jsonb, 1, 'The first fold creates 2 sections; the second fold divides each of those in half. When unfolded, the paper has 2 × 2 = 4 rectangular sections separated by the two crease lines.', true),
  ('AO-SC-1', 'AO', 'ao.spatial-counting', 3, 'A structure is built by stacking cubes. The bottom layer is a 3×3 grid (9 cubes). The second layer is a 2×2 grid centered on the first (4 cubes). The third layer has 1 cube centered on the second. How many cubes are in the structure?', '["9","12","14","16"]'::jsonb, 2, 'Total = 9 + 4 + 1 = 14 cubes.', true),
  ('AO-SC-3', 'AO', 'ao.spatial-counting', 3, 'You see a staircase of cubes: 3 cubes on the bottom row, 2 cubes on the middle row, and 1 cube on the top. All rows are aligned to the left edge. How many cubes are in the structure?', '["5","6","7","9"]'::jsonb, 1, 'Total = 3 + 2 + 1 = 6 cubes.', true),
  ('AO-SC-4', 'AO', 'ao.spatial-counting', 4, 'A 2×3 single-layer base (6 cubes) sits on a table. A second layer of 2×2 cubes is stacked on top starting from one corner. How many cubes are in the complete structure?', '["8","9","10","12"]'::jsonb, 2, 'Bottom layer: 2 × 3 = 6. Second layer: 2 × 2 = 4. Total = 6 + 4 = 10 cubes.', true),
  ('AO-SC-5', 'AO', 'ao.spatial-counting', 5, 'A 4×4×4 large cube is built from unit cubes. How many unit cubes are completely hidden inside (touching no outer face)?', '["0","4","8","16"]'::jsonb, 2, 'The hidden interior is a (4−2)×(4−2)×(4−2) = 2×2×2 = 8 unit cube block. Every other unit cube touches at least one outer face.', true),
  ('AR-AF-B3-1', 'AR', 'ar.arithmetic-fundamentals', 2, 'A classroom has 6 rows of desks with 5 desks in each row. How many desks are in the classroom?', '["11","25","30","36"]'::jsonb, 2, 'Total desks = 6 × 5 = 30. Adding 6 + 5 = 11 instead of multiplying is the most common error.', true),
  ('AR-AF-B3-2', 'AR', 'ar.arithmetic-fundamentals', 3, 'A warehouse receives 3 shipments of 144 items each. Workers then remove 85 items for immediate distribution. How many items remain in the warehouse?', '["347","357","372","432"]'::jsonb, 0, 'Total received = 3 × 144 = 432. Remaining = 432 − 85 = 347. The trap answer 432 ignores the removal step.', true),
  ('AR-AF-B3-3', 'AR', 'ar.arithmetic-fundamentals', 3, 'A painter earns $18 per hour and works 7 hours on Monday, 5 hours on Tuesday, and 6 hours on Wednesday. What are her total earnings for the three days?', '["$216","$252","$288","$324"]'::jsonb, 3, 'Total hours = 7 + 5 + 6 = 18 hours. Earnings = 18 × $18 = $324. The trap is computing 18 hours but multiplying by the wrong wage (e.g., $16/hr = $288).', true),
  ('AR-AF-B3-4', 'AR', 'ar.arithmetic-fundamentals', 4, 'A fuel tank holds 320 gallons when full. A convoy uses 3/8 of the fuel. How many gallons remain?', '["120 gallons","160 gallons","200 gallons","240 gallons"]'::jsonb, 2, 'Fuel used = (3/8) × 320 = 120 gallons. Remaining = 320 − 120 = 200 gallons. The trap is choosing 120 (the amount used, not the amount remaining).', true),
  ('AR-AF-B3-5', 'AR', 'ar.arithmetic-fundamentals', 4, 'A soldier earns $2,640 per month. She contributes 5% to a savings plan and pays $420 in rent. What is her take-home pay after both deductions?', '["$2,088","$2,100","$2,112","$2,220"]'::jsonb, 0, 'Savings contribution = 5% × $2,640 = $132. Take-home = $2,640 − $132 − $420 = $2,088. The trap is forgetting the 5% contribution and subtracting only rent: $2,640 − $420 = $2,220.', true),
  ('AR-AF-B3-6', 'AR', 'ar.arithmetic-fundamentals', 3, 'A store sells notebooks for $2.50 each and pens for $0.75 each. A student buys 8 notebooks and 10 pens. What is the total cost?', '["$25.00","$26.50","$27.50","$28.00"]'::jsonb, 2, 'Notebooks: 8 × $2.50 = $20.00. Pens: 10 × $0.75 = $7.50. Total = $20.00 + $7.50 = $27.50.', true),
  ('AR-AF-B3-7', 'AR', 'ar.arithmetic-fundamentals', 4, 'A bus seats 48 passengers. On three consecutive trips, it carries 35, 41, and 48 passengers. What is the total number of empty seats across all three trips?', '["18","20","22","24"]'::jsonb, 1, 'Empty seats: trip 1 = 48 − 35 = 13; trip 2 = 48 − 41 = 7; trip 3 = 48 − 48 = 0. Total empty = 13 + 7 + 0 = 20.', true),
  ('AR-AF-B3-8', 'AR', 'ar.arithmetic-fundamentals', 5, 'A supply depot has 2,400 ration packs. Each platoon of 30 soldiers needs 4 packs per soldier per day. If 4 platoons draw supplies for 2 days, how many ration packs remain?', '["480","960","1,440","1,920"]'::jsonb, 2, 'Packs drawn per platoon per day = 30 × 4 = 120. Total drawn = 4 platoons × 120 × 2 days = 960 packs. Remaining = 2,400 − 960 = 1,440. The trap is computing per-day total only (960) and selecting that as the answer without subtracting from stock.', true),
  ('AR-AF-B3-9', 'AR', 'ar.arithmetic-fundamentals', 5, 'A mess hall serves breakfast daily. Each soldier eats 4 eggs at breakfast. For a unit of 120 soldiers over 5 days, how many total eggs are used at breakfast?', '["480","1,200","2,000","2,400"]'::jsonb, 3, 'Eggs = 4 per soldier × 120 soldiers × 5 days = 2,400 eggs. The trap is computing 4 × 120 = 480 and forgetting to multiply by the 5-day period.', true),
  ('AR-AF-B3-10', 'AR', 'ar.arithmetic-fundamentals', 5, 'A warehouse stores canned goods on pallets. Each pallet holds 48 cases; each case holds 24 cans. Three pallets arrive fully loaded. Then 864 cans are removed. How many cans remain?', '["2,592","2,736","2,880","3,024"]'::jsonb, 0, 'Total cans = 3 × 48 × 24 = 3,456. After removal: 3,456 − 864 = 2,592. The trap is computing 3 × 48 = 144 and subtracting 864 as if it were cases rather than individual cans.', true),
  ('AR-AF-B3-11', 'AR', 'ar.arithmetic-fundamentals', 4, 'A canteen sells water bottles for $1.25 each. A soldier buys 16 bottles and pays with a $20 bill and a $5 bill. How much change does he receive?', '["$1.00","$3.00","$5.00","$7.00"]'::jsonb, 2, 'Cost = 16 × $1.25 = $20.00. Total paid = $20 + $5 = $25. Change = $25 − $20 = $5.00.', true),
  ('AR-AF-B3-12', 'AR', 'ar.arithmetic-fundamentals', 3, 'A recruit runs 3 miles on Monday, 4 miles on Wednesday, and 5 miles on Friday. How many miles does she run in total?', '["10","11","12","13"]'::jsonb, 2, 'Total = 3 + 4 + 5 = 12 miles.', true),
  ('AR-AF-B3-13', 'AR', 'ar.arithmetic-fundamentals', 2, 'A school trip costs $15 per student. There are 32 students registered, but 4 drop out. How much is collected from the students who actually attend?', '["$360","$390","$420","$480"]'::jsonb, 2, 'Students attending = 32 − 4 = 28. Revenue = 28 × $15 = $420. The trap is computing 32 × $15 = $480 before accounting for the dropouts.', true),
  ('AR-AF-B3-14', 'AR', 'ar.arithmetic-fundamentals', 4, 'A truck can carry 1,200 pounds. It is loaded with 10 boxes at 80 pounds each and 5 boxes at 48 pounds each. How many pounds of remaining capacity does the truck have?', '["160 pounds","180 pounds","200 pounds","240 pounds"]'::jsonb, 0, 'Heavy boxes: 10 × 80 = 800 lb. Light boxes: 5 × 48 = 240 lb. Total loaded = 1,040 lb. Remaining = 1,200 − 1,040 = 160 lb. The trap is adding only 10 boxes: 10 × 80 = 800; 1,200 − 800 = 400, ignoring the lighter boxes.', true),
  ('AR-RP-B3-1', 'AR', 'ar.ratio-proportion', 3, 'A map uses a scale of 1 inch = 20 miles. Two towns are 4 inches apart on the map. What is the actual distance between them?', '["5 miles","24 miles","80 miles","100 miles"]'::jsonb, 2, 'Actual distance = 4 × 20 = 80 miles. The trap is dividing 20 ÷ 4 = 5, which inverts the scale.', true),
  ('AR-RP-B3-2', 'AR', 'ar.ratio-proportion', 3, 'Concrete is mixed using cement, sand, and gravel in a ratio of 1:2:3. To produce 360 pounds of concrete, how many pounds of sand are needed?', '["60","90","120","180"]'::jsonb, 2, 'Total parts = 1 + 2 + 3 = 6. Sand portion = 2/6 of 360 = 120 pounds. The trap is using 2/3 of 360 = 240, which treats the ratio as sand:other rather than sand:total.', true),
  ('AR-RP-B3-3', 'AR', 'ar.ratio-proportion', 3, 'A car uses 3 gallons of fuel for every 75 miles driven. At the same rate, how many gallons are needed for a 325-mile trip?', '["9","11","13","15"]'::jsonb, 2, 'Rate = 75 ÷ 3 = 25 miles per gallon. Gallons needed = 325 ÷ 25 = 13 gallons.', true),
  ('AR-RP-B3-4', 'AR', 'ar.ratio-proportion', 4, 'A trail mix uses nuts and dried fruit in a ratio of 5:3 by weight. A hiker makes 4 pounds of trail mix. How many ounces of dried fruit does she need? (1 pound = 16 ounces)', '["24 oz","30 oz","32 oz","40 oz"]'::jsonb, 0, 'Total parts = 8. Dried fruit = (3/8) × 4 lb = 1.5 lb = 1.5 × 16 = 24 oz. The trap is using 3/5 of 4 lb = 2.4 lb = 38.4 oz, which treats the ratio as fruit:nuts rather than fruit:total.', true),
  ('AR-RP-B3-5', 'AR', 'ar.ratio-proportion', 4, 'A machine produces 420 parts in 7 hours. At the same rate, how many parts does it produce in 10 hours?', '["540","560","580","600"]'::jsonb, 3, 'Rate = 420 ÷ 7 = 60 parts/hour. Output in 10 hours = 60 × 10 = 600 parts.', true),
  ('AR-RP-B3-6', 'AR', 'ar.ratio-proportion', 4, 'A scale model of a ship is built at a ratio of 1:250. The model is 48 centimeters long. What is the actual length of the ship in meters?', '["90 m","100 m","120 m","150 m"]'::jsonb, 2, 'Actual length in cm = 48 × 250 = 12,000 cm. Convert to meters: 12,000 ÷ 100 = 120 m. The trap is reporting the answer in centimeters (12,000) or forgetting the conversion factor.', true),
  ('AR-RP-B3-7', 'AR', 'ar.ratio-proportion', 3, 'A recipe for 12 cookies requires 2 cups of flour. How many cups of flour are needed for 42 cookies?', '["5","6","7","8"]'::jsonb, 2, 'Proportion: 2/12 = x/42. Cross-multiply: 12x = 84. x = 7 cups. Alternatively, scale factor = 42/12 = 3.5; flour = 2 × 3.5 = 7 cups.', true),
  ('AR-RP-B3-8', 'AR', 'ar.ratio-proportion', 4, 'Two workers share a project payment in proportion to the hours each works. Worker A works 18 hours and Worker B works 12 hours. The total payment is $750. How much does Worker A receive?', '["$300","$375","$420","$450"]'::jsonb, 3, 'Total hours = 18 + 12 = 30. Worker A''s share = (18/30) × $750 = 0.60 × $750 = $450. The trap is selecting Worker B''s share (12/30 × $750 = $300) or splitting equally ($375).', true),
  ('AR-RP-B3-9', 'AR', 'ar.ratio-proportion', 5, 'Eight workers can load a truck in 3 hours. Two workers leave after the first hour. How many additional hours will the remaining 6 workers need to finish the job?', '["2 hours","2 hours 20 minutes","2 hours 40 minutes","3 hours"]'::jsonb, 2, 'Total work = 8 × 3 = 24 worker-hours. After hour 1, work completed = 8 worker-hours. Remaining = 16 worker-hours. With 6 workers: 16 ÷ 6 = 2⅔ hours = 2 hours 40 minutes.', true),
  ('AR-RP-B3-10', 'AR', 'ar.ratio-proportion', 3, 'A paint color is mixed using blue and white paint in a ratio of 2:5 (blue:white). A painter needs 28 ounces of the mixture total. How many ounces of blue paint are needed?', '["4","6","8","10"]'::jsonb, 2, 'Total parts = 2 + 5 = 7. Blue portion = (2/7) × 28 = 8 ounces. The trap is computing (2/5) × 28 ≈ 11.2, treating the ratio as blue:white rather than blue:total.', true),
  ('AR-RP-B3-11', 'AR', 'ar.ratio-proportion', 5, 'Two pipes together fill a tank in 4 hours. Pipe A alone fills the tank in 6 hours. How long does Pipe B take to fill the tank alone?', '["8 hours","10 hours","12 hours","14 hours"]'::jsonb, 2, 'Combined rate = 1/4. Pipe A rate = 1/6. Pipe B rate = 1/4 − 1/6 = 3/12 − 2/12 = 1/12. Pipe B alone takes 12 hours. The trap is subtracting times directly: 4 − 6 = −2, which is meaningless.', true),
  ('AR-RP-B3-12', 'AR', 'ar.ratio-proportion', 5, 'In a survey, the ratio of respondents who prefer Brand A : Brand B : Brand C is 4:3:2. A total of 270 people were surveyed. How many more people prefer Brand A than Brand C?', '["30","45","60","90"]'::jsonb, 2, 'Total parts = 9. Each part = 270 ÷ 9 = 30. Brand A = 4 × 30 = 120. Brand C = 2 × 30 = 60. Difference = 60. The trap is computing the difference in parts (4 − 2 = 2) and answering 2, or selecting 30 (one part).', true),
  ('AR-RP-B3-13', 'AR', 'ar.ratio-proportion', 4, 'On a blueprint, 1/4 inch represents 6 feet. A room on the blueprint is 3.5 inches wide. What is the actual width of the room in feet?', '["72 feet","78 feet","84 feet","96 feet"]'::jsonb, 2, 'Scale: 1/4 inch = 6 feet, so 1 inch = 24 feet. Actual width = 3.5 × 24 = 84 feet. The trap is multiplying 3.5 × 6 = 21, failing to account for the fact that each inch contains four quarter-inches.', true),
  ('AR-RP-B3-14', 'AR', 'ar.ratio-proportion', 5, 'A caterer makes punch using juice and sparkling water in a ratio of 3:7 (juice:water). She needs 50 liters total. How many liters of juice are needed?', '["12 liters","15 liters","18 liters","21 liters"]'::jsonb, 1, 'Total parts = 3 + 7 = 10. Juice = (3/10) × 50 = 15 liters. The trap is using 3/7 of 50 ≈ 21.4 liters, treating the ratio as juice:water rather than juice:total.', true),
  ('AR-PC-B3-1', 'AR', 'ar.percent', 3, 'A test has 40 questions. A student answers 30 correctly. What percent did the student answer correctly?', '["65%","70%","75%","80%"]'::jsonb, 2, 'Percent correct = (30 ÷ 40) × 100 = 75%.', true),
  ('AR-PC-B3-2', 'AR', 'ar.percent', 2, 'What is 30% of 150?', '["35","40","45","50"]'::jsonb, 2, '30% × 150 = 0.30 × 150 = 45.', true),
  ('AR-PC-B3-3', 'AR', 'ar.percent', 3, 'A phone originally priced at $360 is discounted by 15%. What is the sale price?', '["$288","$300","$306","$312"]'::jsonb, 2, 'Discount = 15% × $360 = $54. Sale price = $360 − $54 = $306. The trap is computing a 16.7% discount or rounding $360 × 0.85 incorrectly to $300.', true),
  ('AR-PC-B3-4', 'AR', 'ar.percent', 3, 'A soldier''s weight dropped from 200 pounds to 185 pounds during training. What is the percent decrease?', '["6.5%","7.0%","7.5%","8.1%"]'::jsonb, 2, 'Decrease = 15 lb. Percent decrease = (15 ÷ 200) × 100 = 7.5%. The trap is dividing by the new weight: 15 ÷ 185 ≈ 8.1%.', true),
  ('AR-PC-B3-5', 'AR', 'ar.percent', 3, 'A charity collected $3,200 last year. This year it collected $4,000. By what percent did collections increase?', '["20%","25%","28%","33%"]'::jsonb, 1, 'Increase = $800. Percent increase = ($800 ÷ $3,200) × 100 = 25%. The trap is dividing by the new amount: $800 ÷ $4,000 = 20%.', true),
  ('AR-PC-B3-6', 'AR', 'ar.percent', 3, 'In a class of 60 students, 45% received a grade of A or B. How many students received an A or B?', '["24","27","30","33"]'::jsonb, 1, '45% × 60 = 0.45 × 60 = 27 students. The trap is rounding 45% to 50% and computing 30.', true),
  ('AR-PC-B3-7', 'AR', 'ar.percent', 4, 'A bank account has a balance of $2,500. It earns 4% simple annual interest. What is the balance after 2.5 years?', '["$2,600","$2,750","$2,800","$2,850"]'::jsonb, 1, 'Interest = $2,500 × 0.04 × 2.5 = $250. Balance = $2,500 + $250 = $2,750. The trap is computing only 1 year of interest ($100) and arriving at $2,600.', true),
  ('AR-PC-B3-8', 'AR', 'ar.percent', 4, 'A restaurant bill comes to $48. A 20% tip and an 8% tax are both applied to the original $48 bill. What is the total amount paid?', '["$56.64","$60.48","$61.44","$62.08"]'::jsonb, 2, 'Tip = 20% × $48 = $9.60. Tax = 8% × $48 = $3.84. Total = $48 + $9.60 + $3.84 = $61.44. The trap is applying tax to the post-tip amount ($57.60 × 0.08 = $4.61), which gives a different total.', true),
  ('AR-PC-B3-9', 'AR', 'ar.percent', 4, 'A mutual fund gained 20% in Year 1, then lost 20% in Year 2 from the Year 1 ending value. Starting with $1,000, what is the value after Year 2?', '["$960","$970","$980","$1,000"]'::jsonb, 0, 'After Year 1: $1,000 × 1.20 = $1,200. After Year 2: $1,200 × 0.80 = $960. The trap is assuming +20% and −20% cancel out, returning $1,000; they do not because the 20% loss applies to the higher Year 1 balance.', true),
  ('AR-PC-B3-10', 'AR', 'ar.percent', 5, 'A laptop is marked up 40% from its wholesale cost, then placed on sale for 25% off the marked-up price. The sale price is $252. What was the original wholesale cost?', '["$210","$240","$250","$270"]'::jsonb, 1, 'Let wholesale cost = W. Marked-up price = 1.40W. Sale price = 1.40W × 0.75 = 1.05W = $252. W = $252 ÷ 1.05 = $240. The trap is netting the percentages: +40% − 25% = +15%, giving W = $252 ÷ 1.15 ≈ $219.', true),
  ('AR-PC-B3-11', 'AR', 'ar.percent', 5, 'A store reduces a price by 30%, then reduces it again by 20% from the already-reduced price. What single percent reduction would produce the same final price?', '["44%","46%","48%","50%"]'::jsonb, 0, 'Combined multiplier = 0.70 × 0.80 = 0.56. Total reduction = 1 − 0.56 = 0.44 = 44%. The trap is adding 30% + 20% = 50%, which ignores that the second reduction applies to an already-reduced base.', true),
  ('AR-PC-B3-12', 'AR', 'ar.percent', 5, 'A clothing store applies a 35% markup to all wholesale costs, then offers 20% off the marked-up price at clearance. A jacket''s clearance price is $86.40. What was the wholesale cost?', '["$72","$80","$88","$96"]'::jsonb, 1, 'Let W = wholesale. Marked-up = 1.35W. Clearance = 1.35W × 0.80 = 1.08W = $86.40. W = $86.40 ÷ 1.08 = $80. The trap is netting percents (35% − 20% = 15%) and dividing: $86.40 ÷ 1.15 ≈ $75.', true),
  ('AR-PC-B3-13', 'AR', 'ar.percent', 5, 'A company''s revenue grew by 25% in Q1 and by 16% in Q2 relative to the Q1 ending revenue. If starting revenue was $80,000, what was the revenue at the end of Q2?', '["$103,200","$107,200","$112,800","$116,000"]'::jsonb, 3, 'After Q1: $80,000 × 1.25 = $100,000. After Q2: $100,000 × 1.16 = $116,000. The trap is adding the growth rates: 25% + 16% = 41%, giving $80,000 × 1.41 = $112,800.', true),
  ('AR-PC-B3-14', 'AR', 'ar.percent', 4, 'A worker earns $160 per week. She receives a 25% raise. That same week she also earns a bonus equal to 12% of her new weekly wage. What is her total pay for that week?', '["$200","$212","$224","$236"]'::jsonb, 2, 'New weekly wage = $160 × 1.25 = $200. Bonus = 12% × $200 = $24. Total = $200 + $24 = $224. The trap is computing 12% of the original wage ($160 × 0.12 = $19.20) and adding to $200, giving $219.20.', true),
  ('AR-RD-B3-1', 'AR', 'ar.rate-distance-time', 3, 'A car travels at 50 mph. How far does it travel in 3 hours?', '["100 miles","140 miles","150 miles","160 miles"]'::jsonb, 2, 'Distance = speed × time = 50 × 3 = 150 miles.', true),
  ('AR-RD-B3-2', 'AR', 'ar.rate-distance-time', 3, 'A cyclist rides at 15 mph. How far does she travel in 2 hours and 20 minutes?', '["30 miles","33 miles","35 miles","37 miles"]'::jsonb, 2, '2 hours 20 minutes = 7/3 hours. Distance = 15 × 7/3 = 35 miles.', true),
  ('AR-RD-B3-3', 'AR', 'ar.rate-distance-time', 3, 'A train travels 360 miles in 4 hours. At the same speed, how long will it take the train to travel 495 miles?', '["4.5 hours","5 hours","5.5 hours","6 hours"]'::jsonb, 2, 'Speed = 360 ÷ 4 = 90 mph. Time = 495 ÷ 90 = 5.5 hours.', true),
  ('AR-RD-B3-4', 'AR', 'ar.rate-distance-time', 3, 'A plane flies 1,200 miles in 2.5 hours. What is the plane''s average speed?', '["400 mph","440 mph","460 mph","480 mph"]'::jsonb, 3, 'Speed = 1,200 ÷ 2.5 = 480 mph.', true),
  ('AR-RD-B3-5', 'AR', 'ar.rate-distance-time', 4, 'Two runners start at the same point and run in opposite directions. Runner A runs at 7 mph and Runner B at 9 mph. After how many hours are they 64 miles apart?', '["3 hours","4 hours","5 hours","6 hours"]'::jsonb, 1, 'Combined separation rate = 7 + 9 = 16 mph. Time = 64 ÷ 16 = 4 hours. The trap is using only one runner''s speed (64 ÷ 7 ≈ 9 or 64 ÷ 9 ≈ 7).', true),
  ('AR-RD-B3-6', 'AR', 'ar.rate-distance-time', 4, 'A supply convoy travels 120 miles to a base, makes a 45-minute stop, then returns over the same route. The convoy travels at 40 mph in both directions. What is the total elapsed time including the stop?', '["5 hours 45 minutes","6 hours 15 minutes","6 hours 45 minutes","7 hours"]'::jsonb, 2, 'One-way driving time = 120 ÷ 40 = 3 hours. Round trip = 6 hours. Stop = 45 min = 0.75 hr. Total = 6.75 hours = 6 hours 45 minutes.', true),
  ('AR-RD-B3-7', 'AR', 'ar.rate-distance-time', 4, 'Worker A can fill a storage bin in 6 hours; Worker B can fill the same bin in 4 hours. How long will it take them working together?', '["2 hours","2 hours 24 minutes","2 hours 48 minutes","3 hours"]'::jsonb, 1, 'Combined rate = 1/6 + 1/4 = 5/12 bins/hour. Time = 12/5 = 2.4 hours = 2 hours 24 minutes. The trap is averaging the times: (6 + 4) ÷ 2 = 5 hours.', true),
  ('AR-RD-B3-8', 'AR', 'ar.rate-distance-time', 5, 'A drain empties a 900-gallon pool at 30 gallons per minute. A hose adds water at 12 gallons per minute. Both run simultaneously starting with the pool full. How many minutes until the pool is empty?', '["30 minutes","40 minutes","45 minutes","50 minutes"]'::jsonb, 3, 'Net drain rate = 30 − 12 = 18 gal/min. Time to empty = 900 ÷ 18 = 50 minutes. The trap is using only the drain rate: 900 ÷ 30 = 30 minutes.', true),
  ('AR-RD-B3-9', 'AR', 'ar.rate-distance-time', 4, 'A soldier jogs to a checkpoint at 6 mph and walks back the same route at 4 mph. The total round trip takes 2.5 hours. How far away is the checkpoint?', '["4 miles","5 miles","6 miles","8 miles"]'::jsonb, 2, 'Let distance = d. Time equation: d/6 + d/4 = 2.5. LCD = 12: 2d/12 + 3d/12 = 5d/12 = 2.5. d = 2.5 × 12/5 = 6 miles. The trap is dividing 2.5 by the average speed (5 mph) to get 5 miles.', true),
  ('AR-RD-B3-10', 'AR', 'ar.rate-distance-time', 5, 'A and B start from the same town at the same time. A heads north at 50 mph; B heads east at 120 mph. After how many hours is the straight-line distance between them exactly 130 miles?', '["1 hour","1.5 hours","2 hours","2.5 hours"]'::jsonb, 0, 'After t hours, A is 50t miles north and B is 120t miles east. Distance = √((50t)² + (120t)²) = t√(2,500 + 14,400) = 130t = 130, so t = 1 hour. This uses the 5-12-13 triple (50 = 5×10, 120 = 12×10, 130 = 13×10).', true),
  ('AR-RD-B3-11', 'AR', 'ar.rate-distance-time', 5, 'Three painters working together: Painter 1''s rate is 1/6 of a fence per hour; Painter 2''s rate is 1/8 per hour; Painter 3''s rate is 1/12 per hour. How long does it take all three to paint the entire fence?', '["2 hours 10 minutes","2 hours 40 minutes","3 hours","3 hours 20 minutes"]'::jsonb, 1, 'Combined rate = 1/6 + 1/8 + 1/12 = 4/24 + 3/24 + 2/24 = 9/24 = 3/8 fence/hr. Time = 8/3 hours = 2⅔ hours = 2 hours 40 minutes.', true),
  ('AR-RD-B3-12', 'AR', 'ar.rate-distance-time', 4, 'Car A leaves City X at 8:00 AM toward City Y at 60 mph. Car B leaves City Y at 9:00 AM toward City X at 90 mph. The cities are 210 miles apart. At what time do the cars meet?', '["9:30 AM","10:00 AM","10:30 AM","11:00 AM"]'::jsonb, 1, 'By 9:00 AM, Car A has gone 60 miles; gap remaining = 210 − 60 = 150 miles. After 9 AM, combined closing speed = 60 + 90 = 150 mph. Time to close = 150 ÷ 150 = 1 hour. Cars meet at 10:00 AM.', true),
  ('AR-RD-B3-13', 'AR', 'ar.rate-distance-time', 3, 'A cargo ship travels 540 nautical miles at 18 knots, then returns the same distance at 12 knots. What is the total travel time for the round trip?', '["65 hours","70 hours","72 hours","75 hours"]'::jsonb, 3, 'Outbound time = 540 ÷ 18 = 30 hours. Return time = 540 ÷ 12 = 45 hours. Total = 30 + 45 = 75 hours.', true),
  ('AR-RD-B3-14', 'AR', 'ar.rate-distance-time', 5, 'A boat''s engine speed is 14 mph in still water. Traveling downstream with a 4 mph current, it covers 108 miles. How long does the trip take?', '["5 hours","6 hours","6.5 hours","7 hours"]'::jsonb, 1, 'Effective downstream speed = 14 + 4 = 18 mph. Time = 108 ÷ 18 = 6 hours. The trap is using the engine speed alone: 108 ÷ 14 ≈ 7.7 hours.', true),
  ('AR-WP-B3-1', 'AR', 'ar.word-problems', 3, 'A box of 48 granola bars is divided equally among 6 hikers. Each hiker then gives 2 bars to a seventh hiker who arrived late. How many bars does the seventh hiker receive?', '["8","10","12","14"]'::jsonb, 2, 'Each of the 6 hikers starts with 48 ÷ 6 = 8 bars. The seventh hiker gets 2 bars from each of the 6: 2 × 6 = 12 bars.', true),
  ('AR-WP-B3-2', 'AR', 'ar.word-problems', 4, 'A gardener plants tomatoes in 5 rows with 12 plants each and peppers in 4 rows with 9 plants each. How many plants are there in total?', '["84","88","92","96"]'::jsonb, 3, 'Tomatoes = 5 × 12 = 60. Peppers = 4 × 9 = 36. Total = 60 + 36 = 96.', true),
  ('AR-WP-B3-3', 'AR', 'ar.word-problems', 4, 'A jogger burns 8 calories per minute while running and 3 calories per minute while walking. She runs for 25 minutes and walks for 20 minutes. How many total calories does she burn?', '["240","260","280","300"]'::jsonb, 1, 'Calories running = 8 × 25 = 200. Calories walking = 3 × 20 = 60. Total = 260.', true),
  ('AR-WP-B3-4', 'AR', 'ar.word-problems', 3, 'A merchant buys 60 items at $4 each and sells all of them at $7 each. What is his total profit?', '["$120","$150","$180","$210"]'::jsonb, 2, 'Revenue = 60 × $7 = $420. Cost = 60 × $4 = $240. Profit = $420 − $240 = $180.', true),
  ('AR-WP-B3-5', 'AR', 'ar.word-problems', 5, 'Three siblings split an inheritance. The eldest receives twice as much as the middle sibling, and the middle sibling receives three times as much as the youngest. If the youngest receives $4,200, what is the total inheritance?', '["$29,400","$33,600","$37,800","$42,000"]'::jsonb, 3, 'Youngest = $4,200. Middle = 3 × $4,200 = $12,600. Eldest = 2 × $12,600 = $25,200. Total = $4,200 + $12,600 + $25,200 = $42,000. The trap is computing eldest as 2 × youngest ($8,400) instead of 2 × middle.', true),
  ('AR-WP-B3-6', 'AR', 'ar.word-problems', 4, 'A water tank is 3/4 full. After adding 240 gallons, the tank is 9/10 full. What is the total capacity of the tank in gallons?', '["1,200","1,500","1,600","2,000"]'::jsonb, 2, 'The added 240 gallons raised the level by 9/10 − 3/4 = 18/20 − 15/20 = 3/20 of capacity. So (3/20) × C = 240. C = 240 × 20/3 = 1,600 gallons.', true),
  ('AR-WP-B3-7', 'AR', 'ar.word-problems', 4, 'A plumber charges $65 for the first hour and $45 for each additional hour, plus a flat $20 materials fee. If a job takes 4 hours total, what is the total bill?', '["$200","$220","$240","$280"]'::jsonb, 1, 'First hour = $65. Additional 3 hours = 3 × $45 = $135. Materials = $20. Total = $65 + $135 + $20 = $220.', true),
  ('AR-WP-B3-8', 'AR', 'ar.word-problems', 5, 'A factory produces two products. Product X requires 3 labor-hours and $12 in materials per unit; Product Y requires 5 labor-hours and $8 in materials per unit. Labor costs $8 per hour. In one week, 20 units of X and 10 units of Y are produced. What is the total production cost?', '["$1,100","$1,200","$1,300","$1,400"]'::jsonb, 1, 'X cost per unit: 3 × $8 + $12 = $36. Y cost per unit: 5 × $8 + $8 = $48. Total = 20 × $36 + 10 × $48 = $720 + $480 = $1,200. The trap is multiplying all units by only the labor rate and forgetting materials: (20×3 + 10×5) × $8 = 110 × $8 = $880.', true),
  ('AR-WP-B3-10', 'AR', 'ar.word-problems', 4, 'A bookshelf has 8 shelves, each holding 6 books. Currently, 3/4 of the shelves are completely full and the remaining shelves are empty. How many more books can the shelf unit hold?', '["6","8","10","12"]'::jsonb, 3, 'Full shelves = 3/4 × 8 = 6 shelves. Empty shelves = 2. Each empty shelf holds 6 books. Remaining capacity = 2 × 6 = 12 books.', true),
  ('AR-WP-B3-11', 'AR', 'ar.word-problems', 5, 'A catering company charges $11 per adult and $7 per child. At an event, the number of adults is 3 times the number of children. The total bill is $1,200. How many children attended?', '["20","25","30","40"]'::jsonb, 2, 'Let c = number of children; adults = 3c. Bill: 11(3c) + 7c = 33c + 7c = 40c = $1,200. c = 30 children. Verify: 90 adults × $11 = $990; 30 children × $7 = $210; $990 + $210 = $1,200 ✓.', true),
  ('AR-WP-B3-12', 'AR', 'ar.word-problems', 4, 'A bus leaves a depot every 20 minutes. A train leaves the same depot every 30 minutes. Both departed together at 6:00 AM. At what time will they next depart together?', '["6:40 AM","6:50 AM","7:00 AM","7:10 AM"]'::jsonb, 2, 'LCM(20, 30) = 60 minutes. They next depart together 60 minutes after 6:00 AM = 7:00 AM. The trap is adding 20 + 30 = 50 minutes, giving 6:50 AM.', true),
  ('AR-WP-B3-13', 'AR', 'ar.word-problems', 4, 'A soldier''s monthly budget is $2,400. He spends 1/3 on housing, 1/4 on food, and 1/6 on transportation. How much remains for other expenses?', '["$500","$600","$700","$800"]'::jsonb, 1, 'Housing = 1/3 × $2,400 = $800. Food = 1/4 × $2,400 = $600. Transportation = 1/6 × $2,400 = $400. Total spent = $1,800. Remaining = $2,400 − $1,800 = $600.', true),
  ('AR-WP-B3-14', 'AR', 'ar.word-problems', 3, 'A fundraiser sells two types of tickets: regular at $8 and VIP at $20. They sell 150 regular tickets and 50 VIP tickets. What is the total revenue?', '["$1,800","$2,000","$2,200","$2,400"]'::jsonb, 2, 'Regular revenue = 150 × $8 = $1,200. VIP revenue = 50 × $20 = $1,000. Total = $1,200 + $1,000 = $2,200.', true),
  ('MK-AL-B3-1', 'MK', 'mk.algebra-linear', 2, 'Solve for x: x + 14 = 30', '["x = 12","x = 14","x = 16","x = 18"]'::jsonb, 2, 'x = 30 − 14 = 16.', true),
  ('MK-AL-B3-2', 'MK', 'mk.algebra-linear', 3, 'Solve for x: 6x − 11 = 31', '["x = 5","x = 6","x = 7","x = 8"]'::jsonb, 2, '6x = 31 + 11 = 42. x = 42 ÷ 6 = 7.', true),
  ('MK-AL-B3-3', 'MK', 'mk.algebra-linear', 3, 'If y = 3x − 4 and x = 5, what is y?', '["7","9","11","13"]'::jsonb, 2, 'y = 3(5) − 4 = 15 − 4 = 11.', true),
  ('MK-AL-B3-4', 'MK', 'mk.algebra-linear', 3, 'If 3(2x − 4) = 24, what is x?', '["x = 4","x = 5","x = 6","x = 7"]'::jsonb, 2, 'Divide both sides by 3: 2x − 4 = 8. Add 4: 2x = 12. x = 6. The trap is skipping the division step and solving 2x − 4 = 24, giving x = 14.', true),
  ('MK-AL-B3-5', 'MK', 'mk.algebra-linear', 4, 'Solve for y: 4y + 9 = 2y − 5', '["y = −7","y = −5","y = 2","y = 7"]'::jsonb, 0, 'Subtract 2y from both sides: 2y + 9 = −5. Subtract 9: 2y = −14. y = −7. The trap is adding the constants rather than subtracting: 2y = −5 + 9 = 4, giving y = 2.', true),
  ('MK-AL-B3-6', 'MK', 'mk.algebra-linear', 4, 'Which value of x satisfies both inequalities: 2x > 6 AND x + 3 < 10?', '["x = 2","x = 3","x = 4","x = 8"]'::jsonb, 2, 'From 2x > 6: x > 3. From x + 3 < 10: x < 7. So 3 < x < 7. Among the choices, only x = 4 satisfies both. x = 3 fails the strict inequality x > 3; x = 8 fails x < 7.', true),
  ('MK-AL-B3-7', 'MK', 'mk.algebra-linear', 4, 'A number is 5 more than twice another number. Their sum is 29. What is the larger number?', '["17","19","21","23"]'::jsonb, 2, 'Let the smaller number = n. Larger = 2n + 5. Sum: n + 2n + 5 = 29 → 3n = 24 → n = 8. Larger = 2(8) + 5 = 21.', true),
  ('MK-AL-B3-8', 'MK', 'mk.algebra-linear', 4, 'Solve for x: (x/3) + 5 = 11', '["x = 12","x = 15","x = 18","x = 21"]'::jsonb, 2, 'x/3 = 11 − 5 = 6. x = 6 × 3 = 18. The trap is choosing x = 6 (stopping before multiplying by 3).', true),
  ('MK-AL-B3-9', 'MK', 'mk.algebra-linear', 5, 'If 2(3x − 1) = 5x + 4, what is x?', '["x = 4","x = 5","x = 6","x = 7"]'::jsonb, 2, 'Expand: 6x − 2 = 5x + 4. Subtract 5x: x − 2 = 4. x = 6. The trap is distributing 2 only to 3x (ignoring −1): 6x − 1 = 5x + 4, giving x = 5.', true),
  ('MK-AL-B3-10', 'MK', 'mk.algebra-linear', 4, 'The sum of three consecutive odd integers is 57. What is the largest of the three integers?', '["17","19","21","23"]'::jsonb, 2, 'Let the integers be n, n+2, n+4. Sum: 3n + 6 = 57 → 3n = 51 → n = 17. Largest = n + 4 = 21.', true),
  ('MK-AL-B3-11', 'MK', 'mk.algebra-linear', 5, 'Solve the system: 3x − y = 11 and x + y = 9. What is x + y?', '["5","7","8","9"]'::jsonb, 3, 'Add the two equations: 4x = 20, so x = 5. From x + y = 9: y = 4. x + y = 9. Verify: 3(5) − 4 = 11 ✓; 5 + 4 = 9 ✓.', true),
  ('MK-AL-B3-12', 'MK', 'mk.algebra-linear', 5, 'A company rents vans at $40/day plus $0.25 per mile. An employee uses a van for 3 days and is charged $195 total. How many miles did she drive?', '["220 miles","260 miles","300 miles","340 miles"]'::jsonb, 2, 'Base cost = 3 × $40 = $120. Mileage charge = $195 − $120 = $75. Miles = $75 ÷ $0.25 = 300 miles. The trap is dividing the total by the per-mile rate without subtracting the daily fee: $195 ÷ $0.25 = 780.', true),
  ('MK-FR-B3-1', 'MK', 'mk.fractions-decimals', 2, 'What is 1/2 + 1/4 + 1/8?', '["6/8","7/8","3/4","5/8"]'::jsonb, 1, 'Convert to eighths: 4/8 + 2/8 + 1/8 = 7/8.', true),
  ('MK-FR-B3-2', 'MK', 'mk.fractions-decimals', 3, 'What is 5/6 − 3/8?', '["11/24","7/24","2/3","1/2"]'::jsonb, 0, 'LCD = 24. 5/6 = 20/24; 3/8 = 9/24. 20/24 − 9/24 = 11/24. The trap is subtracting numerators and denominators directly: (5−3)/(6−8) = 2/(−2), which is wrong.', true),
  ('MK-FR-B3-3', 'MK', 'mk.fractions-decimals', 3, 'What is 1 3/4 × 2 2/3?', '["3 1/2","4 2/3","4 5/12","3 11/12"]'::jsonb, 1, 'Convert to improper fractions: 7/4 × 8/3 = 56/12 = 14/3 = 4 2/3. The trap is multiplying whole numbers and fractional parts separately: (1×2) + (3/4×2/3) = 2 + 1/2 = 2 1/2.', true),
  ('MK-FR-B3-4', 'MK', 'mk.fractions-decimals', 3, 'Divide: (7/8) ÷ (7/4)', '["1/2","2","49/32","1/4"]'::jsonb, 0, 'Dividing by a fraction means multiplying by its reciprocal: (7/8) × (4/7) = 28/56 = 1/2. The trap is multiplying straight across to get 49/32.', true),
  ('MK-FR-B3-5', 'MK', 'mk.fractions-decimals', 4, 'A recipe calls for 2 2/3 cups of oats and 1 3/4 cups of flour. What is the combined total of these two ingredients?', '["4 1/12 cups","4 5/12 cups","4 7/12 cups","5 cups"]'::jsonb, 1, '2 2/3 = 2 8/12; 1 3/4 = 1 9/12. Sum = 3 17/12 = 4 5/12 cups.', true),
  ('MK-FR-B3-6', 'MK', 'mk.fractions-decimals', 4, 'Convert 3/16 to a decimal.', '["0.1875","0.1975","0.3125","0.1667"]'::jsonb, 0, '3 ÷ 16 = 0.1875. A common trap is misreading 16 as 6 and computing 3 ÷ 6 = 0.5.', true),
  ('MK-FR-B3-7', 'MK', 'mk.fractions-decimals', 4, 'Which of the following represents the greatest value?', '["0.6̄  (= 0.6666…)","5/7","7/11","0.63"]'::jsonb, 1, 'As decimals: 0.666…; 5/7 ≈ 0.7143; 7/11 ≈ 0.6364; 0.63. Largest is 5/7 ≈ 0.7143. The trap is selecting 0.666… because it visually resembles a large value.', true),
  ('MK-FR-B3-8', 'MK', 'mk.fractions-decimals', 5, 'A plank 7 1/2 feet long is cut into pieces each 5/8 foot long. How many complete pieces can be cut?', '["10","11","12","13"]'::jsonb, 2, '7 1/2 = 15/2 feet. Pieces = (15/2) ÷ (5/8) = (15/2) × (8/5) = 120/10 = 12 complete pieces.', true),
  ('MK-FR-B3-9', 'MK', 'mk.fractions-decimals', 4, 'A runner completed 3/5 of a 15-mile race before stopping. After resting, she runs 2/3 of the remaining distance. How many miles does she still have left to run?', '["1 mile","2 miles","3 miles","4 miles"]'::jsonb, 1, 'Completed first = 3/5 × 15 = 9 miles. Remaining = 6 miles. Second run = 2/3 × 6 = 4 miles. Still remaining = 6 − 4 = 2 miles.', true),
  ('MK-FR-B3-10', 'MK', 'mk.fractions-decimals', 5, 'If 2/3 of a number equals 1/2 of another number, and the first number is 24, what is the second number?', '["16","28","32","36"]'::jsonb, 2, '2/3 × 24 = 16. So 1/2 × N = 16, which gives N = 32. The trap is stopping at 16 (the equal value) rather than solving for N.', true),
  ('MK-FR-B3-11', 'MK', 'mk.fractions-decimals', 4, 'Which of the following is equal to 0.41̄6̄ (= 0.41666…)?', '["5/12","5/11","4/9","3/7"]'::jsonb, 0, '5/12 = 0.41666… (the 6 repeats). 5/11 = 0.4545…; 4/9 = 0.444…; 3/7 = 0.4285…. Only 5/12 matches the given decimal.', true),
  ('MK-FR-B3-12', 'MK', 'mk.fractions-decimals', 5, 'A worker earns $22.50 per hour and works 37.5 hours in one week. Her employer withholds 28% of gross pay for taxes and deductions. What is her net pay for the week?', '["$607.50","$618.00","$632.25","$843.75"]'::jsonb, 0, 'Gross pay = $22.50 × 37.5 = $843.75. Withholding = 28% × $843.75 = $236.25. Net pay = $843.75 − $236.25 = $607.50. The trap is selecting $843.75 (gross) or computing withholding on $22.50 alone.', true),
  ('MK-EP-B3-1', 'MK', 'mk.exponents-polynomials', 3, 'What is 3² + 2³?', '["10","13","17","19"]'::jsonb, 2, '3² = 9; 2³ = 8. Sum = 17. The trap is computing 3² as 3 × 2 = 6, giving 6 + 8 = 14.', true),
  ('MK-EP-B3-2', 'MK', 'mk.exponents-polynomials', 3, 'Simplify: 5⁴ ÷ 5²', '["5¹","5²","5⁶","25²"]'::jsonb, 1, 'Dividing same-base powers: subtract exponents. 5⁴ ÷ 5² = 5^(4−2) = 5² = 25. The trap is multiplying the exponents (power of a power rule misapplied): 5^(4×2) = 5⁸.', true),
  ('MK-EP-B3-3', 'MK', 'mk.exponents-polynomials', 3, 'What is the value of 2⁰ + 3¹ + 4²?', '["16","18","20","22"]'::jsonb, 2, '2⁰ = 1; 3¹ = 3; 4² = 16. Sum = 20. The trap is treating 2⁰ = 0, giving 0 + 3 + 16 = 19.', true),
  ('MK-EP-B3-4', 'MK', 'mk.exponents-polynomials', 3, 'What is 10⁻²?', '["−100","−20","0.001","0.01"]'::jsonb, 3, 'A negative exponent means take the reciprocal: 10⁻² = 1/10² = 1/100 = 0.01. The trap is writing the negative exponent as a negative number: −100.', true),
  ('MK-EP-B3-5', 'MK', 'mk.exponents-polynomials', 4, 'Expand and simplify: (2x − 3)²', '["4x² − 9","4x² − 12x + 9","4x² + 12x + 9","4x² − 6x + 9"]'::jsonb, 1, '(2x − 3)² = (2x)² − 2(2x)(3) + 3² = 4x² − 12x + 9. The most common trap is squaring each term individually: (2x)² + (−3)² = 4x² + 9, forgetting the middle term.', true),
  ('MK-EP-B3-6', 'MK', 'mk.exponents-polynomials', 4, 'Simplify: (3a²b)(4ab³)', '["7a²b³","12a²b³","12a³b⁴","7a³b⁴"]'::jsonb, 2, 'Multiply coefficients: 3 × 4 = 12. Add a-exponents: 2 + 1 = 3. Add b-exponents: 1 + 3 = 4. Result: 12a³b⁴. The trap is adding coefficients instead of multiplying: 3 + 4 = 7.', true),
  ('MK-EP-B3-7', 'MK', 'mk.exponents-polynomials', 4, 'Add the polynomials: (3x² − 2x + 5) + (x² + 4x − 3)', '["4x² + 2x + 2","4x² + 2x − 2","4x² − 2x + 2","3x² + 2x + 2"]'::jsonb, 0, 'Combine like terms: (3x²+x²) + (−2x+4x) + (5−3) = 4x² + 2x + 2.', true),
  ('MK-EP-B3-8', 'MK', 'mk.exponents-polynomials', 4, 'Factor completely: 2x² − 8', '["2(x − 2)(x − 2)","2(x + 2)(x − 2)","(2x + 4)(x − 2)","(x + 2)(2x − 4)"]'::jsonb, 1, 'Factor out 2: 2(x² − 4). Then apply difference of squares: 2(x + 2)(x − 2). The trap choices (2x+4)(x−2) and (x+2)(2x−4) are equivalent but not fully factored.', true),
  ('MK-EP-B3-9', 'MK', 'mk.exponents-polynomials', 5, 'Simplify: (x³y²)² ÷ (x²y)', '["x²y","x⁴y³","x⁴y²","x²y³"]'::jsonb, 1, 'Numerator: (x³y²)² = x⁶y⁴. Divide: x^(6−2) × y^(4−1) = x⁴y³.', true),
  ('MK-EP-B3-10', 'MK', 'mk.exponents-polynomials', 5, 'Expand: (x + 3)(x² − 3x + 9)', '["x³ − 27","x³ + 27","x³ − 9x + 27","x³ + 9x² − 27"]'::jsonb, 1, 'This is the sum-of-cubes pattern: (a + b)(a² − ab + b²) = a³ + b³, with a = x, b = 3. Result = x³ + 27. Verify by expansion: x³ − 3x² + 9x + 3x² − 9x + 27 = x³ + 27.', true),
  ('MK-EP-B3-11', 'MK', 'mk.exponents-polynomials', 4, 'Subtract and simplify: (5x² + 3x − 2) − (2x² − x + 4)', '["3x² + 4x − 6","3x² + 4x + 2","3x² + 2x − 6","7x² + 2x − 6"]'::jsonb, 0, 'Distribute the negative sign: 5x² + 3x − 2 − 2x² + x − 4 = 3x² + 4x − 6. The trap is forgetting to distribute the negative to all terms: treating −(−x) as −x instead of +x.', true),
  ('MK-EP-B3-12', 'MK', 'mk.exponents-polynomials', 5, 'If x² − 5x + 6 = 0, what are the solutions?', '["x = 1 and x = 6","x = 2 and x = 3","x = −2 and x = −3","x = −1 and x = 6"]'::jsonb, 1, 'Factor: (x − 2)(x − 3) = 0. Solutions: x = 2 and x = 3. Verify: 4 − 10 + 6 = 0 ✓; 9 − 15 + 6 = 0 ✓. The trap is choosing negative values (x = −2 and −3) by confusing factoring sign rules.', true),
  ('MK-GE-B3-1', 'MK', 'mk.geometry', 2, 'What is the area of a triangle with base 10 cm and height 6 cm?', '["30 cm²","40 cm²","60 cm²","120 cm²"]'::jsonb, 0, 'Area = (1/2) × base × height = (1/2) × 10 × 6 = 30 cm². The trap is omitting the 1/2 factor, giving 60 cm².', true),
  ('MK-GE-B3-3', 'MK', 'mk.geometry', 3, 'A square has a side length of 13 cm. What is its perimeter?', '["36 cm","48 cm","52 cm","64 cm"]'::jsonb, 2, 'Perimeter = 4 × 13 = 52 cm. The trap is computing the area: 13² = 169.', true),
  ('MK-GE-B3-4', 'MK', 'mk.geometry', 4, 'A circular park has a circumference of 62.8 meters. What is its area in square meters? (Use π ≈ 3.14)', '["157 m²","200 m²","314 m²","628 m²"]'::jsonb, 2, 'C = 2πr = 62.8 → r = 62.8 ÷ 6.28 = 10 m. Area = πr² = 3.14 × 100 = 314 m². The trap is using the circumference directly as the area (628/2 = 314 coincidentally matches but using r = C/π = 20 instead of r = C/(2π) = 10 gives 4× the correct area).', true),
  ('MK-GE-B3-5', 'MK', 'mk.geometry', 4, 'A rectangular swimming pool is 25 m long, 12 m wide, and 2 m deep. What is the volume of water needed to fill it completely?', '["300 m³","450 m³","600 m³","750 m³"]'::jsonb, 2, 'Volume = 25 × 12 × 2 = 600 m³. The trap is computing the surface area and selecting a number based on that calculation.', true),
  ('MK-GE-B3-6', 'MK', 'mk.geometry', 4, 'A trapezoid has parallel sides of 10 cm and 14 cm, and a height of 8 cm. What is its area?', '["88 cm²","92 cm²","96 cm²","100 cm²"]'::jsonb, 2, 'Area = (1/2)(b₁ + b₂)(h) = (1/2)(10 + 14)(8) = (1/2)(24)(8) = 96 cm². The trap is omitting the 1/2: (10 + 14) × 8 = 192.', true),
  ('MK-GE-B3-7', 'MK', 'mk.geometry', 5, 'A right triangle has a hypotenuse of 17 cm and one leg of 8 cm. What is the area of the triangle?', '["45 cm²","60 cm²","68 cm²","75 cm²"]'::jsonb, 1, 'Missing leg = √(17² − 8²) = √(289 − 64) = √225 = 15 cm. Area = (1/2) × 8 × 15 = 60 cm². This uses the 8-15-17 Pythagorean triple.', true),
  ('MK-GE-B3-8', 'MK', 'mk.geometry', 5, 'Two similar triangles have corresponding sides in a ratio of 3:5. The area of the smaller triangle is 27 cm². What is the area of the larger triangle?', '["45 cm²","60 cm²","75 cm²","135 cm²"]'::jsonb, 2, 'Areas scale as the square of the linear ratio. Scale factor² = (5/3)² = 25/9. Larger area = 27 × 25/9 = 75 cm². The trap is applying the linear ratio: 27 × (5/3) = 45 cm².', true),
  ('MK-GE-B3-9', 'MK', 'mk.geometry', 4, 'A cone has a radius of 6 cm and a slant height of 10 cm. What is the total surface area of the cone? (Use π ≈ 3.14)', '["263.76 cm²","301.44 cm²","376.8 cm²","414.48 cm²"]'::jsonb, 1, 'Lateral area = πrl = 3.14 × 6 × 10 = 188.4 cm². Base area = πr² = 3.14 × 36 = 113.04 cm². Total = 188.4 + 113.04 = 301.44 cm². The trap is computing only the lateral area (188.4) or using the slant height as the height in a volume formula.', true),
  ('MK-GE-B3-10', 'MK', 'mk.geometry', 4, 'A rectangular garden 20 m long and 15 m wide is surrounded by a 2 m wide path. What is the area of the path alone?', '["148 m²","152 m²","156 m²","164 m²"]'::jsonb, 2, 'Outer rectangle: (20 + 4) × (15 + 4) = 24 × 19 = 456 m². Garden area = 20 × 15 = 300 m². Path area = 456 − 300 = 156 m². The trap is adding 2 (not 4) to each dimension, giving 22 × 17 = 374; 374 − 300 = 74.', true),
  ('MK-GE-B3-11', 'MK', 'mk.geometry', 5, 'A sphere has a radius of 6 cm. What is its volume to the nearest whole number? (Use π ≈ 3.14)', '["452 cm³","678 cm³","754 cm³","904 cm³"]'::jsonb, 3, 'Volume = (4/3)πr³ = (4/3) × 3.14 × 216 = 4.186… × 216 ≈ 904 cm³. The trap is using the surface area formula 4πr² = 4 × 3.14 × 36 ≈ 452 cm² instead.', true),
  ('MK-GE-B3-12', 'MK', 'mk.geometry', 3, 'A rectangular room is 14 feet long and 10 feet wide. What is its area?', '["120 sq ft","130 sq ft","140 sq ft","150 sq ft"]'::jsonb, 2, 'Area = 14 × 10 = 140 sq ft. The trap is computing the perimeter: 2(14 + 10) = 48 ft.', true),
  ('MK-NP-B3-1', 'MK', 'mk.number-properties', 2, 'Which of the following is NOT a factor of 60?', '["8","12","15","20"]'::jsonb, 0, '60 ÷ 8 = 7.5 — not a whole number, so 8 is not a factor. 60 ÷ 12 = 5; 60 ÷ 15 = 4; 60 ÷ 20 = 3 — all are factors.', true),
  ('MK-NP-B3-2', 'MK', 'mk.number-properties', 3, 'What is the LCM (least common multiple) of 8 and 12?', '["16","20","24","32"]'::jsonb, 2, 'Multiples of 8: 8, 16, 24…; multiples of 12: 12, 24… LCM = 24. The trap is multiplying 8 × 12 = 96, or confusing LCM with GCF (GCF = 4).', true),
  ('MK-NP-B3-3', 'MK', 'mk.number-properties', 3, 'What is the GCF (greatest common factor) of 54 and 72?', '["6","9","12","18"]'::jsonb, 3, '54 = 2 × 3³; 72 = 2³ × 3². GCF = 2¹ × 3² = 18. The trap is selecting 9 (taking only 3²) or 6 (taking 2 × 3).', true),
  ('MK-NP-B3-4', 'MK', 'mk.number-properties', 3, 'Which of the following numbers is divisible by both 3 and 4?', '["34","42","48","50"]'::jsonb, 2, '48 ÷ 3 = 16 ✓; 48 ÷ 4 = 12 ✓. The others fail: 34 ÷ 4 = 8.5; 42 ÷ 4 = 10.5; 50 ÷ 3 ≈ 16.67.', true),
  ('MK-NP-B3-5', 'MK', 'mk.number-properties', 4, 'What is the absolute value expression |−14| − |6 − 19|?', '["−1","0","1","27"]'::jsonb, 2, '|−14| = 14. |6 − 19| = |−13| = 13. 14 − 13 = 1. The trap is adding instead of subtracting: 14 + 13 = 27.', true),
  ('MK-NP-B3-6', 'MK', 'mk.number-properties', 4, 'How many prime numbers are between 20 and 40?', '["3","4","5","6"]'::jsonb, 1, 'Primes between 20 and 40: 23, 29, 31, 37. That is 4 primes. Students often include 21 (= 3×7), 27 (= 3×9), or 39 (= 3×13) by failing divisibility checks.', true),
  ('MK-NP-B3-7', 'MK', 'mk.number-properties', 4, 'A number N is divisible by 4, by 9, and by 5. What is the smallest positive value of N?', '["60","90","120","180"]'::jsonb, 3, 'LCM(4, 9, 5): 4 = 2², 9 = 3², 5 = 5. LCM = 2² × 3² × 5 = 180. The trap is choosing 60 (LCM of 4 and 5 only) or 90 (LCM of 9 and 5 only, which is not divisible by 4).', true),
  ('MK-NP-B3-8', 'MK', 'mk.number-properties', 4, 'When a positive integer n is divided by 7, the remainder is 4. What is the remainder when 3n is divided by 7?', '["1","2","3","5"]'::jsonb, 3, 'n = 7k + 4 for some integer k. Then 3n = 21k + 12 = 7(3k + 1) + 5. The remainder is 5. The shortcut: (3 × 4) mod 7 = 12 mod 7 = 5.', true),
  ('MK-NP-B3-9', 'MK', 'mk.number-properties', 5, 'The product of two integers is −36 and their sum is −5. What are the two integers?', '["4 and −9","−4 and 9","3 and −12","6 and −6"]'::jsonb, 0, '4 × (−9) = −36 ✓; 4 + (−9) = −5 ✓. The trap answer −4 and 9 has the same product but sum = +5, not −5.', true),
  ('MK-NP-B3-10', 'MK', 'mk.number-properties', 4, 'If n is an even integer, which of the following expressions must also be even?', '["n² + 1","n² − n + 1","n² + n","n³ + 1"]'::jsonb, 2, 'n even → n = 2k. n² + n = n(n + 1) = 2k(2k+1), which is always even. Check others: n² + 1 = even + 1 = odd; n² − n + 1 = even − even + 1 = odd; n³ + 1 = even + 1 = odd.', true),
  ('MK-NP-B3-11', 'MK', 'mk.number-properties', 5, 'A set of 5 integers has a mean of 8 and a range of 10. The smallest integer is 3. Which of the following could be the set?', '["{3, 6, 8, 11, 13}","{3, 7, 8, 9, 13}","{3, 8, 9, 10, 13}","{3, 5, 8, 10, 13}"]'::jsonb, 1, 'Range = max − min = 10; min = 3, so max = 13. Mean = 8 with 5 integers → sum = 40. Check B: 3+7+8+9+13 = 40 ✓, range = 10 ✓. A: 3+6+8+11+13 = 41 ✗. C: 3+8+9+10+13 = 43 ✗. D: 3+5+8+10+13 = 39 ✗.', true),
  ('MK-NP-B3-12', 'MK', 'mk.number-properties', 4, 'Which statement is true about (−3)⁴?', '["It equals −81","It equals 81","It equals −12","It is undefined"]'::jsonb, 1, '(−3)⁴ = (−3)(−3)(−3)(−3) = 9 × 9 = 81. An even exponent applied to any real number produces a non-negative result. The trap is confusing (−3)⁴ with −(3⁴) = −81.', true),
  ('WK-SN-B4-1', 'WK', 'wk.synonyms', 1, 'BRAVE most nearly means:', '["cowardly","courageous","careless","clever"]'::jsonb, 1, 'Brave means ready to face danger or pain without showing fear. Courageous is its closest synonym. Cowardly is the antonym.', true),
  ('WK-SN-B4-2', 'WK', 'wk.synonyms', 1, 'RAPID most nearly means:', '["slow","loud","fast","heavy"]'::jsonb, 2, 'Rapid means happening in a short time or at great speed. Fast is its direct synonym. Slow is the antonym.', true),
  ('WK-SN-B4-4', 'WK', 'wk.synonyms', 2, 'GREGARIOUS most nearly means:', '["shy","talkative and sociable","aggressive","hardworking"]'::jsonb, 1, 'Gregarious means fond of company; sociable. It describes someone who enjoys being around other people. Shy is the antonym.', true),
  ('WK-SN-B4-5', 'WK', 'wk.synonyms', 2, 'INDOLENT most nearly means:', '["energetic","rude","lazy","independent"]'::jsonb, 2, 'Indolent means avoiding activity; habitually lazy. Energetic is its antonym. Do not confuse indolent with insolent (rude), which differs by one letter.', true),
  ('WK-SN-B4-6', 'WK', 'wk.synonyms', 3, 'LACONIC most nearly means:', '["wordy","brief in speech","humorous","secretive"]'::jsonb, 1, 'Laconic means using very few words; brief and to the point. Wordy is the antonym. It comes from Laconia (Sparta), whose inhabitants were famous for terse speech.', true),
  ('WK-SN-B4-7', 'WK', 'wk.synonyms', 3, 'MITIGATE most nearly means:', '["worsen","lessen or reduce","eliminate","conceal"]'::jsonb, 1, 'Mitigate means to make something less severe, harmful, or painful. Worsen is its antonym. Eliminate goes further than mitigate — mitigate reduces, not removes, the harm.', true),
  ('WK-SN-B4-8', 'WK', 'wk.synonyms', 3, 'OSTRACIZE most nearly means:', '["welcome","exclude from a group","punish physically","deceive"]'::jsonb, 1, 'Ostracize means to banish or exclude someone from a group or society. Welcome is its antonym. The trap ''punish physically'' confuses social exclusion with corporal punishment.', true),
  ('WK-SN-B4-9', 'WK', 'wk.synonyms', 4, 'ASSIDUOUS most nearly means:', '["careless","showing careful and persistent effort","sociable","bold"]'::jsonb, 1, 'Assiduous means showing great care, effort, and persistence in doing something. It describes someone who works diligently and attentively. Careless is the antonym.', true),
  ('WK-SN-B4-10', 'WK', 'wk.synonyms', 4, 'PROSAIC most nearly means:', '["poetic","dull and unimaginative","precise","aggressive"]'::jsonb, 1, 'Prosaic means commonplace; lacking originality or imagination. It comes from prose (ordinary writing), as opposed to poetry. Poetic is essentially the antonym.', true),
  ('WK-SN-B4-11', 'WK', 'wk.synonyms', 4, 'VENERATE most nearly means:', '["criticize","regard with deep respect","imitate","investigate"]'::jsonb, 1, 'Venerate means to regard with great respect and reverence, often for age or wisdom. Criticize is its antonym. Do not confuse with generate (to produce) — the spelling is different.', true),
  ('WK-SN-B4-12', 'WK', 'wk.synonyms', 5, 'ERSATZ most nearly means:', '["authentic","an inferior substitute","elaborate","traditional"]'::jsonb, 1, 'Ersatz means made or used as a substitute, typically an inferior one. From German, it was applied to wartime replacements for scarce goods. Authentic is the antonym.', true),
  ('WK-SN-B4-13', 'WK', 'wk.synonyms', 5, 'FATUOUS most nearly means:', '["insightful","complacently stupid","cautious","withdrawn"]'::jsonb, 1, 'Fatuous means self-satisfied and pointlessly foolish; smugly stupid. Insightful is the antonym. Do not confuse fatuous with fatigued (tired) — they are unrelated.', true),
  ('WK-CTX-B4-1', 'WK', 'wk.context-clues', 1, 'In the sentence ''The child was ELATED when she learned she had won the spelling bee,'' the word ELATED most nearly means:', '["frightened","very happy","surprised","tired"]'::jsonb, 1, 'Elated means filled with joy and pride. Winning a competition clearly produces happiness, not fear. Surprised is tempting but does not capture the celebratory context.', true),
  ('WK-CTX-B4-2', 'WK', 'wk.context-clues', 1, 'In the sentence ''The sun was SCORCHING, so we moved into the shade to cool down,'' the word SCORCHING most nearly means:', '["mild","extremely hot","cloudy","distant"]'::jsonb, 1, 'Scorching means burning hot. The action of moving into shade to cool down is the direct clue that the heat was extreme, not mild or cloudy.', true),
  ('WK-CTX-B4-3', 'WK', 'wk.context-clues', 2, 'In the sentence ''She spoke with such CANDOR that even her critics respected her honesty,'' the word CANDOR most nearly means:', '["arrogance","frankness","caution","authority"]'::jsonb, 1, 'Candor means the quality of being open and honest. ''Respected her honesty'' is the direct context clue. Arrogance and authority might earn respect in other contexts, but the passage ties the respect explicitly to honesty.', true),
  ('WK-CTX-B4-4', 'WK', 'wk.context-clues', 2, 'In the sentence ''The DILATORY contractor missed three deadlines, forcing the base commander to find a new vendor,'' the word DILATORY most nearly means:', '["expensive","slow to act or chronically late","dishonest","inexperienced"]'::jsonb, 1, 'Dilatory means slow to act; tending to delay. Three missed deadlines is the direct clue for chronic lateness, not dishonesty or expense. Inexperienced might cause delays but is a different concept.', true),
  ('WK-CTX-B4-6', 'WK', 'wk.context-clues', 3, 'In the sentence ''The recruit FLOUTED every regulation he disagreed with, earning himself extra duty each week,'' the word FLOUTED most nearly means:', '["followed carefully","openly disregarded","misunderstood","reported"]'::jsonb, 1, 'Flout means to openly disregard a rule or convention. The penalty of extra duty each week confirms deliberate rule-breaking, not misunderstanding. Do not confuse flout with flaunt (to display ostentatiously).', true),
  ('WK-CTX-B4-7', 'WK', 'wk.context-clues', 3, 'In the sentence ''The speaker''s TRENCHANT analysis cut through the confusion and identified the problem within minutes,'' the word TRENCHANT most nearly means:', '["lengthy and detailed","incisive and vigorous","calm and measured","unexpected"]'::jsonb, 1, 'Trenchant means vigorous and incisive in expression or style; cutting right to the point. ''Cut through the confusion'' is the key metaphor in the passage, directly supporting the meaning of sharp and effective analysis.', true),
  ('WK-CTX-B4-8', 'WK', 'wk.context-clues', 4, 'In the sentence ''Her SAGACIOUS decision to stockpile medical supplies before the hurricane proved correct when the storm knocked out supply lines for two weeks,'' the word SAGACIOUS most nearly means:', '["lucky and fortunate","having keen practical wisdom","reckless and impulsive","conservative and reluctant"]'::jsonb, 1, 'Sagacious means having good judgment and foresight. The passage distinguishes this from luck by showing the decision was made before the storm — implying deliberate wisdom, not chance. Reckless is the opposite.', true),
  ('WK-CTX-B4-9', 'WK', 'wk.context-clues', 4, 'In the sentence ''The sergeant REPUDIATED the accusations against his unit, producing records that showed the team had followed every protocol,'' the word REPUDIATED most nearly means:', '["quietly accepted","firmly rejected","investigated","summarized"]'::jsonb, 1, 'Repudiate means to refuse to accept or deny the truth of something. Producing records to disprove accusations is an act of firm rejection, not quiet acceptance. Investigated implies looking into, not countering, the claims.', true),
  ('WK-CTX-B4-10', 'WK', 'wk.context-clues', 4, 'In the sentence ''Despite owning a popular restaurant, the chef lived FRUGALLY, driving an old car and rarely buying new clothes,'' the word FRUGALLY most nearly means:', '["lavishly","in a thrifty manner","with great caution","in an isolated way"]'::jsonb, 1, 'Frugally means carefully spending as little money as possible. The examples — old car, few new clothes — confirm thrifty behavior. Lavishly is the antonym. ''With great caution'' might describe driving, not lifestyle.', true),
  ('WK-CTX-B4-11', 'WK', 'wk.context-clues', 5, 'In the sentence ''The diplomat''s LACONIC cable — three words where others would have written three pages — conveyed the mission''s outcome without ambiguity,'' the word LACONIC most nearly means:', '["cryptically coded","using very few words","overly detailed","formally worded"]'::jsonb, 1, 'Laconic means using very few words. ''Three words where others would have written three pages'' is the direct numerical contrast establishing extreme brevity. Coded implies obscurity; laconic implies clarity through brevity.', true),
  ('WK-CTX-B4-12', 'WK', 'wk.context-clues', 5, 'In the sentence ''The documentary portrayed the era with UNFLINCHING candor, showing the poverty and discrimination that official histories had glossed over for decades,'' the word UNFLINCHING most nearly means:', '["sympathetic","refusing to shy away from difficult truths","politically motivated","technically accurate"]'::jsonb, 1, 'Unflinching means not showing fear or hesitation in the face of something difficult or distressing. ''Official histories had glossed over'' contrasts with the documentary''s refusal to avoid uncomfortable realities. Sympathetic describes feeling, not the courage to depict truth.', true),
  ('WK-PFX-B4-1', 'WK', 'wk.prefixes-suffixes', 1, 'The prefix UN- means not. Based on this, UNHAPPY most nearly means:', '["very happy","not happy","somewhat happy","formerly happy"]'::jsonb, 1, 'UN- is a negating prefix, so unhappy means not happy. This prefix works the same way in unfair, unclear, and unkind. ''Formerly happy'' would require the prefix EX-.', true),
  ('WK-PFX-B4-2', 'WK', 'wk.prefixes-suffixes', 1, 'The suffix -FUL means full of or having. Based on this, CAREFUL most nearly means:', '["without care","full of care and attention","able to be cared for","beyond care"]'::jsonb, 1, '-FUL adds the meaning ''full of'' or ''characterized by.'' Careful means full of care; similarly, hopeful means full of hope and peaceful means full of peace.', true),
  ('WK-PFX-B4-3', 'WK', 'wk.prefixes-suffixes', 2, 'The prefix PRE- means before. Based on this, PRECAUTION most nearly means:', '["an action taken after the fact","an action taken in advance to prevent harm","a warning given loudly","a rule set by authorities"]'::jsonb, 1, 'PRE- means before; a precaution is an action taken beforehand to avoid danger. Compare: preview (see before), prevent (come before to stop), predict (say before). ''After the fact'' would be POST-.', true),
  ('WK-PFX-B4-4', 'WK', 'wk.prefixes-suffixes', 2, 'The suffix -LESS means without. Based on this, RECKLESS most nearly means:', '["very careful","without caution","full of energy","beyond control"]'::jsonb, 1, '-LESS means without, so reckless means without reck (thought or care). Similarly, careless means without care, and helpless means without help. ''Full of energy'' misreads the suffix as -FUL.', true),
  ('WK-PFX-B4-5', 'WK', 'wk.prefixes-suffixes', 3, 'The prefix MIS- means wrongly or badly. The word MISCONSTRUE therefore most nearly means:', '["to build incorrectly","to interpret wrongly","to communicate clearly","to confuse deliberately"]'::jsonb, 1, 'CONSTRUE means to interpret; MIS- means wrongly. Misconstrue means to interpret something incorrectly. ''Deliberately confuse'' implies intent to deceive; misconstrue means the interpretation itself is simply wrong, not necessarily deceptive.', true),
  ('WK-PFX-B4-6', 'WK', 'wk.prefixes-suffixes', 3, 'The prefix INTER- means between or among. Based on this, INTERLUDE most nearly means:', '["a final performance","a period between two events","an opening ceremony","a conflict between parties"]'::jsonb, 1, 'INTER- means between; -LUDE comes from Latin ludere (to play). An interlude is a pause or event occurring between two others. Compare: international (between nations), intermission (pause between acts). A conflict would use INTER- differently (interchange/interfere).', true),
  ('WK-PFX-B4-7', 'WK', 'wk.prefixes-suffixes', 3, 'The suffix -MENT turns a verb into a noun indicating result or process. DEPLOYMENT therefore most nearly means:', '["the ability to deploy","the act or result of deploying","one who deploys","worthy of being deployed"]'::jsonb, 1, '-MENT creates nouns from verbs: deploy → deployment (act of deploying), manage → management (process of managing). -ER/-OR would indicate a person; -ABLE indicates capability.', true),
  ('WK-PFX-B4-8', 'WK', 'wk.prefixes-suffixes', 4, 'The prefix COUNTER- means against or in opposition to. Based on this, COUNTERINTUITIVE most nearly means:', '["supporting common sense","going against what one would naturally expect","requiring careful thought","relating to military counter-operations"]'::jsonb, 1, 'COUNTER- means against; intuitive means based on instinct or natural feeling. Counterintuitive means contrary to what your instincts or common sense would suggest. ''Requiring careful thought'' describes complexity, not opposition to expectation.', true),
  ('WK-PFX-B4-10', 'WK', 'wk.prefixes-suffixes', 4, 'The prefix SUB- means under or below. SUBVERT most nearly means:', '["to support from beneath","to secretly undermine or overthrow","to move below ground level","to speak quietly"]'::jsonb, 1, 'SUB- means under; VERT comes from Latin vertere (to turn). Subvert means to turn under — i.e., to undermine or overturn an established system from within. ''Support from beneath'' misreads sub- as physically supporting rather than undermining.', true),
  ('WK-PFX-B4-11', 'WK', 'wk.prefixes-suffixes', 5, 'The prefix EPI- means upon or in addition to. EPILOGUE most nearly means:', '["an introduction written before the main text","a section added at the end of a literary work","a chapter inserted in the middle","an index of key terms"]'::jsonb, 1, 'EPI- means upon or after; -LOGUE means speech or writing. An epilogue is a section added after the main work. PRO-logue is the introduction; EPI- places the content after, not before. An index is a reference tool, not a narrative addition.', true),
  ('WK-PFX-B4-12', 'WK', 'wk.prefixes-suffixes', 5, 'The suffix -CIDE means the act of killing. Based on this, HERBICIDE is best defined as:', '["a plant-based medicine","a substance that kills plants","a device for cutting vegetation","a chemical that promotes plant growth"]'::jsonb, 1, 'HERB means plant; -CIDE means act of killing. Herbicide is a substance used to kill plants (usually unwanted ones). Promoting growth would be the opposite. A cutting device would be a tool, not a chemical. The -CIDE suffix also appears in insecticide (kills insects) and germicide (kills germs).', true),
  ('WK-ROOT-B4-1', 'WK', 'wk.root-words', 1, 'The root VIS appears in VISIBLE, VISION, and VISUAL. VIS most nearly means:', '["to move","to see","to speak","to know"]'::jsonb, 1, 'VIS comes from the Latin videre, to see. Visible means capable of being seen; vision is the ability to see; visual relates to sight. Compare with AUDI- (to hear).', true),
  ('WK-ROOT-B4-2', 'WK', 'wk.root-words', 1, 'The root PORT appears in TRANSPORT, PORTABLE, and EXPORT. PORT most nearly means:', '["to make","to carry","to open","to place"]'::jsonb, 1, 'PORT comes from Latin portare, to carry. Portable means able to be carried; transport means to carry across; export means to carry out. Do not confuse with port (harbor) — the root is about carrying, not water.', true),
  ('WK-ROOT-B4-3', 'WK', 'wk.root-words', 2, 'The root CRED appears in CREDIBLE, CREDIT, and INCREDULOUS. CRED most nearly means:', '["to judge","to believe","to know","to value"]'::jsonb, 1, 'CRED comes from the Latin credere, to believe. Credible means believable; credit means trust placed in someone; incredulous means unwilling to believe. The credo (creed) is a statement of beliefs.', true),
  ('WK-ROOT-B4-4', 'WK', 'wk.root-words', 2, 'The root DICT appears in DICTATE, PREDICT, and CONTRADICT. DICT most nearly means:', '["to write","to say or speak","to lead","to order by force"]'::jsonb, 1, 'DICT comes from Latin dicere, to say. Dictate means to say aloud for someone to write; predict means to say beforehand; contradict means to say the opposite. To write is SCRIB/SCRIPT; to lead is DUC.', true),
  ('WK-ROOT-B4-5', 'WK', 'wk.root-words', 3, 'The root BENE appears in BENEFIT, BENEFACTOR, and BENEVOLENT. BENE most nearly means:', '["great","good or well","many","before"]'::jsonb, 1, 'BENE comes from Latin meaning good or well. A benefactor is one who does good for others; benefit is a good outcome; benevolent means well-wishing. PRE- means before; MULTI- means many; MAGN- means great.', true),
  ('WK-ROOT-B4-6', 'WK', 'wk.root-words', 3, 'The root GREG appears in GREGARIOUS, CONGREGATE, and SEGREGATE. GREG most nearly means:', '["to speak","a flock or group","a leader","a law"]'::jsonb, 1, 'GREG comes from Latin grex/gregis, meaning flock or herd. Gregarious means fond of the group (sociable); congregate means to gather as a group; segregate means to separate from the group. A leader would be DUX; a law would be LEX.', true),
  ('WK-ROOT-B4-7', 'WK', 'wk.root-words', 3, 'The root PATH appears in EMPATHY, SYMPATHY, and PATHETIC. PATH most nearly means:', '["thought or reason","suffering or feeling","motion or movement","disease only"]'::jsonb, 1, 'PATH comes from Greek pathos, meaning suffering or feeling. Empathy is feeling into another''s experience; sympathy is feeling alongside someone; pathetic originally meant arousing pity. Disease is a modern narrowing of the medical use (pathology), but the root broadly means feeling.', true),
  ('WK-ROOT-B4-8', 'WK', 'wk.root-words', 4, 'The root TRACT appears in EXTRACT, CONTRACT, and RETRACT. TRACT most nearly means:', '["to push","to pull or draw","to hold","to cut"]'::jsonb, 1, 'TRACT comes from Latin trahere, to pull or drag. Extract means to pull out; retract means to pull back; contract literally means to pull together (draw closer). Traction is the grip that allows pulling or movement.', true),
  ('WK-ROOT-B4-9', 'WK', 'wk.root-words', 4, 'The root PEND appears in PENDING, SUSPEND, and APPENDIX. PEND most nearly means:', '["to send","to hang or be uncertain","to write","to add weight"]'::jsonb, 1, 'PEND comes from Latin pendere, to hang. Pending means hanging (unresolved); suspend means to hang up or halt; appendix hangs from the main body of text. ''Add weight'' is a trap — although appended items extend a document, the root captures the hanging quality.', true),
  ('WK-ROOT-B4-10', 'WK', 'wk.root-words', 4, 'The root VOC appears in INVOKE, VOCALIZE, and IRREVOCABLE. VOCA/VOC most nearly means:', '["to see","to feel","to call or voice","to rule"]'::jsonb, 2, 'VOC comes from Latin vocare, to call. Invoke means to call upon; vocalize means to give voice to; irrevocable means unable to be called back (reversed). VIS means to see; SENT/SENS means to feel; REG/RECT means to rule.', true),
  ('WK-ROOT-B4-11', 'WK', 'wk.root-words', 5, 'The root CIDE appears in INCISION, DECIDE, and PRECISE. The root CIDE/CIS most nearly means:', '["to fall","to cut","to go","to bind"]'::jsonb, 1, 'CIS/CIDE comes from Latin caedere, to cut. Incision is a cut; decide means to cut off (other options); precise means cut off exactly. Do not confuse with -CIDE (killer) which derives from caedere in a different sense. To fall is CAD/CAS; to go is it; to bind is LIG.', true),
  ('WK-ROOT-B4-12', 'WK', 'wk.root-words', 5, 'The root PLAC appears in PLACATE, COMPLACENT, and IMPLACABLE. PLAC most nearly means:', '["to please or calm","to place or position","to promise","to fill"]'::jsonb, 0, 'PLAC comes from Latin placare, to please or appease. Placate means to calm or appease; complacent means self-satisfied (pleased with oneself to excess); implacable means impossible to appease. ''Place'' (Latin: ponere/positum) is a different root despite the visual similarity.', true),
  ('PC-MI-B4-1', 'PC', 'pc.main-idea', 1, 'Read the passage below and answer the question.

"Drinking enough water each day is important for good health. Water helps regulate body temperature, carries nutrients to cells, and removes waste from the body. Most adults should drink at least eight glasses of water per day."

What is the main idea of this passage?', '["Adults should drink exactly eight glasses of water each day.","Water is essential for good health and serves several vital functions in the body.","Water removes waste products from the body.","Most people do not drink enough water."]'::jsonb, 1, 'The passage covers water''s importance and multiple functions. Choice A is too narrow (focuses only on quantity). Choice C is a detail. Choice D is an inference not stated in the passage.', true),
  ('PC-MI-B4-2', 'PC', 'pc.main-idea', 1, 'Read the passage below and answer the question.

"Dogs are often called ''man''s best friend.'' They have lived alongside humans for thousands of years, serving as companions, guards, and working animals. Today, dogs are still used to assist the blind, support law enforcement, and provide emotional comfort."

What is the main idea of this passage?', '["Dogs have been human companions and helpers for thousands of years and remain useful today.","Dogs can be trained to assist the blind.","The history of dogs began thousands of years ago.","Dogs are the most popular pets in the world."]'::jsonb, 0, 'The passage covers both historical and modern uses of dogs, making the broad partnership theme the main idea. Choices B and C are supporting details. Choice D is not stated in the passage.', true),
  ('PC-MI-B4-3', 'PC', 'pc.main-idea', 2, 'Read the passage below and answer the question.

"Sleep is not simply a period of rest. During sleep, the brain consolidates memories, the immune system strengthens, and tissues repair themselves. Chronic sleep deprivation has been linked to heart disease, obesity, and impaired decision-making. A full night of sleep is as important to performance as nutrition and exercise."

What is the main idea of this passage?', '["Sleep deprivation causes obesity and heart disease.","The brain processes memories only during sleep.","Sleep is a critical, active process that supports physical and mental performance.","Adults who sleep eight hours make better decisions."]'::jsonb, 2, 'The passage makes a case for sleep as an active, essential process — not passive rest. Choice A is a supporting detail. Choice B overstates one detail. Choice D introduces a specific claim (eight hours) not stated in the passage.', true),
  ('PC-MI-B4-4', 'PC', 'pc.main-idea', 2, 'Read the passage below and answer the question.

"Fort Bragg, renamed Fort Liberty in 2023, is one of the largest military installations in the world. It is home to the 82nd Airborne Division and several special operations units. The base covers more than 160,000 acres and supports over 50,000 soldiers and their families."

What is the main idea of this passage?', '["Fort Liberty is where the 82nd Airborne Division is stationed.","Fort Bragg was renamed Fort Liberty in 2023.","Fort Liberty is a large and significant military installation.","All military bases in the United States are being renamed."]'::jsonb, 2, 'The passage establishes the installation''s scale and importance. The renaming and the 82nd Airborne are supporting details. Choice D goes beyond what the passage states.', true),
  ('PC-MI-B4-5', 'PC', 'pc.main-idea', 3, 'Read the passage below and answer the question.

"The use of body-worn cameras by law enforcement officers has expanded rapidly over the past decade. Proponents argue that cameras improve accountability and reduce use-of-force incidents. Critics raise concerns about privacy and the cost of storing footage. Studies on whether cameras reduce complaints have produced mixed results, with outcomes varying by department policy and context."

What is the main idea of this passage?', '["Body cameras definitively reduce police misconduct.","Privacy concerns make body cameras impractical.","Body cameras are a complex issue with both potential benefits and drawbacks.","Most police departments now require body cameras."]'::jsonb, 2, 'The passage presents both supporters'' and critics'' views and notes mixed research results. Neither side wins outright, making the balanced complexity the main idea. Choices A and B represent one side only. Choice D is not stated.', true),
  ('PC-MI-B4-6', 'PC', 'pc.main-idea', 3, 'Read the passage below and answer the question.

"Coral reefs cover less than one percent of the ocean floor yet support roughly 25 percent of all marine species. Rising ocean temperatures cause corals to expel the algae that give them color and nutrients — a process called bleaching. Without intervention, scientists estimate that most of the world''s reefs could disappear by 2050."

What is the main idea of this passage?', '["Bleaching is the only threat facing coral reefs.","Coral reefs are critically important ecosystems under threat from warming oceans.","Scientists cannot predict the future of coral reefs.","Coral reefs cover 25 percent of the ocean floor."]'::jsonb, 1, 'The passage establishes the reefs'' importance (25% of species, <1% of floor) and the threat from warming. Choice A narrows the threat incorrectly. Choice C contradicts the passage''s prediction. Choice D confuses the statistics.', true),
  ('PC-MI-B4-7', 'PC', 'pc.main-idea', 3, 'Read the passage below and answer the question.

"Urban heat islands form when cities replace natural land with asphalt, concrete, and buildings that absorb and trap heat. Summer temperatures in urban centers can be 10°F higher than in surrounding rural areas. This excess heat increases energy demand for cooling, worsens air quality, and disproportionately harms elderly residents and people without air conditioning."

What is the main idea of this passage?', '["Cities should replace concrete with more trees.","Elderly people are most at risk from high temperatures.","Urban heat islands raise city temperatures and create several cascading problems.","Air quality is worse in cities than in rural areas for many reasons."]'::jsonb, 2, 'The passage defines the phenomenon and explains its multiple effects. Choice A prescribes a solution not mentioned in the text. Choice B focuses on one detail. Choice D broadens beyond the passage''s scope.', true),
  ('PC-MI-B4-8', 'PC', 'pc.main-idea', 4, 'Read the passage below and answer the question.

"For centuries, the ocean was assumed to be a largely silent place. This view was shattered in the mid-20th century when acoustic researchers discovered that marine mammals, fish, and invertebrates produce an enormous variety of sounds for communication, navigation, and predation. The introduction of naval sonar and commercial shipping has since generated underwater noise levels that disrupt these signals, altering migration paths, mating behavior, and feeding patterns across dozens of species."

What is the main idea of this passage?', '["Whales communicate using sonar, which was discovered in the mid-20th century.","Human-generated underwater noise is disrupting marine animal communication and behavior.","Researchers should stop using naval sonar in areas with marine mammals.","Fish produce sounds that are louder than commercial shipping noise."]'::jsonb, 1, 'The passage builds from the discovery that oceans are full of biological sound to the problem of human noise interference and its ecological effects. Choice A conflates whale communication with sonar. Choice C is a prescription the passage does not make. Choice D is not stated.', true),
  ('PC-MI-B4-9', 'PC', 'pc.main-idea', 4, 'Read the passage below and answer the question.

"Military doctrine distinguishes between strategy, which concerns the overall plan to achieve objectives, and tactics, which concern specific actions in the field. A commander who excels at tactics but ignores strategy may win battles while losing the war. Conversely, a strategist who fails to account for tactical realities often produces plans that collapse in contact with the enemy."

What is the main idea of this passage?', '["Strategy is more important than tactics in warfare.","Tactics involve specific battlefield actions, while strategy involves overall planning.","Effective military leadership requires both strategic and tactical competence.","Most commanders are stronger at tactics than at strategy."]'::jsonb, 2, 'The passage shows that neither strategy alone nor tactics alone suffices — both examples end in failure. The integrated lesson is the main idea. Choice B is a supporting definition, not the conclusion. The passage does not rank one above the other or claim one is more common.', true),
  ('PC-MI-B4-10', 'PC', 'pc.main-idea', 4, 'Read the passage below and answer the question.

"The invention of the printing press in the 15th century did not merely speed up book production — it fundamentally restructured the flow of information in European society. Within decades, ideas that once took generations to spread could circle the continent in months. The resulting surge in literacy, religious debate, and scientific exchange contributed to the Reformation, the Scientific Revolution, and ultimately the Enlightenment."

What is the main idea of this passage?', '["The printing press made books cheaper and more widely available.","The Reformation was caused primarily by the printing press.","The printing press transformed the speed and reach of information, reshaping European thought and history.","Johannes Gutenberg''s invention changed European religion more than European science."]'::jsonb, 2, 'The passage argues for broad historical transformation, not just faster printing. Choice A is a supporting detail. Choice B overstates one aspect. Choice D creates a ranking the passage does not support — it lists Reformation and Science as parallel effects.', true),
  ('PC-MI-B4-11', 'PC', 'pc.main-idea', 5, 'Read the passage below and answer the question.

"Risk homeostasis theory suggests that individuals have a target level of acceptable risk and unconsciously adjust their behavior to maintain it. When safety devices reduce perceived danger, people may compensate by behaving more recklessly — a phenomenon observed in seatbelt studies, where drivers with belts were found to follow more closely and brake later than unbelted drivers. The implication is that some safety interventions may partially cancel their own benefits."

What is the main idea of this passage?', '["Seatbelts are ineffective because people drive more recklessly when wearing them.","Safety technology always produces unintended negative consequences.","People tend to maintain a constant level of risk, which can reduce the net benefit of safety measures.","Risk homeostasis theory explains all dangerous driving behavior."]'::jsonb, 2, 'The passage presents the theory and seatbelt study as evidence that safety devices may be partially offset by behavioral changes — not that they are worthless. Choice A overstates the seatbelt finding. Choice B says ''always,'' which is unsupported. Choice D overextends the theory''s scope.', true),
  ('PC-MI-B4-12', 'PC', 'pc.main-idea', 5, 'Read the passage below and answer the question.

"Counterinsurgency doctrine recognizes that military force alone rarely defeats an insurgency. Winning the loyalty of the civilian population — through security guarantees, economic development, and effective governance — is as critical as any battlefield outcome. When operations undermine civilian trust, tactical victories can accelerate strategic defeat by driving the population toward the insurgents."

What is the main idea of this passage?', '["Economic development is the most important element of counterinsurgency.","Military force is useless in counterinsurgency operations.","Effective counterinsurgency requires winning civilian support, not just battlefield victories.","Counterinsurgency doctrine was developed in the 20th century."]'::jsonb, 2, 'The passage argues that civilian loyalty is as critical as military results, and that operations damaging civilian trust can cause strategic failure despite tactical wins. Choice A elevates one element above the others without support. Choice B overstates (''alone rarely defeats'' ≠ ''useless''). Choice D is not addressed.', true),
  ('PC-DR-B4-1', 'PC', 'pc.detail-recall', 1, 'Read the passage below and answer the question.

"The Army Combat Fitness Test (ACFT) replaced the older Army Physical Fitness Test in 2020. The ACFT includes six events: the three-repetition maximum deadlift, the standing power throw, the hand-release push-up, the sprint-drag-carry, the leg tuck, and the two-mile run."

How many events does the ACFT include?', '["four","five","six","seven"]'::jsonb, 2, 'The passage explicitly states the ACFT includes six events and then lists all six. The test replaced the older APFT in 2020.', true),
  ('PC-DR-B4-2', 'PC', 'pc.detail-recall', 1, 'Read the passage below and answer the question.

"The human heart has four chambers: the right atrium, the right ventricle, the left atrium, and the left ventricle. The right side receives oxygen-poor blood from the body and sends it to the lungs; the left side receives oxygen-rich blood from the lungs and pumps it out to the body."

Which side of the heart pumps oxygen-rich blood to the body?', '["the right atrium","the right ventricle","the left side","both sides equally"]'::jsonb, 2, 'The passage states that the left side receives oxygen-rich blood from the lungs and pumps it to the body. The right side handles oxygen-poor blood on its way to the lungs.', true),
  ('PC-DR-B4-3', 'PC', 'pc.detail-recall', 2, 'Read the passage below and answer the question.

"The Uniform Code of Military Justice (UCMJ) is the foundation of military law in the United States. Enacted by Congress in 1950, it applies to all members of the armed forces at all times — on duty or off, in the United States or abroad. Violations are addressed through the military justice system, not the civilian court system."

When does the UCMJ apply to service members?', '["Only while on active duty in the United States","Only when serving overseas","At all times, whether on or off duty and regardless of location","Only when in uniform"]'::jsonb, 2, 'The passage states explicitly that the UCMJ applies ''at all times — on duty or off, in the United States or abroad.'' Being in uniform is not mentioned as a condition.', true),
  ('PC-DR-B4-4', 'PC', 'pc.detail-recall', 2, 'Read the passage below and answer the question.

"Landmines are designed to be triggered by pressure, a trip wire, or a remote signal. Clearing a minefield requires trained engineers using metal detectors, ground-penetrating radar, or specially trained dogs. A typical clearing team can safely clear between 20 and 50 square meters per person per day under field conditions."

According to the passage, which of the following is NOT mentioned as a method of clearing minefields?', '["metal detectors","controlled burning","ground-penetrating radar","specially trained dogs"]'::jsonb, 1, 'The passage lists metal detectors, ground-penetrating radar, and specially trained dogs as clearing methods. Controlled burning is not mentioned. The daily clearing rate of 20–50 square meters is a detail, not a method.', true),
  ('PC-DR-B4-5', 'PC', 'pc.detail-recall', 3, 'Read the passage below and answer the question.

"The Geneva Conventions, first adopted in 1864 and significantly expanded in 1949, establish international legal standards for the humane treatment of wounded soldiers, prisoners of war, and civilians in armed conflict. They do not prohibit war; they regulate how war is conducted. The conventions are binding on all nations that have ratified them, which includes most countries in the world."

According to the passage, what is the primary purpose of the Geneva Conventions?', '["To prohibit nations from going to war","To establish standards for humane treatment during armed conflict","To create an international court for war crimes","To define which weapons are illegal in combat"]'::jsonb, 1, 'The passage states the conventions ''establish international legal standards for humane treatment'' and clarifies they ''do not prohibit war'' but regulate how it is conducted. Courts and weapons restrictions are not mentioned.', true),
  ('PC-DR-B4-6', 'PC', 'pc.detail-recall', 3, 'Read the passage below and answer the question.

"Permafrost is ground that remains frozen for at least two consecutive years. It underlies about 15 percent of the world''s exposed land surface, concentrated in Alaska, Canada, Russia, and Greenland. As global temperatures rise, permafrost thaws and releases carbon dioxide and methane — greenhouse gases that had been trapped for thousands of years. Scientists estimate that Arctic permafrost alone stores twice as much carbon as is currently in the atmosphere."

According to the passage, what happens when permafrost thaws?', '["It releases oxygen into the atmosphere","It lowers global temperatures by exposing cooler ground","It releases carbon dioxide and methane that had been stored for thousands of years","It creates new lakes that absorb greenhouse gases"]'::jsonb, 2, 'The passage directly states that thawing permafrost ''releases carbon dioxide and methane — greenhouse gases that had been trapped for thousands of years.'' The other options are not stated or are contradicted.', true),
  ('PC-DR-B4-7', 'PC', 'pc.detail-recall', 3, 'Read the passage below and answer the question.

"The M4 carbine is a lighter, shorter variant of the M16 rifle and has been the standard infantry weapon of the U.S. Army since 1997. It fires 5.56 mm NATO rounds and has a maximum effective range of approximately 500 meters against a point target. Its collapsible stock allows soldiers to adjust the weapon for comfort and to operate it more easily in confined spaces."

According to the passage, what is one advantage of the M4''s collapsible stock?', '["It increases the rifle''s effective range beyond 500 meters","It allows soldiers to adjust fit and operate the weapon in confined spaces","It reduces the weight of the weapon below the M16","It enables the weapon to fire different caliber rounds"]'::jsonb, 1, 'The passage states the collapsible stock allows adjustment for comfort and easier operation in confined spaces. Range, weight comparison, and caliber flexibility are separate details not attributed to the stock specifically.', true),
  ('PC-DR-B4-8', 'PC', 'pc.detail-recall', 4, 'Read the passage below and answer the question.

"Vitamin D is unusual among vitamins in that the human body can synthesize it from sunlight. When ultraviolet B radiation strikes the skin, it converts a cholesterol compound into a precursor that the liver and kidneys then transform into the active form of vitamin D. Deficiency is common in northern latitudes during winter, among people who spend little time outdoors, and among individuals with darker skin, whose higher melanin levels reduce UV absorption."

According to the passage, which group is at elevated risk for vitamin D deficiency?', '["People who eat large amounts of cholesterol","People who spend little time outdoors","People who live at high altitudes","People who take regular vitamin supplements"]'::jsonb, 1, 'The passage lists three groups at risk: people in northern latitudes in winter, those who spend little time outdoors, and those with darker skin. High altitude and supplementation are not mentioned.', true),
  ('PC-DR-B4-9', 'PC', 'pc.detail-recall', 4, 'Read the passage below and answer the question.

"The Korean War (1950–1953) ended with an armistice agreement rather than a peace treaty. An armistice is a ceasefire agreement that halts active fighting; it does not formally end a state of war. As a result, North Korea and South Korea remain technically at war to this day, with the armistice line — roughly along the 38th parallel — serving as the border between the two nations."

According to the passage, why are North Korea and South Korea technically still at war?', '["The United Nations never recognized South Korea as a separate nation.","Fighting resumed after the armistice was signed.","An armistice halts fighting but does not formally end a state of war.","The peace treaty was signed but never ratified by both governments."]'::jsonb, 2, 'The passage explains that an armistice is only a ceasefire and does not end the war legally. No peace treaty was signed — nor does the passage say one was signed and unratified. Choice B is contradicted by the passage.', true),
  ('PC-DR-B4-10', 'PC', 'pc.detail-recall', 4, 'Read the passage below and answer the question.

"The blood-brain barrier (BBB) is a selective membrane formed by tightly joined cells lining the brain''s blood vessels. It allows oxygen, glucose, and certain small molecules to pass while blocking larger molecules, most bacteria, and many drugs. This protection is valuable during infection, but it also makes treating brain diseases especially challenging because therapeutic compounds must be small and lipid-soluble enough to cross the barrier."

According to the passage, what makes treating brain diseases particularly difficult?', '["Bacteria can cross the blood-brain barrier and destroy brain cells","Most drugs are too large or not lipid-soluble enough to cross the blood-brain barrier","The blood-brain barrier blocks oxygen from reaching the brain during illness","There are no drugs approved for treating brain diseases"]'::jsonb, 1, 'The passage states that drugs must be ''small and lipid-soluble enough to cross the barrier,'' implying most drugs fail this requirement. Bacteria are blocked (not entering), and oxygen does cross the barrier. Choice D is not stated.', true),
  ('PC-DR-B4-11', 'PC', 'pc.detail-recall', 5, 'Read the passage below and answer the question.

"The NATO phonetic alphabet assigns a standardized spoken word to each letter of the alphabet to prevent miscommunication over radio — where letters like B, D, E, and P sound similar. The system, adopted internationally in 1956, uses words such as Alpha (A), Bravo (B), Charlie (C), and Delta (D). These words were chosen based on their distinctiveness across multiple languages and accents, not merely their convenience in English."

According to the passage, why were the NATO phonetic alphabet words specifically chosen?', '["Because they were easiest for English-speaking soldiers to remember","Because they are the shortest words possible for each letter","Because they are distinctive across multiple languages and accents","Because they replaced a longer, more complicated system used in World War II"]'::jsonb, 2, 'The passage explicitly states words were chosen for distinctiveness ''across multiple languages and accents, not merely their convenience in English.'' Choice A is directly contradicted. Choices B and D are not mentioned.', true),
  ('PC-DR-B4-12', 'PC', 'pc.detail-recall', 5, 'Read the passage below and answer the question.

"Autonomous vehicles use a combination of lidar, radar, cameras, and ultrasonic sensors to map their environment in real time. Lidar creates a three-dimensional point cloud by emitting laser pulses and measuring their return time; radar works in darkness and adverse weather where lidar degrades; cameras interpret visual detail and read signs. No single sensor alone provides sufficient data — redundancy across sensor types is what makes autonomous navigation reliable."

According to the passage, what advantage does radar offer over lidar?', '["Radar creates a more detailed three-dimensional map of the surroundings","Radar is more accurate at reading road signs than cameras","Radar functions in darkness and poor weather where lidar performance degrades","Radar is less expensive than lidar and therefore used as the primary sensor"]'::jsonb, 2, 'The passage states radar ''works in darkness and adverse weather where lidar degrades.'' Three-dimensional mapping is attributed to lidar. Sign reading is cameras. Cost is not mentioned.', true),
  ('PC-INF-B4-1', 'PC', 'pc.inference', 1, 'Read the passage below and answer the question.

"Maria studied every night for two weeks before her ASVAB test. She reviewed all the practice questions and completed three full mock exams."

What can be reasonably inferred about Maria?', '["Maria found the ASVAB easy and did not need to study.","Maria took the test seriously and prepared thoroughly.","Maria failed the ASVAB despite her studying.","Maria had already taken the ASVAB once before."]'::jsonb, 1, 'Two weeks of nightly study, review of all material, and three mock exams clearly suggest thorough and serious preparation. No information supports failure or a prior attempt.', true),
  ('PC-INF-B4-2', 'PC', 'pc.inference', 1, 'Read the passage below and answer the question.

"The mess hall ran out of food before the last two platoons could eat. They were told to wait while a new batch was prepared."

What can be reasonably inferred from this passage?', '["The kitchen staff made a planning error or underestimated the number of soldiers to feed.","The last two platoons arrived too late because they were on punishment detail.","The mess hall was being closed permanently.","Food shortages are common at this installation."]'::jsonb, 0, 'Running out of food before all soldiers could eat implies either underestimation or a planning failure. The other choices introduce specifics (punishment, closure, recurring shortages) that the passage does not support.', true),
  ('PC-INF-B4-3', 'PC', 'pc.inference', 2, 'Read the passage below and answer the question.

"After the inspection, the sergeant entered the barracks without speaking, set the checklist on the desk, and left. The soldiers exchanged nervous glances."

What can be inferred about the inspection results?', '["The inspection went well and the soldiers were relieved.","The sergeant was too tired to speak after a long day.","The results were uncertain or possibly unfavorable, creating anxiety among the soldiers.","The sergeant was planning to commend the soldiers later."]'::jsonb, 2, 'The sergeant''s silence, the simple deposit of the checklist, and the soldiers'' nervous glances all signal uncertainty or concern about the outcome. No positive signals (praise, thumbs up) are given. Silent exits after inspections typically indicate a problem, not commendation.', true),
  ('PC-INF-B4-4', 'PC', 'pc.inference', 2, 'Read the passage below and answer the question.

"The new regulation limits each soldier to two personal electronic devices during deployment. Soldiers found with additional devices will have the excess items confiscated."

What can be inferred about a soldier who brings a personal laptop, a tablet, and two cell phones on deployment?', '["The soldier will be permitted to keep all four devices since they serve different purposes.","The soldier has more than the allowed number of devices and risks having some confiscated.","The soldier must have received special authorization for the extra devices.","Cell phones are not counted as electronic devices under the regulation."]'::jsonb, 1, 'Four devices exceeds the limit of two. The regulation states excess devices will be confiscated. The passage gives no basis for special authorization or exempting phones from the device count.', true),
  ('PC-INF-B4-5', 'PC', 'pc.inference', 3, 'Read the passage below and answer the question.

"A city''s storm drainage system was designed in the 1950s to handle up to 2 inches of rain per hour. In recent years, the city has experienced repeated flooding events following storms that produced 3 to 4 inches per hour. City engineers are now examining options for upgrading the system."

What can be inferred from this passage?', '["The engineers designed the original system incorrectly.","Climate patterns have changed, producing more intense rainfall than the system was built to handle.","The city should relocate rather than invest in drainage infrastructure.","Heavy rain events were unknown when the drainage system was built."]'::jsonb, 1, 'The original system''s capacity (2 in/hr) was appropriate for its time; recent storms exceed it (3–4 in/hr). The most logical inference is that conditions have changed, not that the original design was wrong. Relocation is not suggested, and heavy rain certainly occurred in the 1950s.', true),
  ('PC-INF-B4-6', 'PC', 'pc.inference', 3, 'Read the passage below and answer the question.

"At the aid station, the medic triaged four patients: one with a broken wrist, one with a severe abdominal wound, one with a minor laceration, and one with a dislocated shoulder. The medic immediately called for a surgeon and moved the second patient to the operating area."

What can be inferred about the triage decision?', '["The medic treated the least serious cases first to prevent them from worsening.","The abdominal wound was judged most life-threatening and received priority care.","The patient with the broken wrist was the medic''s primary concern.","The medic could not determine which patient was most critical."]'::jsonb, 1, 'The medic moved the second patient — the one with the severe abdominal wound — immediately to surgery. A severe abdominal wound is typically life-threatening, explaining the prioritization. The other injuries (broken wrist, laceration, dislocated shoulder) are serious but less immediately fatal.', true),
  ('PC-INF-B4-7', 'PC', 'pc.inference', 3, 'Read the passage below and answer the question.

"An experienced trail guide once said that a group moving through wilderness is only as fast as its slowest member. He always positioned himself at the rear of the column, not the front."

What can be inferred about why the guide positioned himself at the rear?', '["He wanted to avoid leading the group in case he made a navigation error.","Positioning at the rear let him monitor the slowest members and ensure no one fell behind.","He preferred the view from the back of the column.","Walking at the rear is the safest position in dangerous terrain."]'::jsonb, 1, 'His statement that a group is only as fast as its slowest member logically motivates watching those at the back. If the group''s pace is governed by the slowest person, the guide at the rear can monitor that person and keep the column together.', true),
  ('PC-INF-B4-8', 'PC', 'pc.inference', 4, 'Read the passage below and answer the question.

"Archaeological evidence shows that the first settlements at the site date to approximately 3,000 BCE. The settlement was abandoned suddenly around 1,200 BCE — grain stores were left full, tools were found mid-task, and cooking fires had not been extinguished. No bodies were found in the ruins."

What can be reasonably inferred from the evidence described?', '["The settlement was destroyed by a volcanic eruption that killed all residents.","The inhabitants left abruptly and likely survived to resettle elsewhere.","The settlement was abandoned because the grain supply ran out.","Disease wiped out the population, leaving no one to extinguish the fires."]'::jsonb, 1, 'Full grain stores and tools mid-task indicate the departure was sudden, not planned. The absence of bodies suggests the people left rather than died in place. A volcanic eruption or disease would likely leave victims. Grain supply was clearly not the reason (stores were full).', true),
  ('PC-INF-B4-9', 'PC', 'pc.inference', 4, 'Read the passage below and answer the question.

"A new field manual requires squad leaders to document the reason for any deviation from the standard patrol formation. Within one month, the number of undocumented deviations dropped by 90 percent, but the number of formally documented deviations actually increased by 40 percent."

What can be inferred from these statistics?', '["The patrol route itself was changed 40 percent more often after the manual was issued.","Squad leaders began to comply with the documentation requirement, making previously hidden deviations visible.","Deviations decreased because the new patrol routes were safer.","The 40 percent increase indicates that discipline worsened after the manual was issued."]'::jsonb, 1, 'The near-elimination of undocumented deviations alongside a rise in documented ones suggests that deviations were occurring before — just unrecorded. The requirement brought them into the official record, not that more deviations were happening. The wording about ''discipline worsening'' misreads more documentation as more rule-breaking.', true),
  ('PC-INF-B4-10', 'PC', 'pc.inference', 4, 'Read the passage below and answer the question.

"The treaty required both nations to reduce their stockpiles by 30 percent within five years. Nation A submitted its reduction plan on the first day. Nation B requested four extensions over three years and had completed only 8 percent of its reduction by the deadline."

What can be inferred about Nation B''s commitment to the treaty terms?', '["Nation B strongly supports the treaty but lacked the technical capacity to comply.","Nation B''s pattern of delays and minimal compliance suggests it is not fully committed to the treaty.","Nation B reduced its stockpile by more than required once the extensions were granted.","Both nations treated the deadline as optional."]'::jsonb, 1, 'Four extension requests and only 8% completion against a 30% requirement strongly suggests reluctance or unwillingness, not merely technical difficulty. Nation A''s prompt action makes the treaty''s feasibility clear. Choice C contradicts the 8% figure. Choice D is not supported — Nation A complied.', true),
  ('PC-INF-B4-11', 'PC', 'pc.inference', 5, 'Read the passage below and answer the question.

"A company that manufactured industrial components for 80 years announced in its final quarterly report that it was profitable. Two weeks later, it declared bankruptcy. Investigators later found that the company had been shifting expenses to subsidiaries it owned, making the parent company''s balance sheet appear healthy while debt accumulated elsewhere in the corporate structure."

What can be inferred from this passage?', '["The company''s auditors had approved its financial practices as legal and accurate.","The bankruptcy was caused by a sudden market downturn that followed the report.","The profitable quarterly report was misleading because it concealed debt that existed at the corporate level.","The subsidiaries were unrelated businesses that happened to fail at the same time."]'::jsonb, 2, 'The scheme involved moving debt to subsidiaries so the parent looked profitable. The investigators'' finding directly implies the report misrepresented the company''s true financial condition. Auditor approval is not stated. A sudden market downturn contradicts the structural debt explanation. The subsidiaries were owned by the company, not unrelated.', true),
  ('PC-INF-B4-12', 'PC', 'pc.inference', 5, 'Read the passage below and answer the question.

"A cognitive study found that participants who were told they were being observed performed routine tasks more carefully but produced less creative output. A follow-up study removed the observer and found that creative output increased while error rates on routine tasks rose slightly."

What can be inferred from the two studies taken together?', '["Observation is harmful and should be eliminated from all performance evaluations.","Creative workers should never be monitored.","Observation appears to enhance accuracy on routine tasks but may inhibit creative thinking.","The follow-up study invalidates the results of the first study."]'::jsonb, 2, 'The two studies together show a trade-off: observation increases routine accuracy but suppresses creativity; removing observation reverses both effects. Neither study is invalidated — they are complementary. Choices A and B draw absolute policy conclusions the data do not support.', true),
  ('PC-ATP-B4-1', 'PC', 'pc.author-tone-purpose', 1, 'Read the passage below and answer the question.

"Eating breakfast every morning gives your body the energy it needs to start the day. Students who eat breakfast tend to perform better in class and stay focused longer than those who skip it. Make it a habit to eat something in the morning, even if it is small."

The author''s purpose in writing this passage is to:', '["describe the history of breakfast as a cultural practice","encourage readers to eat breakfast regularly","compare different types of breakfast foods","report the results of a scientific study"]'::jsonb, 1, 'The imperative ''Make it a habit'' and the benefits-focused framing show the author''s goal is to persuade the reader to act. The passage does not cover history, food comparisons, or methodology.', true),
  ('PC-ATP-B4-2', 'PC', 'pc.author-tone-purpose', 1, 'Read the passage below and answer the question.

"The base library is open Monday through Friday from 0800 to 2000 and on Saturdays from 0900 to 1700. It is closed on Sundays and federal holidays. Soldiers must present their military ID to check out materials."

The author''s primary purpose in writing this passage is to:', '["argue that libraries are important resources for soldiers","persuade soldiers to use the library more often","provide factual information about library hours and access requirements","compare the base library to civilian public libraries"]'::jsonb, 2, 'The passage consists entirely of factual information: hours, closure days, and ID requirement. No opinion, comparison, or persuasion is present.', true),
  ('PC-ATP-B4-3', 'PC', 'pc.author-tone-purpose', 2, 'Read the passage below and answer the question.

"Every spring, the river flooded the lower fields, and every spring the farmers rebuilt their fences, replanted their seeds, and returned to work. They did not complain — or if they did, they complained only to one another, quietly, and then went back to the fields."

The author''s tone toward the farmers can best be described as:', '["critical of their failure to prevent the flooding","admiring of their quiet resilience","indifferent to their annual struggles","sympathetic but pessimistic about their future"]'::jsonb, 1, '''Did not complain'' and returning to work each year without fanfare conveys quiet strength. The author''s choice to note their stoicism — and to present it without irony — signals admiration. No criticism, indifference, or pessimism is present in the tone.', true),
  ('PC-ATP-B4-4', 'PC', 'pc.author-tone-purpose', 2, 'Read the passage below and answer the question.

"The city council has approved, for the third time in five years, a measure to study whether a downtown parking garage is needed. Meanwhile, the parking shortage continues, three businesses have closed citing customer difficulty parking, and the mayor has announced another task force. Progress, apparently, is on schedule."

The author''s tone is best described as:', '["supportive of the council''s methodical approach","sarcastically critical of the lack of action","neutral and informational","alarmed by the economic impact on local businesses"]'::jsonb, 1, '''Progress, apparently, is on schedule'' is the give-away — said while describing three studies and no solution, this is textbook sarcasm. The author presents facts in a way that makes the inaction obvious, then punctuates it with a mock-positive conclusion.', true),
  ('PC-ATP-B4-5', 'PC', 'pc.author-tone-purpose', 3, 'Read the passage below and answer the question.

"Letters from soldiers to their families during World War I reveal an almost universal silence on the worst of what they experienced. The mud, the cold, and the artillery were mentioned; the dead faces of friends were not. They wrote about food, about home, about small jokes — anything to protect the people they loved from what could not be unseen."

The author''s tone toward the soldiers can best be described as:', '["critical of the soldiers for hiding the truth from their families","analytical and detached","somber and deeply respectful","nostalgic for the simplicity of wartime letters"]'::jsonb, 2, '''Anything to protect the people they loved from what could not be unseen'' frames the soldiers'' silence as an act of love, not deception. The gravity of ''what could not be unseen'' adds solemnity. The tone is respectful and somber, not analytical or nostalgic.', true),
  ('PC-ATP-B4-6', 'PC', 'pc.author-tone-purpose', 3, 'Read the passage below and answer the question.

"A growing body of research suggests that multitasking — far from being a productivity technique — reduces performance on all tasks attempted simultaneously. The brain does not truly parallel-process complex activities; it rapidly switches attention between them, with a switching cost paid each time. Those who believe they are efficient multitaskers are often, according to the data, among the worst performers on divided-attention tests."

The author''s primary purpose is to:', '["celebrate the ability of skilled professionals to multitask effectively","describe the history of research on human attention","challenge the belief that multitasking is an effective productivity strategy","compare multitasking across different professions"]'::jsonb, 2, 'The passage presents evidence against multitasking and ends with the ironic finding that self-described multitaskers perform worst. The purpose is clearly to challenge the assumption. History and cross-profession comparisons are absent.', true),
  ('PC-ATP-B4-7', 'PC', 'pc.author-tone-purpose', 3, 'Read the passage below and answer the question.

"The space between words is where a good editor works. A manuscript arrives fat with adjectives, brimming with throat-clearing introductions, padded with every idea the writer was afraid to leave out. The editor''s gift is not addition but subtraction — the courage to remove what the writer loved but the reader does not need."

The author''s attitude toward the act of editing is best described as:', '["skeptical that most editors have the necessary skills","reverential — viewing good editing as a rare and meaningful craft","critical of writers who overwrite their manuscripts","neutral, presenting editing as a technical process"]'::jsonb, 1, '''The editor''s gift'' and ''the courage to remove'' frame editing as a special ability — a gift requiring bravery. This elevated treatment signals reverence, not skepticism or neutrality. The passage describes writer habits sympathetically (''every idea the writer was afraid to leave out''), not critically.', true),
  ('PC-ATP-B4-8', 'PC', 'pc.author-tone-purpose', 4, 'Read the passage below and answer the question.

"The glacier that covered this valley 12,000 years ago left behind the hills to the north, the flat plain to the south, and the scattering of boulders that farmers have been removing from their fields ever since. Ice, it turns out, is not merely weather. Given enough time and weight, it becomes geology."

The author''s tone is best described as:', '["alarmed by the ongoing effects of ancient glaciation","wryly reflective, finding meaning in the slow scale of geological time","strictly scientific and data-driven","mournful about the disappearance of glaciers"]'::jsonb, 1, '''It turns out'' and the observation that ice ''becomes geology'' are quiet, reflective moments — the author finds something worth remarking on in the long view of time. This is contemplative, slightly wry, not alarmed or data-driven. Glacial disappearance is not the subject.', true),
  ('PC-ATP-B4-9', 'PC', 'pc.author-tone-purpose', 4, 'Read the passage below and answer the question.

"The committee report ran to 847 pages. It was released on a Friday afternoon in December, with no press conference scheduled. The executive summary was 4 pages. The findings were labeled ''preliminary.'' Six months later, a follow-up was promised."

The author''s implied attitude toward the committee''s handling of the report is:', '["supportive — a 847-page report demonstrates thoroughness","critical — the details suggest the report was released to minimize public attention","neutral — the author is simply presenting facts without judgment","hopeful — the follow-up report may address unresolved questions"]'::jsonb, 1, 'Friday afternoon December releases, no press conference, ''preliminary'' findings, and a delayed follow-up are classic bureaucratic tactics for burying unwanted information. The author selects these details deliberately to imply criticism without stating it. A neutral author would not stack these signals.', true),
  ('PC-ATP-B4-10', 'PC', 'pc.author-tone-purpose', 5, 'Read the passage below and answer the question.

"The soldier who does not think about the mission — who moves on instinct, reflex, and training alone — is often called battle-hardened. We praise him for it. We decorate him for it. And then, when the war ends and he cannot stop moving on instinct, we call it a disorder and wonder why the training does not switch off when the war does."

The author''s primary purpose is to:', '["argue that soldiers should not be given combat training","criticize soldiers for seeking recognition through combat","highlight a contradiction in how society values and then pathologizes combat instincts","propose a new approach to treating veterans with post-traumatic stress"]'::jsonb, 2, 'The passage traces one cycle: we train the response, reward the response, then diagnose the same response as a disorder. The author''s purpose is to expose this contradiction, not to argue against training or propose clinical solutions. ''We praise him'' and ''we call it a disorder'' shows the critical symmetry is the point.', true),
  ('PC-ATP-B4-11', 'PC', 'pc.author-tone-purpose', 5, 'Read the passage below and answer the question.

"There is something both useful and troubling about the word ''closure.'' Useful, because it gives people permission to move forward after loss. Troubling, because it implies that grief has a terminal state — that the missing weight of a person eventually becomes light enough to carry without noticing. People who have lost someone they love report, almost universally, that they do not stop missing them. They simply learn to carry the weight differently."

The author''s tone toward the concept of ''closure'' is best described as:', '["firmly opposed — the author believes the word should be abandoned","fully supportive — closure is essential for healthy grieving","nuanced — the author acknowledges its usefulness while questioning its implied finality","clinical and detached, reporting grief research without personal interpretation"]'::jsonb, 2, 'The author calls closure ''both useful and troubling,'' then unpacks both halves. This is not opposition or support — it is a nuanced critique that preserves the word''s value while questioning its misleading implication of completeness. The lyrical ending (''carry the weight differently'') rules out clinical detachment.', true),
  ('GS-LS-B5-1', 'GS', 'gs.life-science', 1, 'Which organelle is known as the powerhouse of the cell because it produces most of the cell''s energy?', '["Nucleus","Ribosome","Mitochondria","Vacuole"]'::jsonb, 2, 'Mitochondria produce ATP through cellular respiration, supplying the energy cells need for all their functions. The nucleus stores DNA; ribosomes make proteins; vacuoles store materials.', true),
  ('GS-LS-B5-2', 'GS', 'gs.life-science', 1, 'Which gas do plants release as a byproduct of photosynthesis?', '["Carbon dioxide","Nitrogen","Oxygen","Hydrogen"]'::jsonb, 2, 'During photosynthesis, plants split water molecules and release oxygen as a byproduct. Carbon dioxide is consumed, not released, during photosynthesis.', true),
  ('GS-LS-B5-3', 'GS', 'gs.life-science', 2, 'The primary role of the cell membrane is to:', '["Produce proteins for the cell","Control what enters and exits the cell","Store genetic information","Convert sunlight into energy"]'::jsonb, 1, 'The cell membrane is selectively permeable, regulating the passage of substances in and out of the cell. Protein production occurs at ribosomes; DNA is stored in the nucleus.', true),
  ('GS-LS-B5-4', 'GS', 'gs.life-science', 2, 'In an ecosystem, which organisms are the primary producers?', '["Herbivores","Carnivores","Decomposers","Plants and algae"]'::jsonb, 3, 'Primary producers (plants, algae, and some bacteria) capture energy from sunlight through photosynthesis and form the base of the food chain. Herbivores and carnivores are consumers; decomposers break down dead matter.', true),
  ('GS-LS-B5-5', 'GS', 'gs.life-science', 2, 'Which blood component is primarily responsible for fighting bacterial infections?', '["Red blood cells","Platelets","White blood cells","Plasma"]'::jsonb, 2, 'White blood cells (leukocytes) are the immune system''s primary defense, attacking bacteria and other pathogens. Red blood cells carry oxygen; platelets help clot blood; plasma is the liquid carrier.', true),
  ('GS-LS-B5-7', 'GS', 'gs.life-science', 3, 'A food chain reads: grass → grasshopper → frog → hawk. If the frog population is removed, what is the most likely short-term result?', '["Hawks will increase in number","Grasshoppers will increase in number","Grass will decrease","Hawks will switch to eating grasshoppers directly and maintain balance"]'::jsonb, 1, 'Removing frogs eliminates the primary predator of grasshoppers, so grasshopper populations would surge. Hawks lose a food source and may decline. Grass would likely decrease as more grasshoppers consume it.', true),
  ('GS-LS-B5-8', 'GS', 'gs.life-science', 3, 'Osmosis is best defined as:', '["The active transport of glucose across a membrane","The movement of water from low solute concentration to high solute concentration across a semipermeable membrane","The diffusion of oxygen from lungs into the bloodstream","The breakdown of food in the digestive tract"]'::jsonb, 1, 'Osmosis is the passive movement of water through a semipermeable membrane from an area of lower solute concentration to an area of higher solute concentration. It does not require energy and moves water, not solutes.', true),
  ('GS-LS-B5-9', 'GS', 'gs.life-science', 3, 'Which organ system is responsible for removing gaseous waste (carbon dioxide) from the body?', '["Digestive system","Urinary system","Respiratory system","Circulatory system"]'::jsonb, 2, 'The respiratory system — specifically the lungs — exchanges gases: oxygen enters the blood and carbon dioxide is expelled when exhaling. The urinary system removes liquid waste; the digestive system removes solid waste.', true),
  ('GS-LS-B5-10', 'GS', 'gs.life-science', 4, 'A plant cell placed in a highly concentrated salt solution will most likely:', '["Swell and burst as water rushes in","Remain unchanged because the cell wall prevents movement","Shrink as water moves out through osmosis","Absorb the salt ions and increase in size"]'::jsonb, 2, 'The salt solution has a higher solute concentration than the cell''s interior. By osmosis, water moves from the cell (lower solute) into the solution (higher solute), causing the cell to shrink (plasmolyze). The cell wall limits swelling, not shrinking.', true),
  ('GS-LS-B5-11', 'GS', 'gs.life-science', 4, 'Mitosis results in:', '["Two genetically identical daughter cells, each with the same chromosome number as the parent","Four daughter cells, each with half the parent''s chromosome number","One parent cell that doubles its DNA but does not divide","Two cells with different genetic makeup due to chromosome shuffling"]'::jsonb, 0, 'Mitosis produces two genetically identical cells that each carry the same number of chromosomes as the original cell — used for growth and repair. Meiosis (not mitosis) produces four cells with half the chromosome count for sexual reproduction.', true),
  ('GS-LS-B5-12', 'GS', 'gs.life-science', 4, 'Which process do decomposers like fungi and bacteria perform that is essential to the nutrient cycle?', '["Photosynthesis — converting CO₂ to glucose","Nitrogen fixation — converting N₂ gas to ammonia","Decomposition — breaking organic matter into inorganic nutrients","Transpiration — releasing water vapor from leaves"]'::jsonb, 2, 'Decomposers break down dead organisms and waste into simpler inorganic compounds, returning nutrients like carbon and nitrogen to the soil and atmosphere. Without decomposers, ecosystems would become buried in dead matter.', true),
  ('GS-LS-B5-13', 'GS', 'gs.life-science', 5, 'A recessive genetic trait will be expressed in an individual when:', '["The individual carries at least one dominant allele","The individual is heterozygous (one dominant, one recessive allele)","The individual inherits two recessive alleles, one from each parent","The trait skips a generation before appearing"]'::jsonb, 2, 'Recessive traits are masked when a dominant allele is present. Expression requires two copies of the recessive allele (homozygous recessive). Heterozygous individuals carry the trait but do not express it; ''skipping a generation'' describes the pattern, not the cause.', true),
  ('GS-LS-B5-14', 'GS', 'gs.life-science', 5, 'During aerobic cellular respiration, where in the cell does the Krebs cycle take place?', '["In the cytoplasm","In the nucleus","In the mitochondrial matrix","On the outer mitochondrial membrane"]'::jsonb, 2, 'The Krebs cycle (citric acid cycle) occurs in the mitochondrial matrix — the innermost compartment. Glycolysis happens in the cytoplasm. The electron transport chain is located on the inner mitochondrial membrane, not in the matrix itself.', true),
  ('GS-PS-B5-1', 'GS', 'gs.physical-science', 1, 'Which state of matter has a definite volume but no definite shape?', '["Solid","Liquid","Gas","Plasma"]'::jsonb, 1, 'A liquid has a fixed volume but takes the shape of its container. Solids have both definite shape and volume; gases have neither. Plasma is an ionized gas with neither fixed shape nor volume.', true),
  ('GS-PS-B5-2', 'GS', 'gs.physical-science', 1, 'Which of the following is a chemical change?', '["Ice melting into water","Cutting a piece of paper","Iron rusting","Sugar dissolving in water"]'::jsonb, 2, 'Rusting involves iron reacting with oxygen to form iron oxide — a new substance with different chemical properties. Melting, cutting, and dissolving are physical changes; the substance''s chemical identity does not change.', true),
  ('GS-PS-B5-3', 'GS', 'gs.physical-science', 2, 'On the periodic table, elements in the same column (group) share similar properties primarily because they have the same:', '["Atomic mass","Number of protons","Number of neutrons","Number of valence electrons"]'::jsonb, 3, 'Elements in the same group have the same number of valence electrons, which determines their chemical behavior and bonding tendencies. Atomic mass and neutron count vary even within groups.', true),
  ('GS-PS-B5-4', 'GS', 'gs.physical-science', 2, 'What happens to the pressure of a gas inside a sealed container when the temperature increases, assuming volume stays constant?', '["Pressure decreases","Pressure stays the same","Pressure increases","The gas liquefies"]'::jsonb, 2, 'When temperature rises, gas molecules move faster and collide with container walls more forcefully and frequently, increasing pressure. This relationship is described by Gay-Lussac''s Law (P ∝ T at constant volume).', true),
  ('GS-PS-B5-5', 'GS', 'gs.physical-science', 2, 'In a chemical reaction, the substances that are present before the reaction begins are called:', '["Products","Reactants","Catalysts","Compounds"]'::jsonb, 1, 'Reactants are the starting materials in a chemical reaction that are converted into products. Catalysts speed up reactions without being consumed; products are the substances formed.', true),
  ('GS-PS-B5-6', 'GS', 'gs.physical-science', 3, 'A substance has a pH of 2. Which statement best describes this substance?', '["It is strongly basic and will feel slippery","It is weakly acidic and slightly corrosive","It is strongly acidic with high hydrogen ion concentration","It is neutral and safe to drink in any quantity"]'::jsonb, 2, 'pH 2 is strongly acidic — far below the neutral pH of 7. The lower the pH, the higher the concentration of hydrogen ions (H⁺). Battery acid (pH ~1) and vinegar (pH ~3) bracket this range; strongly basic substances have high pH (above 7).', true),
  ('GS-PS-B5-7', 'GS', 'gs.physical-science', 3, 'When a substance undergoes sublimation, it transitions directly from:', '["Liquid to gas","Solid to liquid","Solid to gas","Gas to liquid"]'::jsonb, 2, 'Sublimation is the direct phase transition from solid to gas without passing through the liquid state. Dry ice (solid CO₂) is a common example. The reverse process (gas to solid) is called deposition.', true),
  ('GS-PS-B5-8', 'GS', 'gs.physical-science', 3, 'Which type of chemical bond results from the transfer of electrons from one atom to another?', '["Covalent bond","Hydrogen bond","Ionic bond","Metallic bond"]'::jsonb, 2, 'Ionic bonds form when one atom gives electrons to another, creating oppositely charged ions that attract each other. Covalent bonds involve sharing electrons; hydrogen bonds are weak attractions between polar molecules.', true),
  ('GS-PS-B5-9', 'GS', 'gs.physical-science', 4, 'A catalyst speeds up a chemical reaction primarily by:', '["Increasing the temperature of the reactants","Providing energy to break all molecular bonds","Lowering the activation energy required for the reaction","Increasing the concentration of products"]'::jsonb, 2, 'Catalysts provide an alternative reaction pathway with lower activation energy, allowing more reactant molecules to have sufficient energy to react. A catalyst is not consumed and does not change the energy of reactants or products.', true),
  ('GS-PS-B5-10', 'GS', 'gs.physical-science', 4, 'In a neutralization reaction, an acid and a base react to form:', '["Another acid with different strength","Salt and water","Carbon dioxide and oxygen","A metal oxide"]'::jsonb, 1, 'When an acid and a base react, the H⁺ ions from the acid combine with the OH⁻ ions from the base to form water, while the remaining ions form a salt. Example: HCl + NaOH → NaCl + H₂O.', true),
  ('GS-PS-B5-11', 'GS', 'gs.physical-science', 4, 'Which of the following correctly identifies the number of moles in 44 grams of CO₂? (C = 12 g/mol, O = 16 g/mol)', '["0.5 moles","1 mole","2 moles","44 moles"]'::jsonb, 1, 'Molar mass of CO₂ = 12 + (2 × 16) = 44 g/mol. Moles = mass ÷ molar mass = 44 ÷ 44 = 1 mole. This is a foundational stoichiometry relationship: one mole of CO₂ weighs exactly 44 grams.', true),
  ('GS-PS-B5-12', 'GS', 'gs.physical-science', 5, 'In the balanced equation 2H₂ + O₂ → 2H₂O, how many moles of water are produced from 3 moles of H₂ and excess O₂?', '["1.5 moles","2 moles","3 moles","6 moles"]'::jsonb, 2, 'The molar ratio of H₂ to H₂O is 2:2 = 1:1. Therefore 3 moles of H₂ produce 3 moles of H₂O when O₂ is in excess. Dividing by 2 (getting 1.5) misreads the 1:1 ratio.', true),
  ('GS-PS-B5-13', 'GS', 'gs.physical-science', 5, 'Which of the following best explains why noble gases (Group 18) rarely form chemical bonds with other elements?', '["They have very high atomic masses that prevent bonding","They have complete outer electron shells with no tendency to gain or lose electrons","They are radioactive and unstable at normal temperatures","Their electrons orbit so quickly that other atoms cannot bond to them"]'::jsonb, 1, 'Noble gases have full valence electron shells (8 electrons, or 2 for helium), giving them maximum stability. With no need to gain, lose, or share electrons, they have virtually no chemical reactivity. Their stability is electronic, not related to mass or speed.', true),
  ('GS-ES-B5-1', 'GS', 'gs.earth-space-science', 1, 'The layer of Earth that we live on, which makes up the surface and outer crust, is called the:', '["Mantle","Core","Lithosphere","Asthenosphere"]'::jsonb, 2, 'The lithosphere includes Earth''s crust and the uppermost solid part of the mantle — the rigid layer on which continents and ocean floors rest. The mantle is below; the core is the deepest layer.', true),
  ('GS-ES-B5-2', 'GS', 'gs.earth-space-science', 1, 'What causes the seasons on Earth?', '["Earth''s varying distance from the Sun as it orbits","The tilt of Earth''s axis relative to its orbital plane","Changes in the Sun''s energy output throughout the year","The Moon blocking different amounts of sunlight"]'::jsonb, 1, 'Earth''s axis is tilted approximately 23.5° relative to its orbit. This tilt causes one hemisphere to receive more direct sunlight during part of the year (summer) and less during another (winter). Earth''s distance from the Sun varies only slightly and is not the primary cause.', true),
  ('GS-ES-B5-3', 'GS', 'gs.earth-space-science', 2, 'Metamorphic rock is formed when existing rock is subjected to:', '["Rapid cooling of magma at the surface","The compaction of layers of sediment over time","High heat and pressure deep within Earth","Erosion by wind and water"]'::jsonb, 2, 'Metamorphic rocks (marble, slate, quartzite) form when pre-existing rocks are altered by intense heat and pressure without melting. Rapid cooling of magma creates igneous rock; compacted sediment creates sedimentary rock.', true),
  ('GS-ES-B5-4', 'GS', 'gs.earth-space-science', 2, 'The water cycle step in which water vapor cools and changes into liquid water droplets to form clouds is called:', '["Evaporation","Condensation","Precipitation","Transpiration"]'::jsonb, 1, 'Condensation is the process by which water vapor loses heat energy and converts to liquid droplets, forming clouds and fog. Evaporation is the opposite (liquid to vapor); precipitation is water falling from clouds; transpiration is water released by plants.', true),
  ('GS-ES-B5-5', 'GS', 'gs.earth-space-science', 3, 'Which atmospheric layer, positioned just above the stratosphere, is where meteors typically burn up upon entering Earth''s atmosphere?', '["Troposphere","Stratosphere","Mesosphere","Thermosphere"]'::jsonb, 2, 'The mesosphere extends from about 50 to 80 km altitude. The thin air in this layer creates enough friction to burn up most meteors. The troposphere (0–12 km) contains weather; the stratosphere (12–50 km) holds the ozone layer.', true),
  ('GS-ES-B5-6', 'GS', 'gs.earth-space-science', 3, 'According to the rock cycle, which process can convert igneous rock into sedimentary rock?', '["Melting followed by rapid cooling","Heat and pressure deep underground","Weathering, erosion, and compaction of the rock fragments","Volcanic uplift pushing the rock to the surface"]'::jsonb, 2, 'Igneous rock can be broken down by weathering and erosion into sediment. Over time the sediment is deposited, buried, and compacted (lithification) into sedimentary rock. Heat and pressure would produce metamorphic rock, not sedimentary.', true),
  ('GS-ES-B5-7', 'GS', 'gs.earth-space-science', 3, 'At which location would a hurricane most likely begin to weaken significantly?', '["Over warm tropical ocean water","When moving toward the equator","After making landfall or moving over cooler water","When it absorbs a nearby low-pressure system"]'::jsonb, 2, 'Hurricanes are fueled by warm ocean water that evaporates and feeds the storm''s convection. When a hurricane moves over land or cooler water, it loses its energy source and weakens. Warm equatorial water would sustain or intensify the storm.', true),
  ('GS-ES-B5-8', 'GS', 'gs.earth-space-science', 4, 'Which type of plate boundary is associated with the formation of most of Earth''s major mountain ranges?', '["Divergent boundary, where plates move apart","Transform boundary, where plates slide past each other","Convergent boundary, where plates collide and compress","Subduction boundary, where oceanic plates sink under oceanic plates"]'::jsonb, 2, 'Mountain ranges like the Himalayas and Alps form at convergent boundaries where two continental plates collide, compressing and folding the crust upward. Divergent boundaries form rift valleys; transform boundaries produce faults and earthquakes.', true),
  ('GS-ES-B5-9', 'GS', 'gs.earth-space-science', 4, 'As altitude increases in the troposphere, air temperature generally:', '["Increases at a steady rate","Remains constant","Decreases","Increases then decreases"]'::jsonb, 2, 'In the troposphere, temperature decreases with altitude at roughly 6.5°C per 1,000 meters (the environmental lapse rate). This is opposite to the stratosphere, where temperature increases with altitude due to ozone absorbing UV radiation.', true),
  ('GS-ES-B5-10', 'GS', 'gs.earth-space-science', 4, 'A star''s color is most directly related to its:', '["Size","Distance from Earth","Surface temperature","Age in the stellar lifecycle"]'::jsonb, 2, 'A star''s color is determined by its surface temperature: blue-white stars are hottest, yellow stars (like our Sun) are mid-range, and red stars are coolest. Distance affects apparent brightness, not color. Age and size influence temperature but are not the direct cause of color.', true),
  ('GS-ES-B5-11', 'GS', 'gs.earth-space-science', 5, 'Which phenomenon best explains why oceanic crust is generally younger than continental crust?', '["Oceanic crust forms faster due to more volcanic activity on land","Continental crust is recycled through subduction more rapidly","Oceanic crust is continuously created at mid-ocean ridges and destroyed at subduction zones","Tidal forces from the Moon preferentially age continental crust"]'::jsonb, 2, 'Mid-ocean ridges constantly produce new oceanic crust as magma rises and solidifies. This crust spreads outward and is eventually subducted back into the mantle at trenches, completing the cycle. Continental crust is less dense and resists subduction, so it accumulates age.', true),
  ('GS-ES-B5-12', 'GS', 'gs.earth-space-science', 5, 'During a lunar eclipse, the Moon appears reddish because:', '["The Moon reflects red light from nearby stars","Earth''s atmosphere scatters shorter wavelengths and refracts red light onto the Moon","The Moon''s own iron-rich surface reflects at a red wavelength","Sunlight heats the Moon''s surface, causing it to glow red"]'::jsonb, 1, 'During a lunar eclipse, Earth''s atmosphere acts like a lens: it scatters away blue wavelengths but bends (refracts) longer red and orange wavelengths into Earth''s shadow, illuminating the Moon with a reddish glow — the same physics that makes sunsets red.', true),
  ('GS-PM-B5-1', 'GS', 'gs.physics-mechanics', 1, 'Which type of energy does a moving car possess?', '["Chemical energy","Potential energy","Kinetic energy","Nuclear energy"]'::jsonb, 2, 'Kinetic energy is the energy of motion. Any object in motion — a car, a thrown ball, flowing water — possesses kinetic energy. Potential energy is stored energy due to position; chemical energy is stored in molecular bonds.', true),
  ('GS-PM-B5-2', 'GS', 'gs.physics-mechanics', 1, 'A wedge is a type of simple machine. The primary mechanical purpose of a wedge is to:', '["Change the direction of a force along a rope","Multiply rotational force through gears","Convert a downward force into an outward splitting force","Store energy that can be released later"]'::jsonb, 2, 'A wedge converts a driving force (usually downward) into outward forces that split or separate material. Axes and chisels are examples. It is essentially a moving inclined plane.', true),
  ('GS-PM-B5-3', 'GS', 'gs.physics-mechanics', 2, 'When you stretch a rubber band and hold it motionless, it has:', '["Kinetic energy only","No energy because it is not moving","Elastic potential energy","Thermal energy from being stretched"]'::jsonb, 2, 'Stretching a rubber band stores elastic potential energy — energy due to deformation. When released, this potential energy converts to kinetic energy. Thermal energy might increase slightly, but the dominant stored energy is elastic potential.', true),
  ('GS-PM-B5-4', 'GS', 'gs.physics-mechanics', 2, 'Newton''s Second Law states that force equals mass times acceleration (F = ma). If the net force on an object doubles while its mass stays the same, its acceleration will:', '["Stay the same","Double","Quadruple","Decrease by half"]'::jsonb, 1, 'From F = ma, if F doubles and m is constant, a must double to maintain the equality. Acceleration is directly proportional to net force when mass is unchanged.', true),
  ('GS-PM-B5-5', 'GS', 'gs.physics-mechanics', 3, 'A first-class lever has the fulcrum between the effort and the load. Which of the following is an example of a first-class lever?', '["A wheelbarrow","A pair of scissors","A baseball bat","A bottle opener"]'::jsonb, 1, 'Scissors have the fulcrum (pivot pin) between the effort (handles) and the load (cutting blades) — defining a first-class lever. A wheelbarrow is second-class (load between fulcrum and effort); a baseball bat is third-class (effort between fulcrum and load).', true),
  ('GS-PM-B5-6', 'GS', 'gs.physics-mechanics', 3, 'If a 10-kg object is lifted 5 meters, how much gravitational potential energy does it gain? (Use g = 10 m/s²)', '["15 joules","50 joules","500 joules","5,000 joules"]'::jsonb, 2, 'Gravitational PE = mass × g × height = 10 × 10 × 5 = 500 joules. A common error is forgetting to include g and computing 10 × 5 = 50 joules.', true),
  ('GS-PM-B5-7', 'GS', 'gs.physics-mechanics', 3, 'Friction always acts in what direction relative to an object''s motion?', '["Perpendicular to motion","In the same direction as motion","Opposite to the direction of motion","Downward due to gravity"]'::jsonb, 2, 'Friction is a resistive force that always opposes relative motion or the tendency to move. If a box slides right, friction acts leftward on it. This is why friction converts kinetic energy into thermal energy and slows moving objects.', true),
  ('GS-PM-B5-8', 'GS', 'gs.physics-mechanics', 4, 'A 4-kg block slides down a frictionless ramp and reaches the bottom with a speed of 6 m/s. What is its kinetic energy at the bottom?', '["24 joules","48 joules","72 joules","144 joules"]'::jsonb, 2, 'KE = ½mv² = ½ × 4 × 6² = ½ × 4 × 36 = 72 joules. A common error is forgetting the ½, giving 4 × 36 = 144 joules.', true),
  ('GS-PM-B5-9', 'GS', 'gs.physics-mechanics', 4, 'What is the mechanical advantage of a lever when the effort arm is 3 meters and the load arm is 1 meter?', '["0.33","1","3","4"]'::jsonb, 2, 'Mechanical advantage = effort arm length ÷ load arm length = 3 ÷ 1 = 3. This means you can lift a load 3 times heavier than the force you apply. A MA less than 1 would mean the lever puts you at a disadvantage.', true),
  ('GS-PM-B5-10', 'GS', 'gs.physics-mechanics', 5, 'A 2-kg ball is dropped from 20 meters above the ground. At 10 meters height (halfway down), ignoring air resistance, what is its approximate kinetic energy? (g = 10 m/s²)', '["100 joules","200 joules","300 joules","400 joules"]'::jsonb, 1, 'Initial PE at 20 m = mgh = 2 × 10 × 20 = 400 J. At 10 m, remaining PE = 2 × 10 × 10 = 200 J. By conservation of energy, KE gained = 400 − 200 = 200 J. You do not need to calculate velocity separately.', true),
  ('EI-OL-B5-1', 'EI', 'ei.ohms-law-power', 1, 'According to Ohm''s Law, if the voltage across a resistor is 10 volts and the resistance is 5 ohms, the current through the resistor is:', '["0.5 amperes","1 ampere","2 amperes","50 amperes"]'::jsonb, 2, 'Ohm''s Law: I = V ÷ R = 10 ÷ 5 = 2 amperes. Multiplying voltage by resistance (10 × 5 = 50) is the most common error; the formula divides voltage by resistance.', true),
  ('EI-OL-B5-2', 'EI', 'ei.ohms-law-power', 1, 'Electrical power in a circuit is calculated using the formula P = IV. If a device draws 3 amperes from a 12-volt source, its power consumption is:', '["4 watts","9 watts","15 watts","36 watts"]'::jsonb, 3, 'P = I × V = 3 × 12 = 36 watts. Dividing gives 4 (12/3) — a common error confusing the power formula with Ohm''s Law.', true),
  ('EI-OL-B5-4', 'EI', 'ei.ohms-law-power', 2, 'Using P = I²R, what power is dissipated by a 4-ohm resistor carrying 5 amperes?', '["20 watts","40 watts","80 watts","100 watts"]'::jsonb, 3, 'P = I²R = 5² × 4 = 25 × 4 = 100 watts. A common error is computing I × R first (5 × 4 = 20) and forgetting to square the current.', true),
  ('EI-OL-B5-5', 'EI', 'ei.ohms-law-power', 3, 'Four resistors of 10 ohms each are connected in series. What is the total resistance of the circuit?', '["2.5 ohms","10 ohms","40 ohms","1,000 ohms"]'::jsonb, 2, 'Series resistances add directly: R_total = 10 + 10 + 10 + 10 = 40 ohms. Using the parallel formula (1/R_total = 4/10 → 2.5) is a common error when resistances appear equal.', true),
  ('EI-OL-B5-6', 'EI', 'ei.ohms-law-power', 3, 'A 100-watt appliance runs on 200 volts. Using P = V²/R, what is its resistance?', '["2 ohms","50 ohms","400 ohms","20,000 ohms"]'::jsonb, 2, 'P = V²/R → R = V²/P = 200² ÷ 100 = 40,000 ÷ 100 = 400 ohms. First squaring voltage (40,000) then dividing by power is required; simply computing 200/100 = 2 skips the squaring step.', true),
  ('EI-OL-B5-7', 'EI', 'ei.ohms-law-power', 3, 'Three resistors — 2 ohms, 3 ohms, and 5 ohms — are connected in series to a 20-volt battery. What is the current in the circuit?', '["0.5 amperes","1 ampere","2 amperes","4 amperes"]'::jsonb, 2, 'Total series resistance = 2 + 3 + 5 = 10 ohms. Current = V/R = 20/10 = 2 amperes. Using only one resistor (e.g., 20/5 = 4) ignores the others in series.', true),
  ('EI-OL-B5-8', 'EI', 'ei.ohms-law-power', 4, 'A 24-volt source powers three identical resistors connected in parallel. If each resistor is 12 ohms, what is the total current drawn from the source?', '["0.67 amperes","2 amperes","4 amperes","6 amperes"]'::jsonb, 3, 'In parallel, each branch sees the full 24 V. Current in each branch = 24/12 = 2 A. Three branches × 2 A = 6 A total. Alternately: parallel resistance = 12/3 = 4 ohms; total I = 24/4 = 6 A.', true),
  ('EI-OL-B5-9', 'EI', 'ei.ohms-law-power', 4, 'A 10-ohm resistor and a 15-ohm resistor are connected in parallel. What is the combined resistance? (Express your answer as a fraction or decimal.)', '["25 ohms","12.5 ohms","6 ohms","5 ohms"]'::jsonb, 2, '1/R = 1/10 + 1/15 = 3/30 + 2/30 = 5/30 = 1/6, so R = 6 ohms. Adding resistances (25) is the series formula. Averaging (12.5) is not a valid circuit rule. In parallel, result is always less than the smallest individual resistor (10 ohms).', true),
  ('EI-OL-B5-10', 'EI', 'ei.ohms-law-power', 5, 'A series circuit with a 30-volt source contains two resistors: R₁ = 6 ohms and R₂ = 4 ohms. What is the voltage drop across R₁?', '["6 volts","12 volts","18 volts","24 volts"]'::jsonb, 2, 'Total resistance = 6 + 4 = 10 ohms. Current = 30/10 = 3 A. Voltage across R₁ = I × R₁ = 3 × 6 = 18 volts. Voltage drops are proportional to resistance: R₁ is 60% of total, so it takes 60% of 30 V = 18 V. The remaining 12 V appears across R₂.', true),
  ('EI-OL-B5-11', 'EI', 'ei.ohms-law-power', 5, 'A device with 50 ohms of resistance must dissipate exactly 200 watts. What supply voltage is required?', '["10 volts","50 volts","100 volts","4 volts"]'::jsonb, 2, 'P = V²/R → V² = P × R = 200 × 50 = 10,000 → V = √10,000 = 100 volts. Using P = IV requires finding I first: I = √(P/R) = √4 = 2 A, then V = IR = 2 × 50 = 100 V — both routes confirm 100 V.', true),
  ('EI-OL-B5-12', 'EI', 'ei.ohms-law-power', 4, 'If resistance in a circuit doubles while voltage stays constant, what happens to the current?', '["It doubles","It remains the same","It is cut in half","It increases by the square of the resistance"]'::jsonb, 2, 'I = V/R. If R doubles and V is constant, I = V/(2R) — current is halved. Current is inversely proportional to resistance in Ohm''s Law.', true),
  ('EI-CT-B5-1', 'EI', 'ei.circuit-types', 1, 'In a parallel circuit, the voltage across each branch compared to the source voltage is:', '["Less than the source voltage","Equal to the source voltage","Greater than the source voltage","Divided equally among branches"]'::jsonb, 1, 'In a parallel circuit, each branch is connected directly between the same two nodes (the source terminals), so every branch sees the full source voltage. This is the key difference from a series circuit, where voltage is divided.', true),
  ('EI-CT-B5-2', 'EI', 'ei.circuit-types', 1, 'In a series circuit, the current through each component is:', '["Different for each component based on its resistance","The same throughout the entire circuit","Zero if any component has high resistance","Split between components based on their resistance"]'::jsonb, 1, 'A series circuit provides only one path for current flow, so the same current passes through every component. Voltage divides across components in proportion to resistance, but current remains constant.', true),
  ('EI-CT-B5-3', 'EI', 'ei.circuit-types', 2, 'Three light bulbs are connected in parallel to a battery. One bulb burns out (open circuit). What happens to the other two bulbs?', '["They also go out because the circuit is broken","They dim slightly because total resistance decreases","They continue to glow normally","They burn brighter because they now draw more current"]'::jsonb, 2, 'In a parallel circuit, each bulb has its own independent path to the source. A failed bulb opens only its own branch; the remaining branches still carry current normally. This is why home wiring uses parallel circuits.', true),
  ('EI-CT-B5-4', 'EI', 'ei.circuit-types', 2, 'A series circuit with a 9-volt battery and two resistors (3 ohms and 6 ohms) carries a current of 1 ampere. What is the voltage drop across the 6-ohm resistor?', '["1.5 volts","3 volts","6 volts","9 volts"]'::jsonb, 2, 'V = I × R = 1 × 6 = 6 volts across the 6-ohm resistor. The 3-ohm resistor drops 3 volts, and 3 + 6 = 9 V confirms Kirchhoff''s Voltage Law. Using the full 9 volts across one resistor is a common error.', true),
  ('EI-CT-B5-5', 'EI', 'ei.circuit-types', 3, 'Adding more resistors in parallel to an existing circuit will:', '["Increase total resistance and decrease total current","Decrease total resistance and increase total current","Have no effect on total current from the source","Decrease voltage at the source"]'::jsonb, 1, 'Each additional parallel branch creates another current path, reducing total resistance (1/R_total increases). With source voltage constant, lower total resistance means greater total current draw. This is why plugging in more appliances on the same circuit can trip a breaker.', true),
  ('EI-CT-B5-6', 'EI', 'ei.circuit-types', 3, 'In a series circuit, adding a resistor will:', '["Decrease total resistance and increase current","Increase total resistance and decrease current","Keep current the same because voltage adjusts","Only affect the components after it in the circuit"]'::jsonb, 1, 'Series resistances add: total resistance increases. By Ohm''s Law (I = V/R), with voltage constant, higher resistance reduces current throughout the entire series loop — not just after the added resistor.', true),
  ('EI-CT-B5-7', 'EI', 'ei.circuit-types', 3, 'Kirchhoff''s Current Law states that the total current entering a junction in a circuit equals the total current leaving it. This law applies to which circuit type as a core analysis tool?', '["Series circuits only","Open circuits only","Parallel and combination circuits","Only DC battery circuits"]'::jsonb, 2, 'KCL is most useful at nodes (junctions) where current divides — which occurs in parallel and combination circuits. In a simple series circuit, there are no junctions; current never splits, so KCL is trivially satisfied.', true),
  ('EI-CT-B5-8', 'EI', 'ei.circuit-types', 4, 'A circuit has two branches in parallel: Branch A draws 4 amperes and Branch B draws 2 amperes. The source voltage is 12 volts. What is the resistance of Branch B?', '["2 ohms","4 ohms","6 ohms","24 ohms"]'::jsonb, 2, 'In parallel, each branch sees 12 volts. R_B = V/I_B = 12/2 = 6 ohms. Do not add the branch currents before calculating resistance — each branch is analyzed independently with the full source voltage.', true),
  ('EI-CT-B5-9', 'EI', 'ei.circuit-types', 4, 'A switch is placed in the main line of a parallel circuit (before the branches split). If this switch is opened, what happens?', '["Only the first branch loses power","All branches lose power simultaneously","Branches alternate between on and off","The branch with the highest resistance loses power first"]'::jsonb, 1, 'A switch in the main line controls current to the entire parallel section. Opening it breaks the only path for current before it can split into branches, cutting power to all branches simultaneously — the same principle as the main breaker in a home.', true),
  ('EI-CT-B5-10', 'EI', 'ei.circuit-types', 4, 'A combination circuit has a 2-ohm resistor in series with a parallel combination of a 4-ohm and 4-ohm resistor. What is the total circuit resistance?', '["10 ohms","6 ohms","4 ohms","2 ohms"]'::jsonb, 2, 'Two 4-ohm resistors in parallel: R_parallel = 4/2 = 2 ohms. Total = series 2 ohms + parallel 2 ohms = 4 ohms. Adding all three directly (2 + 4 + 4 = 10) ignores the parallel arrangement.', true),
  ('EI-CT-B5-11', 'EI', 'ei.circuit-types', 5, 'In a series circuit with a 48-volt source and three resistors (R₁ = 8 Ω, R₂ = 4 Ω, R₃ = 4 Ω), what percentage of the source voltage appears across R₁?', '["25%","33%","50%","75%"]'::jsonb, 2, 'Total resistance = 8 + 4 + 4 = 16 Ω. Current = 48/16 = 3 A. Voltage across R₁ = 3 × 8 = 24 V. Percentage = 24/48 × 100 = 50%. Alternatively, R₁ is 8/16 = 50% of total resistance, so it captures 50% of the voltage.', true),
  ('EI-CT-B5-12', 'EI', 'ei.circuit-types', 5, 'Two batteries, each 6 volts with internal resistance of 1 ohm, are connected in series and power a 10-ohm external load. What is the current through the load?', '["0.5 amperes","1 ampere","1.2 amperes","2 amperes"]'::jsonb, 1, 'Total voltage = 6 + 6 = 12 V. Total resistance = 1 + 1 + 10 = 12 Ω (internal resistances add in series). Current = 12/12 = 1 ampere. Ignoring internal resistance gives 12/10 = 1.2 A — a common error on multi-battery problems.', true),
  ('EI-CD-B5-1', 'EI', 'ei.components-devices', 1, 'A capacitor in an electrical circuit primarily functions to:', '["Amplify the voltage in the circuit","Allow current to flow in one direction only","Store electrical energy in an electric field","Convert AC to DC"]'::jsonb, 2, 'A capacitor stores energy in an electric field between two conductive plates separated by an insulator (dielectric). It charges when voltage is applied and releases that energy when the circuit demands. A diode, not a capacitor, allows one-directional current flow.', true),
  ('EI-CD-B5-2', 'EI', 'ei.components-devices', 1, 'A resistor is used in an electrical circuit mainly to:', '["Store charge for later use","Limit the amount of current flowing through a component","Convert AC voltage to DC voltage","Step up or step down voltage levels"]'::jsonb, 1, 'Resistors oppose current flow (resistance measured in ohms) and limit current according to Ohm''s Law. Capacitors store charge; rectifiers convert AC to DC; transformers change voltage levels.', true),
  ('EI-CD-B5-3', 'EI', 'ei.components-devices', 2, 'An inductor stores energy in a:', '["Chemical battery cell","Magnetic field","Electric field between plates","Mechanical flywheel"]'::jsonb, 1, 'An inductor (a coil of wire) stores energy in the magnetic field created by current flowing through it. Capacitors store energy in an electric field; batteries in chemical form. The inductor resists changes in current.', true),
  ('EI-CD-B5-4', 'EI', 'ei.components-devices', 2, 'Which device is used to step up or step down alternating current voltage levels in power distribution systems?', '["Rectifier","Transistor","Transformer","Capacitor"]'::jsonb, 2, 'Transformers use electromagnetic induction to change AC voltage levels. Power companies step up voltage for long-distance transmission to reduce energy loss, then step it back down for home use. Rectifiers convert AC to DC; transistors amplify or switch signals.', true),
  ('EI-CD-B5-5', 'EI', 'ei.components-devices', 3, 'A light-emitting diode (LED) converts electrical energy primarily into:', '["Heat and mechanical energy equally","Light energy with minimal heat","Chemical energy stored in a capacitor","Alternating current from direct current"]'::jsonb, 1, 'LEDs convert electrical energy into light through electroluminescence in a semiconductor junction. They are far more efficient than incandescent bulbs, which waste most energy as heat. LEDs do not convert AC to DC or store chemical energy.', true),
  ('EI-CD-B5-6', 'EI', 'ei.components-devices', 3, 'A transistor can be used as an electronic switch because it can:', '["Block all current from flowing in either direction","Store charge and release it on command","Control a large output current with a small input (base) current","Convert AC to DC by allowing current in one direction only"]'::jsonb, 2, 'In a transistor (BJT), a small current at the base terminal controls a much larger current between collector and emitter — enabling amplification and switching. When base current is zero, the transistor is off (open switch); when sufficient, it is on (closed switch).', true),
  ('EI-CD-B5-7', 'EI', 'ei.components-devices', 3, 'Which component would most likely be used to filter out high-frequency noise from a DC power supply while allowing the steady DC current to pass?', '["A resistor in series","A capacitor in parallel with the load","A diode in reverse bias","An additional battery"]'::jsonb, 1, 'Capacitors pass AC (and AC noise) but block steady DC. Placing one in parallel with the load creates a low-impedance path for high-frequency noise to bypass the load while the desired DC current continues through. This is called decoupling or bypass capacitor usage.', true),
  ('EI-CD-B5-8', 'EI', 'ei.components-devices', 4, 'A transformer has 200 turns on its primary and 50 turns on its secondary. If the primary carries 1 ampere, what is the secondary current (assuming 100% efficiency)?', '["0.25 amperes","1 ampere","4 amperes","10 amperes"]'::jsonb, 2, 'For an ideal transformer, power is conserved: Vp × Ip = Vs × Is. The turns ratio Np/Ns = 200/50 = 4, so the transformer steps down voltage by 4 and steps up current by 4: Is = Ip × (Np/Ns) = 1 × 4 = 4 amperes.', true),
  ('EI-CD-B5-9', 'EI', 'ei.components-devices', 4, 'A Zener diode is connected in reverse bias in a circuit. Its primary application is to:', '["Block all current completely in that branch","Amplify voltage to a higher level","Regulate voltage by maintaining a constant voltage drop","Convert AC to DC in a rectifier bridge"]'::jsonb, 2, 'Zener diodes are designed to conduct in reverse bias once voltage reaches their Zener breakdown voltage, clamping the voltage to a stable reference level. They are used in voltage regulators to protect sensitive components from voltage spikes.', true),
  ('EI-CD-B5-10', 'EI', 'ei.components-devices', 4, 'Which effect describes how an inductor resists changes in current by generating a back-EMF (electromotive force)?', '["Capacitance","Self-inductance","Dielectric effect","Zener breakdown"]'::jsonb, 1, 'Self-inductance (measured in henries) is the property of a coil to oppose changes in current by inducing a voltage that opposes the change — Faraday''s Law in action. Capacitance opposes voltage changes; dielectric effect describes insulator behavior in capacitors.', true),
  ('EI-CD-B5-11', 'EI', 'ei.components-devices', 5, 'A full-wave bridge rectifier using four diodes converts AC to pulsating DC. Compared to a half-wave rectifier (one diode), the bridge rectifier:', '["Doubles the output voltage","Uses both halves of the AC cycle, producing smoother DC output at twice the frequency","Reverses the polarity of the DC output","Requires a transformer, whereas the half-wave rectifier does not"]'::jsonb, 1, 'A half-wave rectifier passes only one half-cycle of the AC input, wasting the other half. The bridge rectifier flips the negative half-cycle to positive using a diode arrangement, utilizing both halves. The output pulsates at twice the AC frequency and is smoother (easier to filter). Voltage is not doubled.', true),
  ('EI-CD-B5-12', 'EI', 'ei.components-devices', 5, 'In a radio receiver circuit, an LC (inductor-capacitor) tank circuit is used primarily to:', '["Amplify received signals across all frequencies equally","Convert radio waves into alternating current","Select a specific resonant frequency and filter out others","Step down the antenna voltage before processing"]'::jsonb, 2, 'An LC tank circuit resonates at a specific frequency f = 1/(2π√LC), creating high impedance at that frequency and low impedance at others. Adjusting L or C (tuning) selects a desired station. The circuit is a tunable bandpass filter, not an amplifier or antenna converter.', true),
  ('EI-CI-B5-1', 'EI', 'ei.conductors-insulators', 1, 'Which of the following materials is the best electrical insulator?', '["Aluminum","Graphite","Silver","Ceramic"]'::jsonb, 3, 'Ceramic (and glass, rubber, plastic) are insulators — they have very high electrical resistance and prevent current flow. Aluminum, graphite, and silver are all conductors. Ceramic is used for electrical insulators on power lines.', true),
  ('EI-CI-B5-2', 'EI', 'ei.conductors-insulators', 1, 'Electrical wiring is typically covered in a plastic jacket primarily because plastic is:', '["A good conductor that improves current flow","Flexible, cheap, and an effective insulator","A semiconductor that limits dangerous voltage spikes","A material that cools the wire during use"]'::jsonb, 1, 'Plastic (PVC and similar polymers) insulates by preventing current from escaping the conductor and causing short circuits or shock hazards. Its flexibility and low cost make it ideal for wire jacketing. Plastic does not conduct or regulate electricity.', true),
  ('EI-CI-B5-3', 'EI', 'ei.conductors-insulators', 2, 'Gold is used in some high-quality electrical connectors despite its high cost because:', '["Gold has higher conductivity than any other metal","Gold is non-corrosive and maintains low contact resistance over time","Gold''s weight improves mechanical connection strength","Gold stores electrical charge better than copper"]'::jsonb, 1, 'Gold does not oxidize (corrode), so gold-plated connectors maintain reliable, low-resistance electrical contact over time. Silver and copper have higher conductivity but corrode, increasing contact resistance. Weight provides no electrical benefit.', true),
  ('EI-CI-B5-4', 'EI', 'ei.conductors-insulators', 2, 'When the temperature of most metals increases, their electrical resistance:', '["Decreases because the electrons move faster","Stays the same regardless of temperature","Increases because atomic vibrations impede electron flow","Drops to zero because the metal becomes a superconductor"]'::jsonb, 2, 'As metal temperature rises, atoms vibrate more vigorously, creating more collisions that impede electron movement — increasing resistance. Superconductivity (zero resistance) occurs only at extremely low temperatures in certain materials, not at room temperature.', true),
  ('EI-CI-B5-5', 'EI', 'ei.conductors-insulators', 3, 'Silicon is classified as a semiconductor because its conductivity:', '["Is equal to that of copper at all temperatures","Can be precisely controlled by temperature, light, or the addition of impurities (doping)","Is zero until voltage exceeds a fixed threshold","Depends only on the current direction, like a diode"]'::jsonb, 1, 'Semiconductors occupy the middle ground between conductors and insulators. Silicon''s conductivity is tunable: doping with phosphorus adds free electrons (n-type) and doping with boron adds holes (p-type), enabling transistors and diodes. Pure silicon is a poor conductor at room temperature.', true),
  ('EI-CI-B5-6', 'EI', 'ei.conductors-insulators', 3, 'The dielectric in a capacitor is an insulating material placed between the plates. Its primary purpose is to:', '["Allow electrons to tunnel between the plates and store charge","Increase the capacitance by allowing a stronger electric field to build up","Convert stored energy into heat for circuit protection","Conduct alternating current while blocking direct current"]'::jsonb, 1, 'The dielectric material has a high permittivity that allows the capacitor to store more charge for a given voltage, increasing capacitance (C = ε × A/d). The insulator prevents electrons from crossing between plates; charge is stored in the electric field, not by electron transfer.', true),
  ('EI-CI-B5-7', 'EI', 'ei.conductors-insulators', 3, 'An electrical wire''s resistance depends on which of the following properties?', '["Only the length of the wire","Length, cross-sectional area, and material resistivity","Cross-sectional area and the voltage applied","The current passing through it at any given moment"]'::jsonb, 1, 'Wire resistance R = ρ × L / A, where ρ is material resistivity, L is length, and A is cross-sectional area. Longer, thinner wire of more resistive material has higher resistance. Applied voltage and current are results of resistance, not causes of it.', true),
  ('EI-CI-B5-8', 'EI', 'ei.conductors-insulators', 4, 'Two copper wires are identical in length. Wire A has twice the cross-sectional area of Wire B. How does the resistance of Wire A compare to Wire B?', '["Wire A has twice the resistance of Wire B","Wire A has the same resistance as Wire B","Wire A has half the resistance of Wire B","Wire A has four times the resistance of Wire B"]'::jsonb, 2, 'R = ρL/A. Since A_A = 2 × A_B, R_A = ρL/(2 × A_B) = R_B/2. Doubling the cross-sectional area halves the resistance — the wire provides more parallel paths for electrons.', true),
  ('EI-CI-B5-9', 'EI', 'ei.conductors-insulators', 4, 'Which statement correctly explains why copper is preferred over iron for electrical wiring despite iron being more abundant?', '["Copper has a lower melting point, making it easier to form into wire","Copper has much lower resistivity than iron, meaning less energy is lost as heat","Copper is magnetic, which helps carry alternating current","Iron corrodes rapidly in air, and copper does not oxidize at all"]'::jsonb, 1, 'Copper''s resistivity (~1.68 μΩ·cm) is about six times lower than iron''s (~10 μΩ·cm), so copper wire wastes far less energy as heat. This efficiency advantage outweighs the cost difference. Copper does oxidize slightly but forms a stable, low-resistance patina; iron rusts severely.', true),
  ('EI-CI-B5-10', 'EI', 'ei.conductors-insulators', 5, 'A 10-meter copper wire has a resistance of 0.2 ohms. If the wire is replaced with a 20-meter wire of the same material and the same cross-sectional area, what is the new resistance?', '["0.1 ohms","0.2 ohms","0.4 ohms","0.8 ohms"]'::jsonb, 2, 'R = ρL/A. Doubling the length (while keeping area and material constant) doubles the resistance: 2 × 0.2 = 0.4 ohms. Halving length would halve resistance (0.1 ohms); neither area change nor a squared relationship applies here.', true),
  ('EI-CI-B5-11', 'EI', 'ei.conductors-insulators', 5, 'N-type semiconductor material is created by doping silicon with an element that has more valence electrons than silicon. Which of the following dopants creates an n-type semiconductor?', '["Boron (3 valence electrons)","Aluminum (3 valence electrons)","Phosphorus (5 valence electrons)","Carbon (4 valence electrons)"]'::jsonb, 2, 'Silicon has 4 valence electrons. Adding phosphorus (5 valence electrons) provides one extra electron per dopant atom — these free electrons become the majority charge carriers, creating an n-type (negative carrier) semiconductor. Boron and aluminum have only 3 valence electrons and create p-type material by introducing electron holes.', true),
  ('EI-CI-B5-12', 'EI', 'ei.conductors-insulators', 4, 'Which of the following most accurately describes why distilled water is a poor conductor while seawater conducts electricity well?', '["Seawater contains more hydrogen, which improves conductivity","Distilled water has no dissolved ions, while seawater''s dissolved salts provide free ions that carry charge","Distilled water molecules resist current because of their polarity","The pressure of the ocean compresses seawater, increasing conductivity"]'::jsonb, 1, 'Electrical conduction in liquids requires free charge carriers. Distilled water has virtually no ions, so it conducts poorly. Dissolved salts (NaCl, MgCl₂, etc.) ionize in seawater, providing Na⁺, Cl⁻, Mg²⁺ ions that carry charge — making seawater a reasonable conductor.', true),
  ('AS-HT-B6-1', 'AS', 'as.hand-tools', 1, 'Which hand tool is used to tighten or loosen nuts and bolts and has an opening that can be adjusted to fit different fastener sizes?', '["Adjustable wrench","Needle-nose pliers","Cold chisel","Ball-peen hammer"]'::jsonb, 0, 'An adjustable wrench (crescent wrench) has a movable jaw that can be set to grip different fastener sizes. Pliers grip by pressure rather than fitting a hex shape, so they risk rounding fastener corners.', true),
  ('AS-HT-B6-2', 'AS', 'as.hand-tools', 1, 'A mechanic needs to grip a round pipe firmly while cutting threads onto it. Which tool is designed specifically to hold cylindrical workpieces without slipping?', '["Slip-joint pliers","Pipe wrench","Box-end wrench","Offset screwdriver"]'::jsonb, 1, 'A pipe wrench has serrated, self-tightening jaws angled so that applying torque causes them to bite harder into the cylinder. Box-end and open-end wrenches are designed for hex fasteners, not round stock.', true),
  ('AS-HT-B6-3', 'AS', 'as.hand-tools', 2, 'A torque wrench is used instead of a standard socket wrench when:', '["you need to reach fasteners in deep recesses","tightening fasteners to a precise torque specification is required","the fastener head is stripped and will not grip","you are working in a tight space and need a ratcheting motion"]'::jsonb, 1, 'A torque wrench applies a measured, calibrated twisting force to a fastener. This is critical for engine head bolts, wheel lug nuts, and other joints where over- or under-tightening causes failure. A standard ratchet cannot measure torque.', true),
  ('AS-HT-B6-4', 'AS', 'as.hand-tools', 2, 'What is the primary purpose of a center punch when working with metal?', '["To scribe a straight line across the workpiece","To mark a starting point so a drill bit does not wander","To remove burrs from a drilled hole","To cut a hole in sheet metal without a drill"]'::jsonb, 1, 'A center punch creates a small indentation at the exact drilling location. This dimple seats the tip of the drill bit and prevents it from skating across the smooth metal surface as drilling begins.', true),
  ('AS-HT-B6-5', 'AS', 'as.hand-tools', 2, 'A technician selects a drill bit with a twist-style cutting flute and a 118-degree included angle tip. This bit is best suited for drilling:', '["concrete and masonry","general-purpose holes in steel or aluminum","glass and ceramic tile","large-diameter holes in wood only"]'::jsonb, 1, 'A standard high-speed steel (HSS) twist drill with a 118-degree point is the general-purpose choice for metals like steel and aluminum. Masonry bits have a carbide tip; glass bits require a spear-point or diamond tip.', true),
  ('AS-HT-B6-6', 'AS', 'as.hand-tools', 3, 'A vise-grip (locking pliers) differs from standard slip-joint pliers in that a vise-grip:', '["can be used as a wrench on hex fasteners only","locks onto a workpiece and maintains clamping force without the user squeezing","is used exclusively for cutting wire","adjusts automatically to the size of the fastener"]'::jsonb, 1, 'Locking pliers have an over-center mechanism: once the jaws are clamped, the linkage locks and the tool maintains grip without hand pressure. This frees the user''s hands and applies constant clamping force — useful for holding, bending, and removing stripped fasteners.', true),
  ('AS-HT-B6-7', 'AS', 'as.hand-tools', 3, 'A combination square is primarily used to:', '["apply torque to hex fasteners in tight spaces","measure and mark 90-degree and 45-degree angles on a workpiece","hold a workpiece in place during cutting","thread bolts onto nuts in hard-to-reach locations"]'::jsonb, 1, 'A combination square consists of a rule and a sliding head that provides both 90-degree and 45-degree reference angles. It is used to mark cut lines, check squareness, and verify miters. It does not apply torque or hold workpieces.', true),
  ('AS-HT-B6-8', 'AS', 'as.hand-tools', 3, 'A snap-ring pliers set includes two types of tips. One type spreads a ring outward to remove an external snap ring; the other type squeezes a ring inward to remove an internal snap ring. Why must the correct type be used?', '["Using the wrong type will damage the pliers'' handles","Using the wrong type moves the ring in the wrong direction and can launch it unexpectedly or distort it","Both types are interchangeable; choice depends only on ring size","The wrong type will strip the threading on the fastener"]'::jsonb, 1, 'External snap rings are compressed to fit into a shaft groove; internal rings are expanded to fit inside a bore groove. Using expanding pliers on an external ring — or compressing pliers on an internal ring — pushes the ring the wrong way, risking sudden release and possible injury or ring damage.', true),
  ('AS-HT-B6-9', 'AS', 'as.hand-tools', 4, 'A mechanic describes a tool as having a T-shaped handle, with a square drive that accepts interchangeable sockets, and a ratcheting pawl that allows rotation in one direction without removing the tool from the fastener. What tool is being described?', '["Breaker bar","Speed handle","Ratchet wrench","Flex-head torque wrench"]'::jsonb, 2, 'A ratchet wrench has a reversible ratcheting mechanism that lets the user turn the handle back without moving the fastener, then apply torque again on the next forward stroke. A breaker bar provides high torque but does not ratchet; a speed handle spins freely but also lacks a ratchet pawl.', true),
  ('AS-HT-B6-10', 'AS', 'as.hand-tools', 4, 'When measuring a shaft''s outside diameter, a technician reads a micrometer thimble scale and finds the sleeve reading is 0.350 inches and the thimble adds 0.012 inches. What is the total measured diameter?', '["0.338 inches","0.350 inches","0.362 inches","0.412 inches"]'::jsonb, 2, 'A micrometer reading combines the barrel (sleeve) measurement and the thimble graduation. Total = 0.350 + 0.012 = 0.362 inches. Subtracting instead of adding (0.350 − 0.012 = 0.338) is a common error; the thimble always adds to the sleeve reading.', true),
  ('AS-HT-B6-11', 'AS', 'as.hand-tools', 4, 'A technician wants to cut an external thread onto a steel rod so a nut can be threaded onto it. Which hand tool accomplishes this?', '["Tap","Die","Reamer","Broach"]'::jsonb, 1, 'A die cuts external threads onto a rod or bolt. A tap cuts internal threads inside a hole (to accept a bolt). A reamer smooths and sizes a drilled hole to a precise diameter but does not cut threads.', true),
  ('AS-HT-B6-12', 'AS', 'as.hand-tools', 5, 'A star-pattern torque sequence is specified when installing a cylinder head. Why is this sequence used instead of tightening bolts in order from one end to the other?', '["To finish faster by tightening the center bolts last","To distribute clamping load evenly and prevent the gasket from warping or sealing unevenly","Because cylinder head bolts are left-hand threaded on alternating positions","To allow the bolts to be re-tightened after the engine warms up"]'::jsonb, 1, 'A star (criss-cross) pattern draws the head down against the gasket from the center outward in a balanced way. Tightening sequentially from one end pulls that end tight first, which can bow the head or create uneven gasket compression that leads to leaks.', true),
  ('AS-HT-B6-13', 'AS', 'as.hand-tools', 5, 'A feeler gauge (thickness gauge) is used to check the valve clearance in an engine. The technician inserts two blades: a 0.006-inch blade slides with slight drag; a 0.007-inch blade will not enter the gap. What does this tell the technician?', '["The clearance is exactly 0.006 inches","The clearance is between 0.006 and 0.007 inches","The clearance is less than 0.006 inches","The clearance is greater than 0.007 inches"]'::jsonb, 1, 'A feeler gauge works by go/no-go logic. The 0.006-inch blade fits (gap is at least 0.006 in), but the 0.007-inch blade does not fit (gap is less than 0.007 in). Therefore the clearance lies between 0.006 and 0.007 inches.', true),
  ('AS-VS-B6-1', 'AS', 'as.vehicle-systems', 1, 'In a four-stroke gasoline engine, which stroke draws the air-fuel mixture into the cylinder?', '["Compression stroke","Power stroke","Intake stroke","Exhaust stroke"]'::jsonb, 2, 'The four strokes in order are: intake (piston moves down, drawing in air-fuel mixture), compression (piston moves up, compressing the mixture), power (spark ignites mixture, piston pushed down), and exhaust (piston moves up, pushing burnt gases out).', true),
  ('AS-VS-B6-2', 'AS', 'as.vehicle-systems', 1, 'The purpose of a vehicle''s clutch in a manual transmission is to:', '["regulate engine idle speed","temporarily disconnect the engine from the transmission to allow gear changes","convert the alternator''s output to DC current","control the flow of coolant to the engine block"]'::jsonb, 1, 'The clutch uses friction plates to engage and disengage the engine from the transmission. Pressing the clutch pedal separates the plates, allowing the driver to shift gears without grinding. Releasing the pedal reconnects engine power to the drivetrain.', true),
  ('AS-VS-B6-3', 'AS', 'as.vehicle-systems', 2, 'What is the function of a vehicle''s differential?', '["It filters fuel before it reaches the injectors","It allows the drive wheels to rotate at different speeds when turning","It regulates the voltage output of the charging system","It compresses refrigerant in the air conditioning system"]'::jsonb, 1, 'When a vehicle turns, the outer wheel must travel a larger arc than the inner wheel and therefore must rotate faster. The differential uses a planetary gear set to allow the two drive wheels to spin at different speeds while still receiving engine torque.', true),
  ('AS-VS-B6-4', 'AS', 'as.vehicle-systems', 2, 'A vehicle''s battery provides current to start the engine. Once the engine is running, which component keeps the battery charged?', '["Starter motor","Distributor","Alternator","Voltage regulator only"]'::jsonb, 2, 'The alternator is driven by a belt from the engine crankshaft and generates AC electricity, which is converted to DC to recharge the battery and power electrical loads while the engine runs. The starter is only used during cranking.', true),
  ('AS-VS-B6-5', 'AS', 'as.vehicle-systems', 3, 'Disc brakes use calipers and rotors. When the brake pedal is pressed, what converts pedal force into hydraulic pressure that actuates the calipers?', '["The brake booster","The master cylinder","The proportioning valve","The ABS modulator"]'::jsonb, 1, 'The master cylinder converts the mechanical force of the brake pedal (often amplified by a vacuum booster) into hydraulic pressure in the brake lines. This pressure pushes caliper pistons outward to clamp the pads against the rotor.', true),
  ('AS-VS-B6-6', 'AS', 'as.vehicle-systems', 3, 'Engine oil pressure drops to near zero while the engine is running at highway speed. The FIRST action should be to:', '["Continue driving to the nearest service station","Shut off the engine immediately to prevent catastrophic bearing damage","Add oil while the engine is running","Rev the engine to increase oil pump speed"]'::jsonb, 1, 'Oil pressure lubricates engine bearings and prevents metal-to-metal contact. Near-zero pressure means bearings are running dry; continued operation causes scoring and seizure within seconds. Shutting off the engine immediately is the correct response.', true),
  ('AS-VS-B6-7', 'AS', 'as.vehicle-systems', 3, 'An automatic transmission uses a torque converter instead of a clutch. The torque converter:', '["mechanically locks the engine to the transmission at all times","uses hydraulic fluid to transfer and multiply torque between engine and transmission","shifts gears by means of a centrifugal governor","replaces the differential in front-wheel-drive vehicles"]'::jsonb, 1, 'The torque converter is a fluid coupling filled with transmission fluid. The engine drives a pump impeller; fluid motion spins a turbine connected to the transmission input shaft. At low speeds the fluid also provides torque multiplication, acting like a variable gear reduction.', true),
  ('AS-VS-B6-8', 'AS', 'as.vehicle-systems', 4, 'A vehicle''s temperature gauge climbs into the red zone. Steam is seen coming from under the hood. The MOST likely cause is:', '["A low transmission fluid level","A burst radiator hose or failed thermostat causing coolant loss","An overcharged battery","A stuck-open EGR valve"]'::jsonb, 1, 'Steam and a rising temperature gauge together indicate coolant is escaping and the engine is no longer being cooled. The most common culprits are a burst hose, blown head gasket, or failed thermostat that traps coolant in the block. Low transmission fluid causes shifting problems, not overheating steam.', true),
  ('AS-VS-B6-9', 'AS', 'as.vehicle-systems', 4, 'A fuel-injected engine uses an oxygen sensor (O2 sensor) in the exhaust stream. The engine control module (ECM) uses the O2 sensor signal to:', '["determine ignition timing advance based on knock","adjust the fuel injector pulse width to maintain the proper air-fuel ratio","regulate alternator output voltage","control cooling fan speed based on engine temperature"]'::jsonb, 1, 'The O2 sensor measures oxygen content in exhaust gases, which indicates whether combustion was rich (too much fuel) or lean (too little fuel). The ECM uses this feedback in a closed-loop system to trim injector on-time (pulse width) and keep the mixture near stoichiometric (14.7:1 air-to-fuel ratio).', true),
  ('AS-VS-B6-10', 'AS', 'as.vehicle-systems', 4, 'A front-wheel-drive vehicle clicks loudly when turning at low speed but is quiet when driving straight. The most likely cause is:', '["A worn constant-velocity (CV) joint","Low power-steering fluid","A cracked brake rotor","A loose exhaust heat shield"]'::jsonb, 0, 'CV joints allow the drive axle to transmit power through a range of angles as the front wheels turn and move with suspension travel. When a CV joint''s boot tears and loses grease, the joint wears and produces a clicking or popping noise that is loudest during sharp, low-speed turns.', true),
  ('AS-VS-B6-11', 'AS', 'as.vehicle-systems', 5, 'A technician notices that the engine temperature rises quickly to normal then a short time later climbs well above normal, cools slightly, then rises again in a repeating cycle. The MOST likely cause is:', '["A clogged catalytic converter","A thermostat that is stuck partially open, cycling the engine through warm-cool oscillations","A blown head gasket allowing combustion gases into the cooling system","A faulty coolant temperature sensor sending erratic signals to the ECM"]'::jsonb, 2, 'A blown head gasket allows combustion gases (under high pressure) to enter the cooling system. These gases displace coolant, form pockets that reduce cooling efficiency, and can cause the temperature to cycle as coolant is intermittently lost and returned. A stuck thermostat causes persistent overheating or chronic under-temperature, not cycling. A faulty sensor changes gauge readings but not actual temperature.', true),
  ('AS-VS-B6-12', 'AS', 'as.vehicle-systems', 5, 'An engine knocks heavily under load but the knock nearly disappears at idle. This is most consistent with:', '["A cracked flywheel","Pre-ignition (detonation) caused by low-octane fuel or advanced timing","A broken engine mount","An air leak in the intake manifold"]'::jsonb, 1, 'Detonation (knock or ping) occurs when the air-fuel mixture ignites spontaneously before the spark plug fires, causing a shock wave inside the cylinder. It is most pronounced under load when cylinder pressures and temperatures are high, and nearly absent at light-throttle idle. Low-octane fuel, carbon deposits causing hot spots, or over-advanced ignition timing are common causes.', true),
  ('AS-SS-B6-1', 'AS', 'as.shop-safety', 1, 'When working in a shop where gasoline or solvent vapors may be present, adequate ventilation is required primarily to:', '["keep tools at the correct operating temperature","prevent accumulation of flammable vapors that could ignite","ensure that paint dries faster","reduce humidity that causes rust on tools"]'::jsonb, 1, 'Gasoline, solvent, and similar vapors are heavier than air and collect at floor level. In an enclosed, unventilated space they can reach explosive concentrations. Proper ventilation dilutes vapors below their lower explosive limit, preventing ignition.', true),
  ('AS-SS-B6-2', 'AS', 'as.shop-safety', 1, 'A small Class B fire breaks out in the shop. Class B fires involve flammable liquids such as gasoline or oil. Which type of extinguisher is appropriate?', '["Water extinguisher","Class A dry extinguisher","CO2 or dry chemical extinguisher rated for Class B","Any available extinguisher regardless of rating"]'::jsonb, 2, 'Water on a flammable-liquid (Class B) fire can spread burning fuel and make the fire worse. CO2 smothers the fire by displacing oxygen; dry chemical extinguishers interrupt the chemical chain reaction. Both are rated for Class B fires.', true),
  ('AS-SS-B6-3', 'AS', 'as.shop-safety', 2, 'Lockout/tagout (LOTO) procedures are required before performing maintenance on a machine. The PRIMARY purpose of LOTO is to:', '["document the maintenance procedure for quality records","prevent the machine from being energized while a worker is inside or working on it","notify supervisors that the equipment is being serviced","ensure tools are returned to their correct storage locations"]'::jsonb, 1, 'LOTO procedures physically lock energy-isolation devices (circuit breakers, valves) in the off position and attach a tag. This prevents the machine from being accidentally energized while a worker''s hands or body are in a dangerous position inside the equipment.', true),
  ('AS-SS-B6-4', 'AS', 'as.shop-safety', 2, 'A shop worker spills a small amount of motor oil on the floor. The safest IMMEDIATE action is to:', '["Mark the spill with a cone and clean it up at the end of the shift","Spread sawdust or absorbent material and clean it up promptly","Wipe it with a rag and place the rag in an open trash can","Pour water over the spill to dilute it"]'::jsonb, 1, 'An oil spill is a slip hazard and must be cleaned up immediately. Oil-absorbent compound (or sawdust) draws up the liquid; the material is then swept and disposed of properly. Leaving it until shift end risks falls; oily rags in open trash cans can spontaneously combust.', true),
  ('AS-SS-B6-5', 'AS', 'as.shop-safety', 3, 'A worker is grinding metal and is producing sparks and metal fragments. Besides eye protection, what additional PPE should be worn?', '["Latex examination gloves and a dust mask","Face shield over safety glasses, leather gloves, and hearing protection","Safety glasses only — sparks are not hazardous at short range","Chemical-splash goggles and a rubber apron"]'::jsonb, 1, 'Grinding produces sparks (burn hazard), metal fragments (impact hazard), and loud noise (hearing hazard). A full face shield over safety glasses provides both impact and burn protection for the face; leather gloves protect hands from sharp edges and heat; hearing protection guards against noise-induced damage.', true),
  ('AS-SS-B6-6', 'AS', 'as.shop-safety', 3, 'Before lifting a vehicle with a floor jack to work underneath it, you MUST also:', '["Remove the wheels first to reduce vehicle weight","Place jack stands under the vehicle''s frame or pinch-weld points to support it","Set the parking brake and leave the floor jack as the only support","Run the engine for 10 minutes to warm the oil before working"]'::jsonb, 1, 'A floor (hydraulic) jack can fail due to seal leakage or accidental contact. Jack stands are rigid mechanical supports that prevent the vehicle from dropping onto a person working beneath it. Never rely on a jack alone as the sole support for a vehicle you are working under.', true),
  ('AS-SS-B6-7', 'AS', 'as.shop-safety', 3, 'Oily rags used for wiping up solvent or paint should be stored in a:', '["Cardboard box kept away from windows","Sealed metal container approved for flammable waste","Plastic bin lined with a trash bag","Open drum to allow vapors to escape"]'::jsonb, 1, 'Oils and solvents soaked into rags can oxidize and generate heat through spontaneous combustion. A sealed metal container limits oxygen supply and contains any fire that starts. Plastic bins can melt; open drums allow vapor to accumulate and ignite.', true),
  ('AS-SS-B6-8', 'AS', 'as.shop-safety', 4, 'A worker is about to use a bench grinder and notices that the grinding wheel has a small crack running from the center outward. The correct action is to:', '["Run it at low speed only to avoid spreading the crack","Replace the wheel immediately; a cracked wheel can shatter at high RPM","Apply epoxy to the crack and allow it to cure before use","Use the wheel on the side face rather than the rim to avoid the crack"]'::jsonb, 1, 'A cracked abrasive wheel can explode at operating RPM, sending fragments outward with great force. Any crack, chip, or damage is grounds for immediate replacement. Running it at lower speed or using the side face does not eliminate the risk of sudden catastrophic failure.', true),
  ('AS-SS-B6-9', 'AS', 'as.shop-safety', 4, 'Which class of fire involves energized electrical equipment?', '["Class A","Class B","Class C","Class D"]'::jsonb, 2, 'Class C fires involve energized electrical equipment. Class A covers ordinary combustibles (wood, paper); Class B covers flammable liquids; Class D covers combustible metals. For Class C fires, use a non-conductive extinguishing agent (CO2 or dry chemical); water is dangerous because it conducts electricity.', true),
  ('AS-SS-B6-10', 'AS', 'as.shop-safety', 4, 'Before entering a large tank or enclosed space for maintenance work, a technician should first:', '["Enter quickly and complete the task before vapors build up","Test the atmosphere for oxygen level and toxic or flammable vapors","Bring a lit lamp inside to check for visibility","Seal any ventilation openings to keep temperature stable"]'::jsonb, 1, 'Confined spaces can contain oxygen-deficient atmospheres or accumulated toxic/flammable vapors from residues. Atmospheric testing with calibrated instruments is mandatory before entry. Entering without testing risks asphyxiation, explosion, or poisoning.', true),
  ('AS-SS-B6-11', 'AS', 'as.shop-safety', 5, 'A shop receives a drum of a new cleaning solvent. The Safety Data Sheet (SDS) lists an IDLH (Immediately Dangerous to Life and Health) concentration of 100 ppm. This value means that:', '["100 ppm is the safe, permissible exposure limit for an 8-hour shift","at 100 ppm, a worker without a respirator faces conditions from which escape may be impaired or irreversible harm may occur","100 ppm is the concentration at which the solvent becomes flammable","100 ppm must be measured monthly to comply with OSHA standards"]'::jsonb, 1, 'IDLH defines the maximum concentration from which a healthy worker could escape within 30 minutes without escape-impairing symptoms or irreversible health effects. It is used to select respirator types for emergency planning. The permissible exposure limit (PEL) is a separate, lower value for routine shift exposure.', true),
  ('AS-SS-B6-12', 'AS', 'as.shop-safety', 5, 'A shop policy requires that all rotating machinery guards be in place before the machine is started. A supervisor removes a guard temporarily for an adjustment and then leaves without replacing it. The correct action for the next technician who needs to use the machine is to:', '["Use the machine quickly and then replace the guard afterward","Report the missing guard and refuse to operate the machine until the guard is reinstalled","Operate the machine while holding the guard in place manually","Tape cardboard over the exposed area as a temporary barrier"]'::jsonb, 1, 'Machine guards are a primary engineering control against contact with rotating parts. Operating unguarded machinery violates safety standards and exposes the worker to serious injury. The correct response is to stop, report the hazard to a supervisor, and await proper repair before operating the machine.', true),
  ('AS-MR-B6-1', 'AS', 'as.maintenance-repair', 1, 'Coolant reservoir level is checked and found to be below the MIN mark while the engine is cold. What is the correct action?', '["Add the correct antifreeze-water mixture to bring the level to the MIN-MAX range","Drain and replace all coolant regardless of level","Add straight water only so coolant does not become too concentrated","The reservoir level is irrelevant; check only the radiator cap"]'::jsonb, 0, 'The overflow reservoir is the service point for most modern cooling systems. If the level is below MIN when cold, add the manufacturer-specified antifreeze/water mix (typically 50/50) to bring it into the MIN-MAX range. Adding straight water repeatedly dilutes the antifreeze and reduces freeze/boil protection.', true),
  ('AS-MR-B6-2', 'AS', 'as.maintenance-repair', 1, 'The low-oil pressure warning light illuminates while idling at a stoplight. The engine sounds normal. The driver should FIRST:', '["Rev the engine to 3,000 RPM to build oil pressure","Turn off the engine, check the oil level, and add oil if needed before restarting","Continue driving — oil pressure lights are often faulty","Add transmission fluid to the engine to restore pressure quickly"]'::jsonb, 1, 'A low oil pressure warning can indicate low oil level, low oil pressure, or a failing oil pressure sensor. The safest immediate action is to shut off the engine (protecting it from oil starvation), check the dipstick, and add oil if the level is low. Never add transmission fluid to an engine — it can damage seals and bearings.', true),
  ('AS-MR-B6-3', 'AS', 'as.maintenance-repair', 2, 'A technician checks the brake fluid and finds it is dark brown and appears contaminated. The correct service action is to:', '["Top off with fresh fluid to dilute the contamination","Flush the brake system and fill with fresh fluid of the correct DOT specification","Add a brake fluid conditioner and continue use","No action needed — brake fluid darkens naturally and remains effective"]'::jsonb, 1, 'Brake fluid is hygroscopic and absorbs water over time, lowering its boiling point and promoting corrosion of metal components. Dark, contaminated fluid should be flushed from the system completely and replaced with fresh fluid matching the vehicle''s DOT rating (e.g., DOT 3, DOT 4). Topping off only dilutes the contamination without removing it.', true),
  ('AS-MR-B6-4', 'AS', 'as.maintenance-repair', 2, 'A driver notices the engine hesitates and stumbles when accelerating from a stop. A mechanic inspects and finds the air filter is completely clogged with dirt. Why would a clogged air filter cause this symptom?', '["The filter restricts airflow, creating an excessively rich fuel mixture that makes the engine stumble under load","The filter blocks cooling airflow to the radiator","A clogged filter increases intake air temperature, advancing ignition timing","The filter restricts oil return to the crankcase"]'::jsonb, 0, 'The engine needs a precise air-fuel ratio. A severely clogged air filter restricts incoming air, causing the mixture to become too rich (too much fuel relative to air). Under load the engine stumbles because combustion is incomplete. At idle, the effect may be minor, but under acceleration it becomes pronounced.', true),
  ('AS-MR-B6-5', 'AS', 'as.maintenance-repair', 3, 'A technician replaces a worn serpentine belt. After installation, the belt squeals briefly when the engine is cold but goes away when warmed. The MOST likely cause is:', '["The replacement belt is too long","Slight slipping on a pulley due to condensation or belt material until the belt seats fully","The tensioner pulley bearing has failed","A mismatch in belt rib count"]'::jsonb, 1, 'Brief cold squealing from a new belt is common as the rubber conforms to pulley grooves and surface moisture evaporates. If squealing persists or occurs warm, it indicates a worn tensioner, glazed pulley, or incorrect belt. Rib-count mismatches produce constant noise and would cause the belt to mistrack.', true),
  ('AS-MR-B6-6', 'AS', 'as.maintenance-repair', 3, 'When replacing brake pads on a disc brake vehicle, a technician compresses the caliper piston back into the caliper bore. Before doing so, what precaution should be taken?', '["Open the bleeder screw to release pressure while compressing the piston","Remove the master cylinder reservoir cap and siphon out some fluid to prevent overflow as the piston is pushed back","Disconnect the ABS module to prevent error codes","Add brake fluid to the reservoir to prevent air from entering"]'::jsonb, 1, 'Pushing the caliper piston back forces fluid backward into the master cylinder reservoir. If the reservoir is full, this fluid has nowhere to go and will overflow, potentially damaging painted surfaces or rubber seals. Removing the reservoir cap and siphoning excess fluid first prevents overflow. (The bleeder screw method also works but requires catching old fluid separately.)', true),
  ('AS-MR-B6-7', 'AS', 'as.maintenance-repair', 4, 'A spark plug removed from a cylinder has a wet, oily black deposit coating the ceramic insulator and electrodes. This most likely indicates:', '["The engine is running too lean","Oil is entering the combustion chamber due to worn piston rings or valve seals","The ignition timing is excessively advanced","The coolant system is leaking into the cylinder"]'::jsonb, 1, 'An oil-fouled spark plug — wet and black — indicates oil contamination in the combustion chamber. This happens when piston rings wear and lose their seal, or when valve stem seals fail and allow oil to enter from the valve guides. A lean mixture leaves a white powdery deposit; coolant leaks leave a white crusty or sweet-smelling residue.', true),
  ('AS-MR-B6-8', 'AS', 'as.maintenance-repair', 4, 'A vehicle''s power steering pump whines loudly when the steering wheel is turned to full lock in either direction. The fluid level is within the normal range. The MOST likely cause is:', '["Overfilled power steering reservoir","Normal cavitation at the pressure limit — acceptable as long as not held at full lock for extended time","A failing electric power steering motor","A clogged hydraulic return line causing system overpressure"]'::jsonb, 1, 'Hydraulic power steering systems reach their maximum pressure limit at full steering lock. The pump continues to build pressure against a closed circuit, causing fluid to cavitate (form vapor bubbles) and produce a whining or moaning sound. This is normal for short periods; holding full lock for extended time can damage the pump. If it whines at all steering positions, that indicates a different problem.', true),
  ('AS-MR-B6-9', 'AS', 'as.maintenance-repair', 4, 'A visual inspection of a vehicle''s exhaust smoke reveals continuous white smoke from a cold engine that does NOT clear after warm-up. This most likely indicates:', '["Normal condensation burning off","A rich fuel mixture from a faulty injector","Coolant entering the combustion chamber through a failed head gasket","Burning engine oil due to a cracked piston"]'::jsonb, 2, 'Light white smoke on cold startup that clears quickly is normal condensation. Persistent white smoke after warm-up that has a sweet smell and does not dissipate strongly indicates coolant (antifreeze) burning in the cylinders — a hallmark of a blown head gasket or cracked block. Oil smoke tends to be blue-gray with an acrid odor.', true),
  ('AS-MR-B6-10', 'AS', 'as.maintenance-repair', 5, 'A technician performs a cylinder compression test and finds cylinder 3 has 80 psi while all others read 165 psi. Adding a small amount of oil to cylinder 3 through the spark plug hole raises its compression to 150 psi. What does this indicate?', '["A bent intake valve in cylinder 3","Worn piston rings in cylinder 3 — the oil temporarily seals the gap","A cracked cylinder wall in cylinder 3","A leaking head gasket between cylinders 3 and 4"]'::jsonb, 1, 'This is the wet compression test. Adding oil temporarily seals the ring-to-cylinder-wall gap. If compression rises significantly when oil is added, the low reading is caused by ring wear or blow-by, not by a valve or gasket problem. A valve issue would not improve with oil because valves seal above the rings.', true),
  ('AS-MR-B6-11', 'AS', 'as.maintenance-repair', 5, 'After replacing a vehicle''s oxygen sensor, the technician clears the fault code and performs a drive cycle, but the check-engine light returns with the same code. The NEXT diagnostic step is to:', '["Replace the oxygen sensor again with a higher-grade part","Check wiring harness continuity and inspect for exhaust leaks upstream of the sensor","Replace the catalytic converter, as it is the usual cause of sensor codes","Reprogram the ECM with updated software"]'::jsonb, 1, 'If a new sensor triggers the same code, the sensor is likely not the root cause. The technician should inspect the wiring harness for shorts, opens, or damaged connectors, and check for exhaust leaks upstream that can introduce false oxygen readings. Replacing parts without checking the circuit is inefficient and costly.', true),
  ('AS-MR-B6-12', 'AS', 'as.maintenance-repair', 3, 'A technician finds the battery terminals heavily corroded with a white-blue crusty buildup. After cleaning the terminals, what is the correct follow-up action?', '["Replace the battery immediately regardless of its test results","Apply a battery terminal protector spray or grease to prevent future corrosion","Coat the terminals with motor oil for corrosion protection","Tighten the terminal clamps as hard as possible to ensure good contact"]'::jsonb, 1, 'After cleaning corrosion from battery terminals, a protective spray (petroleum-based terminal spray or anti-corrosion felt pads) applied to the terminals significantly reduces the rate of future corrosion by sealing the metal from battery acid vapors. Motor oil is not intended for this purpose and can attract dirt.', true),
  ('MC-LP-B6-1', 'MC', 'mc.levers-pulleys', 1, 'Which class of lever has the effort force applied between the fulcrum and the load?', '["First-class lever","Second-class lever","Third-class lever","Fourth-class lever"]'::jsonb, 2, 'In a third-class lever the effort is between the fulcrum and the load (e.g., a fishing rod or tweezers). First-class has the fulcrum in the middle (e.g., a seesaw); second-class has the load in the middle (e.g., a wheelbarrow). There is no fourth-class lever.', true),
  ('MC-LP-B6-2', 'MC', 'mc.levers-pulleys', 1, 'A first-class lever has its fulcrum exactly in the middle, with a 20-pound weight on each side. The lever is:', '["Balanced, with no mechanical advantage","Tipped toward the left side","Tipped toward the right side","Providing a mechanical advantage of 2"]'::jsonb, 0, 'When both sides have equal weight at equal distance from the fulcrum, torques are equal and the lever is balanced. Mechanical advantage requires the effort arm to be longer than the load arm; equal arm lengths give MA = 1 (no advantage, just direction change).', true),
  ('MC-LP-B6-3', 'MC', 'mc.levers-pulleys', 2, 'A lever has a 4-foot effort arm and a 1-foot load arm. What is the mechanical advantage?', '["1","2","4","5"]'::jsonb, 2, 'Mechanical advantage of a lever = effort arm length / load arm length = 4 / 1 = 4. This means you can lift a 4-pound load with 1 pound of effort (ignoring the lever''s own weight).', true),
  ('MC-LP-B6-4', 'MC', 'mc.levers-pulleys', 2, 'A movable pulley is attached to the load rather than to a fixed point. Compared to a single fixed pulley, a single movable pulley:', '["Provides no change in mechanical advantage","Doubles the mechanical advantage to 2 by supporting the load with two rope segments","Triples the mechanical advantage to 3","Reverses the direction of pull with no force benefit"]'::jsonb, 1, 'A movable pulley travels with the load. Both sides of the rope support the load, so each side bears half the weight — giving a mechanical advantage of 2. The trade-off is that you pull twice the rope distance (distance is doubled, force is halved).', true),
  ('MC-LP-B6-5', 'MC', 'mc.levers-pulleys', 2, 'A 90-pound load is placed 2 feet from the fulcrum of a lever. To balance the load, how much force must be applied at a point 6 feet from the fulcrum on the other side?', '["15 pounds","30 pounds","45 pounds","180 pounds"]'::jsonb, 1, 'Lever equilibrium: Load × Load arm = Effort × Effort arm. 90 × 2 = Effort × 6. Effort = 180 / 6 = 30 pounds. The common trap is dividing the load by the load arm (90 / 2 = 45) rather than setting up the full balance equation.', true),
  ('MC-LP-B6-6', 'MC', 'mc.levers-pulleys', 3, 'A compound pulley system has one fixed pulley and two movable pulleys, resulting in 5 rope segments supporting the load. If the load weighs 200 pounds, how much effort force is needed (ignoring friction)?', '["20 pounds","40 pounds","50 pounds","100 pounds"]'::jsonb, 1, 'Mechanical advantage = number of rope segments supporting the load = 5. Effort = Load / MA = 200 / 5 = 40 pounds. Dividing by the number of pulleys rather than rope segments is the common error.', true),
  ('MC-LP-B6-7', 'MC', 'mc.levers-pulleys', 3, 'A crowbar (first-class lever) is 4 feet long. The fulcrum is placed 6 inches from the load end. How long is the effort arm?', '["6 inches","42 inches","3.5 feet","4 feet"]'::jsonb, 1, 'Total lever length = 4 feet = 48 inches. Load arm = 6 inches. Effort arm = 48 − 6 = 42 inches. MA = 42 / 6 = 7 — a significant mechanical advantage. The trap is reporting the effort arm as 4 feet (the whole lever).', true),
  ('MC-LP-B6-8', 'MC', 'mc.levers-pulleys', 3, 'A flagpole uses a fixed pulley at the top. When you pull the rope down, the flag goes up. What does this pulley change?', '["The magnitude of the required force","Only the direction of the applied force","Both the direction and the magnitude of the force","The speed of the rope only"]'::jsonb, 1, 'A single fixed pulley has a mechanical advantage of 1 — it does not reduce the force needed. Its only benefit is redirecting the force: you pull down to move the load up, which is more convenient. To reduce required force you need a movable pulley or a compound system.', true),
  ('MC-LP-B6-9', 'MC', 'mc.levers-pulleys', 4, 'A block-and-tackle system supports a 360-pound load with 6 rope segments. You pull the free rope end upward 12 feet. How far does the load actually rise?', '["2 feet","6 feet","12 feet","72 feet"]'::jsonb, 0, 'With 6 rope segments sharing the load, you trade force for distance: MA = 6. Load distance = rope distance / MA = 12 / 6 = 2 feet. You exert 360 / 6 = 60 pounds of effort but must pull 6 feet of rope for each foot the load moves.', true),
  ('MC-LP-B6-10', 'MC', 'mc.levers-pulleys', 4, 'A wheelbarrow is a second-class lever. The wheel axle acts as the fulcrum; the load sits in the center; the handles are gripped at the far end. If the load weighs 150 pounds and sits 1.5 feet from the axle, and the handles are 4.5 feet from the axle, how much upward force at the handles is needed to lift the load?', '["50 pounds","75 pounds","100 pounds","225 pounds"]'::jsonb, 0, 'Effort × Effort arm = Load × Load arm. Effort × 4.5 = 150 × 1.5 = 225. Effort = 225 / 4.5 = 50 pounds. The wheelbarrow''s long effort arm (handles) gives MA = 4.5 / 1.5 = 3, so you need only 1/3 of the load''s weight.', true),
  ('MC-LP-B6-11', 'MC', 'mc.levers-pulleys', 4, 'Two pulleys are connected by a belt. The driving pulley has a diameter of 8 inches and turns at 300 RPM. The driven pulley has a diameter of 4 inches. At what RPM does the driven pulley spin?', '["150 RPM","300 RPM","600 RPM","1200 RPM"]'::jsonb, 2, 'Belt-connected pulleys: speed ratio is inversely proportional to diameter ratio. Driven RPM = Driver RPM × (Driver diameter / Driven diameter) = 300 × (8 / 4) = 300 × 2 = 600 RPM. A smaller driven pulley spins faster; a larger one spins slower.', true),
  ('MC-LP-B6-12', 'MC', 'mc.levers-pulleys', 5, 'A mechanic uses a breaker bar that is 24 inches long to loosen a bolt. She can apply 60 pounds of force. The bolt requires 180 pound-inches of torque to loosen. Can she loosen it, and if not, what minimum bar length is needed?', '["Yes, 24 inches is sufficient","No; she needs at least 3 inches","No; she needs at least 30 inches","No; she needs at least 36 inches"]'::jsonb, 0, 'Torque = Force × Arm length = 60 × 24 = 1,440 pound-inches. The bolt requires only 180 pound-inches, so 24 inches is more than sufficient. The trap is misreading the question; 60 × 24 = 1,440, which greatly exceeds 180.', true),
  ('MC-LP-B6-13', 'MC', 'mc.levers-pulleys', 5, 'A lever system is set up with the fulcrum 1 foot from the load end and 5 feet from the effort end (total 6 feet). A 200-pound load is placed at the load end. How much effort is needed, and what is the direction of effort relative to the load for a first-class lever?', '["40 pounds applied upward — same direction as the load pushes","40 pounds applied downward — opposite direction to the load","200 pounds applied downward","40 pounds applied horizontally"]'::jsonb, 1, 'Effort = Load × Load arm / Effort arm = 200 × 1 / 5 = 40 pounds. In a first-class lever the fulcrum is between effort and load, so effort and load forces act in opposite directions — pressing down at the effort end lifts the load end up. The effort is applied downward (opposite to the upward force the load exerts on its end).', true),
  ('MC-GW-B6-1', 'MC', 'mc.gears-wheels', 1, 'Two meshing spur gears always rotate in:', '["the same direction","opposite directions","alternating directions depending on speed","the same direction only when they are the same size"]'::jsonb, 1, 'When two external spur gears mesh, their teeth push against each other, causing each gear to rotate in the direction opposite to the other. If you need both gears to rotate the same direction, you must add an idler gear between them.', true),
  ('MC-GW-B6-2', 'MC', 'mc.gears-wheels', 1, 'A driving gear has 8 teeth and the driven gear has 24 teeth. The gear ratio (driven:driver) is:', '["1:3","3:1","8:1","1:8"]'::jsonb, 1, 'Gear ratio (driven to driver) = teeth on driven / teeth on driver = 24 / 8 = 3:1. This means the driven gear completes one revolution for every three revolutions of the driving gear — a 3:1 gear reduction.', true),
  ('MC-GW-B6-3', 'MC', 'mc.gears-wheels', 2, 'Gear A has 12 teeth and turns at 600 RPM. It meshes with Gear B, which has 36 teeth. How fast does Gear B rotate?', '["100 RPM","200 RPM","300 RPM","1,800 RPM"]'::jsonb, 1, 'Speed is inversely proportional to teeth count: RPM_B = RPM_A × (Teeth_A / Teeth_B) = 600 × (12 / 36) = 600 × (1/3) = 200 RPM. The larger gear turns slower; this is a 3:1 reduction in speed (and a 3:1 increase in torque).', true),
  ('MC-GW-B6-4', 'MC', 'mc.gears-wheels', 2, 'In a gear train, decreasing rotational speed by using a larger driven gear also has what effect on torque?', '["Torque decreases proportionally","Torque increases proportionally","Torque is unaffected by the gear ratio","Torque doubles regardless of the ratio"]'::jsonb, 1, 'Gears trade speed for torque (assuming no friction losses). When the driven gear is larger, it turns slower but the torque multiplies by the same ratio. If speed is halved, torque is doubled. This is why low gears in a vehicle provide more pulling force.', true),
  ('MC-GW-B6-5', 'MC', 'mc.gears-wheels', 3, 'Three gears are in a row: Gear 1 (driver, 10 teeth) meshes with Gear 2 (20 teeth, idler), which meshes with Gear 3 (10 teeth). In which direction does Gear 3 turn relative to Gear 1?', '["Opposite direction — the idler reverses the direction once","Same direction — each mesh reverses direction, and two reversals return to original","Gear 3 does not rotate when an idler is present","Gear 3 rotates 90 degrees out of phase with Gear 1"]'::jsonb, 1, 'Each time two external gears mesh, the direction reverses. Gear 1→Gear 2 is one reversal; Gear 2→Gear 3 is a second reversal. Two reversals return Gear 3 to the same direction as Gear 1. The idler (Gear 2) also changes the speed ratio to 1:1 in this case (10:20:10).', true),
  ('MC-GW-B6-6', 'MC', 'mc.gears-wheels', 3, 'A wheel and axle system has a wheel radius of 15 cm and an axle radius of 3 cm. A 60-Newton load is hung from the axle. What force must be applied at the rim of the wheel to hold the load in equilibrium?', '["4 N","12 N","60 N","300 N"]'::jsonb, 1, 'MA of a wheel and axle = wheel radius / axle radius = 15 / 3 = 5. Effort = Load / MA = 60 / 5 = 12 N. A common trap is dividing 60 by 15 (the wheel radius alone) to get 4 N, confusing radius with MA.', true),
  ('MC-GW-B6-7', 'MC', 'mc.gears-wheels', 3, 'A gear reduction system uses a 5-tooth pinion driving a 40-tooth ring gear. The input shaft turns at 2,000 RPM. What is the output RPM, and how does the output torque compare to the input?', '["250 RPM output; torque is multiplied by 8","250 RPM output; torque is the same","16,000 RPM output; torque is divided by 8","400 RPM output; torque is multiplied by 5"]'::jsonb, 0, 'Output RPM = 2,000 × (5/40) = 250 RPM. Gear ratio = 40/5 = 8:1 reduction. With a factor of 8 reduction in speed, torque is multiplied by 8 (before friction losses). This is the fundamental speed-torque trade-off in gear reductions.', true),
  ('MC-GW-B6-8', 'MC', 'mc.gears-wheels', 4, 'A bicycle chainring has 48 teeth and the rear sprocket has 16 teeth. For each complete revolution of the pedals, how many times does the rear wheel turn?', '["1 time","2 times","3 times","4 times"]'::jsonb, 2, 'The chain transmits motion: rear wheel revolutions per pedal revolution = chainring teeth / sprocket teeth = 48 / 16 = 3. Each pedal stroke turns the rear wheel 3 times — a speed advantage that requires more pedaling force.', true),
  ('MC-GW-B6-9', 'MC', 'mc.gears-wheels', 4, 'In a planetary gear set, the sun gear has 20 teeth, each of three planet gears has 10 teeth, and the ring gear has 40 teeth. If the ring gear is held fixed and power is applied to the sun gear, which output produces the highest torque?', '["The planet carrier (output through the arm holding the planets)","The ring gear (despite being held)","The sun gear itself","All outputs produce identical torque"]'::jsonb, 0, 'When the ring gear is fixed and the sun drives the system, the planet gears walk around the fixed ring, carrying the planet carrier (arm) as output. The speed reduction is significant (overall ratio = 1 + Ring/Sun = 1 + 40/20 = 3:1), giving 3× torque multiplication at the carrier — the highest available output torque configuration for this setup.', true),
  ('MC-GW-B6-10', 'MC', 'mc.gears-wheels', 4, 'A worm gear pair has a worm with 1 thread (start) and a worm wheel with 50 teeth. If the worm shaft turns at 1,500 RPM, at what speed does the worm wheel turn?', '["1 RPM","30 RPM","50 RPM","75,000 RPM"]'::jsonb, 1, 'For a single-start worm, each full turn of the worm advances the worm wheel by 1 tooth. The wheel has 50 teeth, so the gear ratio is 50:1. Output RPM = 1,500 / 50 = 30 RPM. A multi-start worm (e.g., 2 threads) would give 1,500 / 25 = 60 RPM.', true),
  ('MC-GW-B6-11', 'MC', 'mc.gears-wheels', 5, 'A 4-speed manual transmission has gear ratios of 3.5:1, 2.2:1, 1.4:1, and 1:1 for first through fourth gear. In first gear with the engine producing 200 Newton-meters of torque, approximately how much torque is available at the transmission output shaft (ignoring drivetrain losses)?', '["57 Nm","200 Nm","440 Nm","700 Nm"]'::jsonb, 3, 'Output torque = Engine torque × Gear ratio = 200 × 3.5 = 700 Nm. Gear reduction multiplies torque — this is why first gear provides the greatest pulling force for starting from rest. In fourth gear (1:1), output torque equals engine torque (200 Nm).', true),
  ('MC-GW-B6-12', 'MC', 'mc.gears-wheels', 5, 'Two meshing gears have a center-to-center distance of 18 cm. Gear A has a pitch radius of 6 cm. What is the gear ratio if Gear A is the driver?', '["1:1","1:2","2:1","3:1"]'::jsonb, 1, 'Center-to-center distance = radius_A + radius_B. 18 = 6 + radius_B, so radius_B = 12 cm. Since pitch radius is proportional to tooth count, gear ratio (driven:driver) = radius_B / radius_A = 12 / 6 = 2:1. The driven gear is twice as large, so it turns at half the speed of the driver.', true),
  ('MC-GW-B6-13', 'MC', 'mc.gears-wheels', 2, 'A rack and pinion gear system converts which type of motion to which?', '["Rotary motion to linear motion","Linear motion to circular oscillation","Vertical motion to horizontal rotary motion","Torque to electrical energy"]'::jsonb, 0, 'A rack is a straight gear (linear); a pinion is a circular gear. As the pinion rotates, its teeth engage the rack and push it linearly. This converts rotary (circular) motion into linear (straight-line) motion — the basis of rack-and-pinion steering systems.', true),
  ('MC-FF-B6-1', 'MC', 'mc.forces-friction', 1, 'A 50-pound box sits on a rough surface. A horizontal force of 20 pounds is applied but the box does not move. Which statement correctly describes the friction force acting on the box?', '["Friction is 50 pounds, opposing the weight of the box","Friction is 20 pounds, exactly opposing the applied force","Friction is zero because the box is not moving","Friction is 70 pounds, combining weight and applied force"]'::jsonb, 1, 'Static friction adjusts to exactly cancel the applied horizontal force when the object is not moving. The box is in equilibrium, so the horizontal forces must balance: static friction = 20 pounds directed opposite to the applied force.', true),
  ('MC-FF-B6-2', 'MC', 'mc.forces-friction', 1, 'Compared to static friction, kinetic (sliding) friction for the same object on the same surface is generally:', '["Greater","Equal","Less","Dependent only on velocity"]'::jsonb, 2, 'Kinetic friction — the friction acting on a sliding object — is typically less than the maximum static friction required to start the object moving. This is why it takes more force to start sliding a heavy box than to keep it sliding once moving.', true),
  ('MC-FF-B6-3', 'MC', 'mc.forces-friction', 2, 'A 100-pound block rests on a horizontal surface with a coefficient of static friction of 0.4. What minimum horizontal force is needed to start the block moving?', '["20 pounds","40 pounds","60 pounds","100 pounds"]'::jsonb, 1, 'Maximum static friction = coefficient of static friction × normal force = 0.4 × 100 = 40 pounds. This is the minimum force needed to overcome static friction and start motion. On a horizontal surface, the normal force equals the object''s weight.', true),
  ('MC-FF-B6-4', 'MC', 'mc.forces-friction', 2, 'A 200-pound box is being dragged across a floor. The coefficient of kinetic friction is 0.25. What is the friction force resisting the motion?', '["25 pounds","50 pounds","80 pounds","200 pounds"]'::jsonb, 1, 'Kinetic friction = coefficient of kinetic friction × normal force = 0.25 × 200 = 50 pounds. To maintain constant speed, the applied force must equal this friction force. Multiplying 0.25 × 200 = 50; dividing 200 by 0.25 = 800 is a common arithmetic reversal.', true),
  ('MC-FF-B6-5', 'MC', 'mc.forces-friction', 3, 'A 60-pound block is placed on a ramp inclined at 30 degrees. The normal force on the block from the ramp surface equals the component of the block''s weight perpendicular to the ramp surface. If the ramp is smooth (frictionless), the normal force is approximately:', '["30 pounds","52 pounds","60 pounds","120 pounds"]'::jsonb, 1, 'Normal force = W × cos(θ) = 60 × cos(30°) = 60 × 0.866 ≈ 52 pounds. The component pulling the block down the ramp = W × sin(30°) = 60 × 0.5 = 30 pounds. The normal force is NOT equal to the full weight on a ramp — it is reduced by the cosine of the angle.', true),
  ('MC-FF-B6-6', 'MC', 'mc.forces-friction', 3, 'A person pushes down at an angle on a lawnmower handle. The downward component of the pushing force increases the normal force on the mower''s wheels. What effect does this have on friction?', '["Friction decreases because the mower moves forward","Friction increases because friction depends on normal force","Friction is unchanged because only horizontal force causes motion","Friction is eliminated by the forward-directed component"]'::jsonb, 1, 'Friction force = coefficient × normal force. When a downward force component is added to the weight, the total normal force increases, which proportionally increases the friction force. This is why pushing down on a handle makes it harder to slide the mower across rough grass.', true),
  ('MC-FF-B6-7', 'MC', 'mc.forces-friction', 3, 'A 120-pound crate is on a frictionless surface. Two horizontal forces act on it: 50 pounds to the right and 30 pounds to the left. What is the net force and the resulting acceleration? (Use weight ÷ 32 ft/s² to find mass in slugs.)', '["Net 20 pounds right; acceleration ≈ 5.3 ft/s²","Net 80 pounds right; acceleration ≈ 21 ft/s²","Net 20 pounds right; acceleration ≈ 2.5 ft/s²","Net 50 pounds right; no acceleration because friction balances it"]'::jsonb, 0, 'Net force = 50 − 30 = 20 pounds to the right. Mass = weight / g = 120 / 32 = 3.75 slugs. Acceleration = F / m = 20 / 3.75 ≈ 5.3 ft/s². (Note: In SI, 120 lb ≈ 534 N, but using US customary: a = F(lb) / m(slugs). The surface is frictionless, so there is no friction balance issue.)', true),
  ('MC-FF-B6-8', 'MC', 'mc.forces-friction', 4, 'A 500-Newton engine rests on a steel workbench. The coefficient of static friction between the engine and bench is 0.3. A horizontal force of 160 N is applied. Does the engine move, and if not, what is the friction force?', '["Yes, it moves because 160 N exceeds friction","No; static friction = 150 N, and 160 N exceeds it, so it moves","No; maximum static friction = 150 N — since 160 N > 150 N, it just barely moves","No; friction = 160 N opposing the applied force, since the engine is stationary"]'::jsonb, 2, 'Maximum static friction = 0.3 × 500 = 150 N. The applied force is 160 N, which exceeds the maximum static friction. Therefore the engine just begins to move. (If static friction could exactly equal 160 N, it would hold, but 150 N is the ceiling.) The answer correctly identifies that movement occurs.', true),
  ('MC-FF-B6-9', 'MC', 'mc.forces-friction', 4, 'A block slides down a ramp at a constant speed. At constant speed, which of the following must be true?', '["There is no friction force on the block","The component of gravity along the ramp exactly equals the kinetic friction force","The normal force equals the gravitational force","The coefficient of kinetic friction is zero"]'::jsonb, 1, 'Constant speed means zero acceleration, so net force = 0. Along the ramp direction, gravity''s component (W sin θ) pulls the block down the ramp while kinetic friction (μk × W cos θ) acts up the ramp. At constant speed these forces are exactly equal and opposite.', true),
  ('MC-FF-B6-10', 'MC', 'mc.forces-friction', 4, 'A 40-kg box sits on a horizontal floor. Coefficient of static friction = 0.5, kinetic friction = 0.35. A horizontal force of 180 N is applied. What is the friction force and does the box move? (g = 10 m/s²)', '["Friction = 200 N, box does not move","Friction = 180 N, box does not move","Maximum static friction = 200 N; 180 N < 200 N so box stays; friction = 180 N","Box moves; kinetic friction = 140 N"]'::jsonb, 2, 'Normal force = mg = 40 × 10 = 400 N. Maximum static friction = 0.5 × 400 = 200 N. Applied force = 180 N < 200 N, so the box does NOT move. When stationary, static friction equals the applied force: 180 N. Kinetic friction (140 N) is only relevant if the box were sliding.', true),
  ('MC-FF-B6-11', 'MC', 'mc.forces-friction', 5, 'A crate is being pushed across a rough floor at constant velocity with a horizontal force of 80 N. If the floor surface is then treated to reduce the coefficient of kinetic friction by half, and the same 80-N force is maintained, what happens to the crate?', '["It continues at the same constant velocity","It decelerates and stops","It accelerates because the applied force now exceeds the reduced friction","It reverses direction"]'::jsonb, 2, 'Originally, 80 N of applied force equaled 80 N of kinetic friction (constant velocity). Halving the coefficient halves the friction force to 40 N. Now the net force = 80 − 40 = 40 N in the direction of motion, so the crate accelerates. Newton''s Second Law: a = F_net / m > 0.', true),
  ('MC-FF-B6-12', 'MC', 'mc.forces-friction', 5, 'A 10-kg block rests on a 25-degree incline. The coefficient of static friction is 0.5. Will the block slide? (Use g = 10 m/s², sin 25° ≈ 0.42, cos 25° ≈ 0.91)', '["Yes, because gravity down the ramp exceeds maximum static friction","No, because maximum static friction exceeds gravity''s ramp component","It will slide at exactly constant velocity","Insufficient information without knowing the block''s surface material"]'::jsonb, 1, 'Gravity along ramp = mg sin 25° = 10 × 10 × 0.42 = 42 N. Normal force = mg cos 25° = 10 × 10 × 0.91 = 91 N. Maximum static friction = 0.5 × 91 = 45.5 N. Since 45.5 N > 42 N, static friction can fully oppose the sliding tendency. The block does not slide.', true),
  ('MC-IPH-B6-1', 'MC', 'mc.inclined-plane-hydraulics', 1, 'A screw is a simple machine based on which other simple machine?', '["Lever","Wheel and axle","Inclined plane wrapped in a helix","Pulley"]'::jsonb, 2, 'A screw is essentially an inclined plane (ramp) wrapped in a spiral around a cylinder. Rotating the screw converts the rotational force (torque) into a linear force along the screw''s axis, just as a ramp converts a horizontal push into a vertical lift.', true),
  ('MC-IPH-B6-2', 'MC', 'mc.inclined-plane-hydraulics', 1, 'Pascal''s principle states that pressure applied to an enclosed fluid is:', '["absorbed by the fluid and converted to heat","transmitted equally in all directions throughout the fluid","reduced in proportion to the depth of the fluid","only transmitted upward in the fluid"]'::jsonb, 1, 'Pascal''s principle states that a change in pressure applied to an enclosed fluid is transmitted undiminished to every part of the fluid and to the walls of the container. This is the operating principle behind all hydraulic systems.', true),
  ('MC-IPH-B6-3', 'MC', 'mc.inclined-plane-hydraulics', 2, 'A frictionless ramp is 12 feet long and rises 3 feet vertically. What is its mechanical advantage?', '["3","4","9","36"]'::jsonb, 1, 'Mechanical advantage of an inclined plane = length of slope / vertical height = 12 / 3 = 4. A longer ramp (relative to height) requires less force but the load must travel a greater distance. MA = 4 means you need 1/4 of the load''s weight as effort force.', true),
  ('MC-IPH-B6-4', 'MC', 'mc.inclined-plane-hydraulics', 2, 'A hydraulic system input piston has an area of 5 in² and the output piston has an area of 25 in². If the input force is 100 pounds, what force does the output piston exert?', '["20 pounds","100 pounds","500 pounds","2,500 pounds"]'::jsonb, 2, 'Hydraulic force multiplication: F_out = F_in × (A_out / A_in) = 100 × (25 / 5) = 100 × 5 = 500 pounds. The output force is multiplied by the ratio of the piston areas — the fundamental advantage of hydraulics.', true),
  ('MC-IPH-B6-5', 'MC', 'mc.inclined-plane-hydraulics', 3, 'A ramp 20 feet long rises 5 feet. A 240-pound load is pushed up the ramp. What effort force is required (frictionless)?', '["12 pounds","40 pounds","48 pounds","60 pounds"]'::jsonb, 3, 'MA = ramp length / height = 20 / 5 = 4. Effort = Load / MA = 240 / 4 = 60 pounds. A trap answer of 48 pounds corresponds to 240 / 5 (dividing by height instead of MA).', true),
  ('MC-IPH-B6-6', 'MC', 'mc.inclined-plane-hydraulics', 3, 'A hydraulic brake system has an input piston area of 1 in² and the brake caliper piston area is 3 in². A driver applies 30 pounds of force at the brake pedal, which the booster amplifies by a factor of 4 before reaching the master cylinder. How much clamping force does the caliper exert?', '["30 pounds","90 pounds","120 pounds","360 pounds"]'::jsonb, 3, 'Pedal force after booster = 30 × 4 = 120 pounds to the master cylinder piston. Hydraulic area ratio = 3/1 = 3. Caliper force = 120 × 3 = 360 pounds. Two stages of force multiplication (mechanical booster + hydraulic area ratio) are applied in sequence.', true),
  ('MC-IPH-B6-7', 'MC', 'mc.inclined-plane-hydraulics', 3, 'A wedge has a length of 10 inches and a thickness (wide end) of 2 inches. You drive it under a 600-pound rock. How much driving force is needed to generate the lifting force (assuming MA fully transfers)?', '["60 pounds","120 pounds","300 pounds","600 pounds"]'::jsonb, 1, 'Wedge MA = length / thickness = 10 / 2 = 5. Effort needed = Load / MA = 600 / 5 = 120 pounds. The wedge allows a relatively small driving force to create a much larger splitting or lifting force perpendicular to the wedge''s direction of travel.', true),
  ('MC-IPH-B6-8', 'MC', 'mc.inclined-plane-hydraulics', 4, 'In a hydraulic system, the input piston moves down 10 inches with an area of 2 in². The output piston has an area of 8 in². How far does the output piston move upward?', '["1.25 inches","2.5 inches","5 inches","40 inches"]'::jsonb, 1, 'Fluid volume is conserved: Volume in = Volume out. Input volume = 2 in² × 10 in = 20 in³. Output: 20 in³ = 8 in² × d. d = 20 / 8 = 2.5 inches. The output piston moves a shorter distance but with proportionally more force — the same trade-off as any mechanical advantage system.', true),
  ('MC-IPH-B6-9', 'MC', 'mc.inclined-plane-hydraulics', 4, 'A loading ramp is 18 feet long and rises 6 feet. An 800-pound engine is pushed up the ramp with a steady force. How much work is done on the engine as it is raised the full 6 feet vertically? (Work = Force × Distance traveled; use the vertical height.)', '["800 foot-pounds","2,400 foot-pounds","4,800 foot-pounds","14,400 foot-pounds"]'::jsonb, 2, 'Work done against gravity = weight × vertical height = 800 × 6 = 4,800 foot-pounds. The ramp''s MA (18/6 = 3) reduces the effort force to 800/3 ≈ 267 pounds, but you push over 18 feet of ramp: 267 × 18 = 4,800 ft-lb — the same result, confirming conservation of energy. Work done on the load always equals weight × height, regardless of the path.', true),
  ('MC-IPH-B6-10', 'MC', 'mc.inclined-plane-hydraulics', 4, 'A hydraulic press has an input cylinder of area 3 cm² and an output cylinder of area 75 cm². A technician pushes the input piston down 50 cm. What is the output force if the input force is 60 N?', '["60 N","300 N","1,500 N","3,750 N"]'::jsonb, 2, 'Area ratio = 75 / 3 = 25. Output force = 60 × 25 = 1,500 N. The output piston moves 50 × (3/75) = 2 cm — short distance but large force. Output piston travel is inversely proportional to the area ratio, confirming energy conservation.', true),
  ('MC-IPH-B6-11', 'MC', 'mc.inclined-plane-hydraulics', 5, 'An engine hoist uses a compound system: a 3:1 lever feeds into a 4-rope pulley block-and-tackle. An engine weighs 600 pounds. What is the minimum effort force required at the lever input to lift the engine?', '["50 pounds","200 pounds","400 pounds","600 pounds"]'::jsonb, 0, 'Total MA = lever MA × pulley MA = 3 × 4 = 12. Minimum effort = Load / Total MA = 600 / 12 = 50 pounds. When multiple simple machines are combined in series, their mechanical advantages multiply.', true),
  ('MC-IPH-B6-12', 'MC', 'mc.inclined-plane-hydraulics', 5, 'A hydraulic system output piston has an area of 50 in². The system pressure is 200 psi. What force does the output piston exert?', '["4 pounds","250 pounds","10,000 pounds","1,000,000 pounds"]'::jsonb, 2, 'Force = Pressure × Area = 200 psi × 50 in² = 10,000 pounds. This is the fundamental hydraulic force formula. The trap answer 250 pounds comes from adding (200 + 50) rather than multiplying, and 4 pounds comes from dividing (200 / 50).', true),
  ('MC-MP-B6-1', 'MC', 'mc.motion-projectile', 1, 'Newton''s Second Law of Motion states that force equals mass times acceleration (F = ma). If a 2-kg object has an acceleration of 10 m/s², what is the net force on it?', '["5 N","12 N","20 N","0.2 N"]'::jsonb, 2, 'F = m × a = 2 kg × 10 m/s² = 20 N. Dividing m by a (2/10 = 0.2) inverts the formula. Adding them (2 + 10 = 12) misunderstands the relationship. Newton''s Second Law: force is proportional to both mass and acceleration.', true),
  ('MC-MP-B6-2', 'MC', 'mc.motion-projectile', 1, 'A ball is thrown horizontally from a building ledge. At the instant it leaves the thrower''s hand, which direction does gravity act on it?', '["Horizontally, in the direction of throw","Upward, opposing the throw","Vertically downward, regardless of horizontal motion","At a 45-degree angle combining horizontal and vertical"]'::jsonb, 2, 'Gravity always acts vertically downward, independent of horizontal motion. This is the key principle of projectile motion: horizontal and vertical motions are independent. The moment the ball leaves the hand, gravity begins pulling it straight down at 9.8 m/s².', true),
  ('MC-MP-B6-3', 'MC', 'mc.motion-projectile', 2, 'What is the momentum of a 4-kg object moving at 15 m/s?', '["3.75 kg·m/s","11 kg·m/s","60 kg·m/s","225 kg·m/s"]'::jsonb, 2, 'Momentum p = mass × velocity = 4 kg × 15 m/s = 60 kg·m/s. Dividing instead of multiplying (4/15 ≈ 0.27 or 15/4 = 3.75) inverts the formula. Momentum is a vector quantity with units of kg·m/s.', true),
  ('MC-MP-B6-4', 'MC', 'mc.motion-projectile', 5, 'In a perfectly inelastic collision, two objects stick together after impact. What is conserved in this type of collision?', '["Kinetic energy only","Momentum only","Both kinetic energy and momentum","Neither momentum nor kinetic energy"]'::jsonb, 1, 'In any collision (elastic or inelastic), total momentum is conserved. In a perfectly inelastic collision, kinetic energy is NOT conserved — some is converted to heat, sound, and deformation. Elastic collisions conserve both momentum and kinetic energy.', true),
  ('MC-MP-B6-5', 'MC', 'mc.motion-projectile', 2, 'A rocket in space fires its engines and accelerates. Newton''s Third Law explains this by stating that:', '["Objects in space have no inertia and respond to any force","The exhaust gases are pushed backward, and the rocket is pushed forward by an equal and opposite reaction force","The rocket''s mass decreases as fuel is burned, increasing speed automatically","Gravity pulls the rocket forward in the direction of acceleration"]'::jsonb, 1, 'Newton''s Third Law: for every action force there is an equal and opposite reaction force. The rocket engine pushes exhaust gases out the back (action); the gases push the rocket forward with an equal force (reaction). This works in a vacuum where there is no air to push against.', true),
  ('MC-MP-B6-6', 'MC', 'mc.motion-projectile', 3, 'A 3-kg object moving east at 8 m/s collides with a 3-kg object at rest. They stick together. What is the velocity of the combined mass immediately after the collision?', '["8 m/s east","4 m/s east","0 m/s","2 m/s east"]'::jsonb, 1, 'Conservation of momentum: p_before = (3 × 8) + (3 × 0) = 24 kg·m/s. Combined mass = 6 kg. v_after = 24 / 6 = 4 m/s east. The combined mass is twice the original, so velocity is halved. This is a perfectly inelastic collision — kinetic energy is not conserved but momentum is.', true),
  ('MC-MP-B6-7', 'MC', 'mc.motion-projectile', 3, 'A ball is thrown upward and reaches its highest point. At that exact moment, what is the ball''s velocity and what is its acceleration?', '["Velocity = 0 m/s; acceleration = 0 m/s² (weightless at peak)","Velocity = 0 m/s; acceleration = 9.8 m/s² downward","Velocity = peak speed; acceleration = 9.8 m/s² upward","Velocity = 0 m/s; acceleration is upward until it reverses"]'::jsonb, 1, 'At the highest point, vertical velocity is momentarily zero (the ball is neither moving up nor down). However, gravity still acts downward at 9.8 m/s² continuously — acceleration due to gravity never stops, regardless of the object''s velocity. This is a common misconception: zero velocity does not mean zero acceleration.', true),
  ('MC-MP-B6-8', 'MC', 'mc.motion-projectile', 3, 'Two balls are dropped simultaneously from the same height: Ball A has a mass of 1 kg, Ball B has a mass of 5 kg. Ignoring air resistance, which hits the ground first?', '["Ball A, because it is lighter and falls more easily","Ball B, because gravity exerts more force on it","They hit at the same time","It depends on the shape of the balls"]'::jsonb, 2, 'Galileo''s principle: in the absence of air resistance, all objects fall with the same gravitational acceleration (g ≈ 9.8 m/s²) regardless of mass. Although gravity exerts more force on Ball B, Ball B also has more inertia (F = ma → a = F/m, and F and m both scale with mass, so a = g for all). Both hit simultaneously.', true),
  ('MC-MP-B6-9', 'MC', 'mc.motion-projectile', 4, 'A stationary 8-kg bowling ball is struck by a 0.5-kg cue ball moving at 20 m/s. After the collision, the cue ball bounces straight back at 10 m/s. Using conservation of momentum, what is the approximate velocity of the bowling ball after the collision?', '["0.94 m/s in the original direction of the cue ball","1.875 m/s in the original direction","20 m/s in the original direction","10 m/s backward"]'::jsonb, 1, 'Taking the cue ball''s initial direction as positive: p_before = 0.5 × 20 + 8 × 0 = 10 kg·m/s. p_after = 0.5 × (−10) + 8 × v_bowling. 10 = −5 + 8v → 8v = 15 → v = 1.875 m/s in the original forward direction. The cue ball reverses direction (negative), transferring most of its momentum to the heavier ball.', true),
  ('AO-PA-B7-1', 'AO', 'ao.pattern-assembly', 1, 'Three pieces are given: Piece A is a large right triangle with a right angle at the bottom-left corner. Piece B is a small right triangle with the right angle at the top-right corner. Piece C is a rectangle. When pieces A, B, and C are assembled together, which figure results?', '["A large rectangle whose width equals the base of piece A","A square with side length equal to the height of piece A","A large right triangle with no interior gaps","An L-shaped piece with a notch on one side"]'::jsonb, 0, 'Piece B''s hypotenuse mirrors piece A''s hypotenuse; placing B against A fills the triangular gap along that edge. The rectangle C bridges the remaining strip, completing a large rectangle.', true),
  ('AO-PA-B7-2', 'AO', 'ao.pattern-assembly', 1, 'Two pieces are shown: Piece A is a medium square with a dot in its center. Piece B is an identical medium square with no markings. When placed side by side along their right and left edges respectively, what shape results?', '["A large square","A tall thin rectangle","A wide rectangle with the dot on the left half","A wide rectangle with the dot on the right half"]'::jsonb, 2, 'The two squares placed side by side form a wide rectangle (2:1 ratio). Piece A (with the dot) is on the left, so the dot appears in the left half of the assembled figure.', true),
  ('AO-PA-B7-3', 'AO', 'ao.pattern-assembly', 1, 'Four small right triangles, each identical and each with a right angle at the bottom-left, are shown. When all four are assembled by rotating pairs to face each other and joining along their hypotenuses, what shape do they form?', '["A large right triangle","A rectangle","A parallelogram","An irregular pentagon"]'::jsonb, 1, 'Pairing two triangles along each hypotenuse creates two rectangles; those two rectangles can then be placed side by side to form one larger rectangle. All four identical right triangles together always tile a rectangle.', true),
  ('AO-PA-B7-4', 'AO', 'ao.pattern-assembly', 2, 'Three pieces are given: Piece A is a large equilateral triangle marked with an arrow pointing up. Piece B is an identical equilateral triangle with no marking. Piece C is a small equilateral triangle. Pieces A and B are joined along one edge with B flipped (pointing down). Where should piece C be placed to complete a larger equilateral triangle?', '["Along the left edge of piece A","In the gap at the upper-right where the two piece edges don''t meet","In the corner gap at the bottom where the combined A-B shape has an open notch","On top of piece A to extend it upward"]'::jsonb, 2, 'Two equilateral triangles joined base-to-base (one pointing up, one pointing down) form a rhombus. A small equilateral triangle fills the bottom-corner notch to complete a larger equilateral triangle.', true),
  ('AO-PA-B7-5', 'AO', 'ao.pattern-assembly', 2, 'Four pieces are shown: Piece A is a large square. Piece B is a right triangle whose legs are each half the side length of piece A. Piece C is an identical triangle to B. Piece D is an identical triangle to B. When B, C, and D are assembled and attached to piece A, which shape results?', '["A larger square","A regular hexagon","A square with one corner cut off","A pentagon with one right angle"]'::jsonb, 3, 'Each triangle fills one corner of the large square when pressed against it. Three triangles cover three corners; the fourth corner remains. The result is a pentagon with the uncovered corner forming the one remaining right angle.', true),
  ('AO-PA-B7-6', 'AO', 'ao.pattern-assembly', 2, 'Two pieces are given: Piece A is an L-shaped piece (a 3×2 rectangle with a 1×1 square removed from one corner). Piece B is a small 1×1 square. When piece B is placed in the missing corner of piece A, what shape results?', '["A 3×2 rectangle","A 2×3 rectangle (same thing, different orientation)","A T-shape","A 4×1 strip"]'::jsonb, 0, 'Piece A is a 3×2 rectangle minus a 1×1 corner square. Filling the missing corner with piece B restores the complete 3×2 rectangle.', true),
  ('AO-PA-B7-7', 'AO', 'ao.pattern-assembly', 2, 'Three pieces are given: Piece A is a medium isosceles right triangle with the right angle at top. Piece B is an identical triangle. Piece C is a small square whose side equals the leg length of pieces A and B. When A and B are placed with their hypotenuses together, then C is attached to one open side, which figure results?', '["A larger isosceles right triangle","A square","A rectangle that is twice as wide as it is tall","A rectangle with a triangular bump on one end"]'::jsonb, 2, 'Two identical isosceles right triangles joined at their hypotenuses form a square. Attaching the small square C (side = leg length) to one open side of that square extends it into a rectangle that is twice as wide as it is tall. The resulting shape is a rectangle with a 2:1 width-to-height ratio.', true),
  ('AO-PA-B7-8', 'AO', 'ao.pattern-assembly', 3, 'Five pieces are labeled A–E. Piece A is a large square. Pieces B and C are identical right triangles each with legs equal to half the side of A. Piece D is a small square with side equal to one-quarter the side of A. Piece E is a thin rectangle. When all five pieces are assembled without gaps or overlaps, which overall shape results?', '["A large right triangle","A large square larger than piece A","A large rectangle that is twice as long as it is wide","A T-shape"]'::jsonb, 1, 'Piece A forms the core. Triangles B and C fill two corners, piece D fills a quarter-corner gap, and rectangle E fills the remaining strip. Combined, they tile a large square whose side is 1.5 times piece A''s side.', true),
  ('AO-PA-B7-9', 'AO', 'ao.pattern-assembly', 3, 'Piece A is a large right triangle with the right angle at the lower-left, the vertical leg on the left, and the horizontal leg on the bottom. Piece B is a smaller right triangle that is congruent to the upper-left half of piece A when it is cut along its median. Piece C is the remaining lower-right portion of that median cut. When B and C are reassembled, which shape do they form?', '["A square","A shape identical to piece A","A rectangle","A parallelogram"]'::jsonb, 1, 'Pieces B and C are simply the two halves of piece A cut along its median to the hypotenuse. Reassembling B and C recreates piece A identically.', true),
  ('AO-PA-B7-10', 'AO', 'ao.pattern-assembly', 3, 'Four pieces: Piece A is a large square with a diagonal line drawn from the top-left to the bottom-right corner. Pieces B, C, D are right triangles of equal size. When B, C, and D are placed against piece A so that each triangle''s hypotenuse aligns with an outer edge of A, which overall assembled figure results?', '["A regular octagon","A larger square rotated 45°","A plus sign (cross shape)","A star shape"]'::jsonb, 1, 'Adding right triangles to three sides of a square by aligning their hypotenuses to the square''s edges extends each side outward. Three such triangles together with the square form a larger square rotated 45° relative to the original.', true),
  ('AO-PA-B7-11', 'AO', 'ao.pattern-assembly', 3, 'Three pieces: Piece A is a large rectangle (3 units wide, 2 units tall). Piece B is a right triangle with legs 2 units and 1 unit. Piece C is a right triangle identical to B. B and C are mirror images of each other. When B is placed against the right side of A (hypotenuse facing A''s right edge), and C is placed against the left side (mirrored), which shape results?', '["A regular hexagon","A parallelogram","A hexagon with two right angles","A parallelogram with clipped corners"]'::jsonb, 1, 'Placing opposite-facing right triangles on each short end of a rectangle extends both ends diagonally in the same slant direction, converting the rectangle into a parallelogram.', true),
  ('AO-PA-B7-12', 'AO', 'ao.pattern-assembly', 4, 'Six pieces labeled A–F. Piece A is a medium square. Piece B is a medium square of identical size. Piece C is a right triangle with legs equal to the side of A. Piece D is an identical triangle to C. Piece E is a small rectangle 1×2 units. Piece F is a 1×1 square. All pieces assembled without gaps or overlap: which overall shape is formed?', '["A square whose side equals twice the side of piece A","A rectangle twice as long as it is wide","An irregular pentagon","A large right triangle"]'::jsonb, 0, 'Pieces A and B form a 1×2 rectangle. Triangles C and D complete a square at each end (each triangle fills a corner gap). Piece E and piece F fill the remaining central strip. Total area = side² × 4, forming a square with side = 2× piece A.', true),
  ('AO-PA-B7-13', 'AO', 'ao.pattern-assembly', 4, 'Piece A is a large isosceles trapezoid with a long base of 4 units, a short top of 2 units, and height 2 units. Piece B is a right triangle with legs 2 units each. Piece C is an identical right triangle to B. When B is placed against trapezoid A''s left slanted edge and C is placed against the right slanted edge, what overall shape is formed?', '["A large rectangle 4 units wide and 2 units tall","A large square 4 units on each side","A regular hexagon","A parallelogram"]'::jsonb, 0, 'Each right triangle fills the gap between the trapezoid''s slanted leg and a vertical line. With both gaps filled, the combined shape is a rectangle 4 units wide (matching the long base) and 2 units tall.', true),
  ('AO-PA-B7-14', 'AO', 'ao.pattern-assembly', 4, 'Piece A is a large square. A smaller square piece B (half the side of A) is cut from the center-right of A, leaving an L-shape. Piece C is that same smaller square. Piece D is a right triangle with legs equal to half the side of A. When pieces A (L-shape), C, and D are assembled in a flat arrangement without overlap, what results?', '["A shape identical to the original large square A","A right triangle larger than piece D","A rectangle that is 1.5 times as long as it is wide","A pentagon"]'::jsonb, 2, 'Re-assembling the L-shape with square C restores the original square. Adding triangle D along one edge extends it into a 1.5:1 rectangle (area of square + area of triangle produces this ratio).', true),
  ('AO-PA-B7-15', 'AO', 'ao.pattern-assembly', 3, 'Pieces A, B, C, D are four congruent parallelograms, each with a horizontal top edge and slanted sides leaning to the right. When the four pieces are arranged in a 2×2 grid with alternating orientations (every other piece flipped upside down), what overall shape is formed?', '["A large parallelogram","A large rectangle","A rhombus","An irregular hexagon"]'::jsonb, 1, 'Alternating orientation (normal and flipped) of parallelograms in a grid causes the slanted edges to cancel out, producing straight left and right edges. The combined shape is a rectangle.', true),
  ('AO-PA-B7-16', 'AO', 'ao.pattern-assembly', 5, 'Seven pieces: Piece A is a regular hexagon with a dot at its center. Pieces B through G are six equilateral triangles, each with one side equal to the side length of hexagon A. When all six triangles (B–G) are placed against each outer edge of hexagon A, what shape results?', '["A larger regular hexagon","A 12-pointed star","A regular 12-sided polygon (dodecagon)","A six-pointed Star of David shape"]'::jsonb, 0, 'Placing an equilateral triangle against each of the six edges of a regular hexagon fills in six triangular gaps. The outer vertices of those triangles form the six vertices of a larger regular hexagon, exactly doubling the side length.', true),
  ('AO-PA-B7-17', 'AO', 'ao.pattern-assembly', 5, 'Four pieces: Piece A is a large right triangle (legs 3 and 4 units). Piece B is a right triangle with legs 3 and 4 units (identical to A). Piece C is a 3×4 rectangle. Piece D is a right triangle with legs 3 and 4. When A and B are joined at their hypotenuses and C is placed along the 3-unit side, then D fills the remaining gap, what shape is formed?', '["A square with side 5 units","A rectangle 4 units wide and 6 units tall","A rectangle 3 units wide and 8 units tall","A 3×4 rectangle"]'::jsonb, 1, 'A and B joined at hypotenuses form a 3×4 rectangle. Adding C (another 3×4 rectangle) doubles it to a 4×6 or 3×8 strip — with C on the 4-unit side the result is 4 units wide and 6 units tall. Triangle D fills the diagonal gap producing a clean 4×6 rectangle.', true),
  ('AO-PA-B7-18', 'AO', 'ao.pattern-assembly', 5, 'Pieces A–D are four identical right trapezoids, each with a long parallel side of 4 units, a short parallel side of 2 units, and height 2 units. The slanted leg rises from the right end of the long base. When the four trapezoids are arranged so that each slanted leg fits flush against the next piece''s slanted leg (alternating flip), what overall shape results?', '["A large square","A large regular octagon","A large rectangle 8 units wide and 4 units tall","A large parallelogram"]'::jsonb, 2, 'Each pair of mirrored trapezoids (normal + flipped) forms a rectangle 6 units wide and 2 units tall. Two such pairs stacked vertically give a rectangle 6×4 — but joining all four end-to-end yields 8 units wide × 2 units tall when laid flat. Accounting for all edges correctly: four trapezoids in alternating-flip row produce an 8×2 rectangle; two rows give 8×4.', true),
  ('AO-PA-B7-19', 'AO', 'ao.pattern-assembly', 4, 'Three pieces: Piece A is a medium square (side = 2 units) with a diagonal arrow pointing from the bottom-left to the top-right corner. Piece B is a right triangle with legs 2 and 2 units (the lower-left half of a same-sized square). Piece C is a right triangle with legs 2 and 2 units (the upper-right half). When A, B, and C are assembled flat without overlap, what shape results?', '["A 2×4 rectangle","A large right triangle with legs 4 units each","A large square with side 2√2","A 2×2 square with two triangular ears on the sides"]'::jsonb, 1, 'Piece A (2×2 square) combined with triangle B (lower-left 2×2 half) and triangle C (upper-right 2×2 half) totals 2 complete 2×2 squares in area. Arranged in an L: the square and two triangles tile a large right triangle with both legs measuring 4 units.', true),
  ('AO-PA-B7-20', 'AO', 'ao.pattern-assembly', 5, 'Five pieces are shown. Piece A is a large equilateral triangle (side 4 units). Pieces B, C, D are small equilateral triangles (side 2 units). Piece E is a rhombus made from two small equilateral triangles joined at one edge. When A, B, C, D, and E are assembled, which shape results?', '["A regular hexagon with side 2 units","A larger equilateral triangle with side 6 units","A trapezoid","A regular hexagon with side 4 units"]'::jsonb, 1, 'The large triangle (area 4 small-triangle units²) plus three small triangles plus rhombus E (2 small-triangle units²) equals 9 small equilateral triangle areas — exactly a side-6 equilateral triangle. They tile it without gaps.', true),
  ('AO-3D-B7-1', 'AO', 'ao.3d-visualization', 1, 'A rectangular prism (box) is sitting with its longest dimension running left to right. If you rotate it 90° by tipping it backward (the top face tilts away from you, rotating around the back-bottom edge), which face is now on top?', '["The original top face","The original bottom face","The original back face","The original front face"]'::jsonb, 3, 'Tipping backward around the back-bottom edge causes the front face to swing up and become the new top. The original top rotates away to become the new front (facing away).', true),
  ('AO-3D-B7-2', 'AO', 'ao.3d-visualization', 1, 'A cube has colored stickers: top = orange, bottom = purple, front = red, back = blue, left = green, right = white. The cube is picked up and turned upside-down (rotated 180° around a horizontal front-to-back axis). What color is now on top?', '["Orange","Purple","Red","Blue"]'::jsonb, 1, 'A 180° flip around the front-to-back axis swaps top and bottom, and swaps left and right, but leaves front and back unchanged. The original bottom (purple) is now on top.', true),
  ('AO-3D-B7-3', 'AO', 'ao.3d-visualization', 1, 'You are looking directly at the front face of a rectangular prism. It is then rotated 90° to the left around its vertical axis (the left side swings toward you). Which face is now facing you?', '["The original front face","The original right face","The original back face","The original left face"]'::jsonb, 1, 'Rotating left around the vertical axis brings the right face around to the front. The original front moves to become the new left side.', true),
  ('AO-3D-B7-4', 'AO', 'ao.3d-visualization', 2, 'A cube: top = silver, bottom = gold, front = red, back = blue, left = green, right = yellow. Rotate the cube 90° to the right around the vertical axis (the right face swings to the front). Then rotate 90° forward — tilting the new top toward you, pivoting around the new front-bottom edge. What color is now on top after both rotations?', '["Yellow","Silver","Red","Blue"]'::jsonb, 0, 'After rotation 1 (90° right around vertical axis): the right face (yellow) moves to front, the front (red) moves to left, the left (green) moves to back, the back (blue) moves to right; top stays silver. After rotation 2 (90° forward, pivoting around the front-bottom edge): the new front face (yellow) swings up to become the new top. Final top = yellow (index 0).', true),
  ('AO-3D-B7-5', 'AO', 'ao.3d-visualization', 2, 'A rectangular prism is 2 units wide, 3 units tall, and 4 units deep. You view it from directly in front. If you then view it from directly above (bird''s-eye view), what shape do you see?', '["A 2×3 rectangle","A 2×4 rectangle","A 3×4 rectangle","A 4×4 square"]'::jsonb, 1, 'The top view shows width × depth = 2×4. The front view (2×3) and side view (4×3) each involve height. Only the top view gives 2×4.', true),
  ('AO-3D-B7-6', 'AO', 'ao.3d-visualization', 3, 'A cube has colored faces: top = white, bottom = black, front = red, back = green, left = blue, right = yellow. Rotate 90° to the left around its vertical axis, then rotate 90° backward (top tilts away from you, pivoting around the back-bottom edge). What color is now facing you (front) after both rotations?', '["Blue","White","Black","Yellow"]'::jsonb, 1, 'Rotation 1 (90° left, vertical): left (blue) → back, back (green) → right, right (yellow) → front, front (red) → left. Top = white, bottom = black. Rotation 2 (90° backward, around back-bottom edge): new top = original back = green; new front = original top = white; new bottom = original front = yellow; new back = original bottom = black. Front face = white.', true),
  ('AO-3D-B7-7', 'AO', 'ao.3d-visualization', 3, 'A solid triangular prism rests with one rectangular face flat on a table. You view it from the front and see a rectangle. What shape do you see when you view it from the left end?', '["A rectangle","A triangle","A square","A trapezoid"]'::jsonb, 1, 'A triangular prism has triangular cross-sections on its two ends. Viewing it from the left end reveals the triangular face.', true),
  ('AO-3D-B7-8', 'AO', 'ao.3d-visualization', 4, 'A cube is placed with face 1 on top. It is then rotated 90° forward twice in a row (each time the top tilts toward you, pivoting around the front-bottom edge). After both rotations, which original face is now on top?', '["The original top face (face 1)","The original front face","The original bottom face (face opposite face 1)","The original back face"]'::jsonb, 2, 'Each 90° forward rotation advances the cycle: top → front → bottom → back → top. After 1 rotation: original front is on top. After 2 rotations: original bottom is on top.', true),
  ('AO-3D-B7-9', 'AO', 'ao.3d-visualization', 4, 'A cube has faces numbered 1 (top), 2 (bottom), 3 (front), 4 (back), 5 (left), 6 (right). It is rotated 90° to the right (around vertical axis), then 90° to the right again, then 90° forward (around front-bottom edge). What number is on top?', '["1","3","4","2"]'::jsonb, 1, 'Starting state: top=1, bottom=2, front=3, back=4, left=5, right=6. Right rotation 1 (vertical axis): right→front, old front→left, old left→back, old back→right; top and bottom unchanged. After rot1: front=6, left=3, back=5, right=4; top=1, bottom=2. Right rotation 2: front=4, left=6, back=3, right=5; top=1, bottom=2. Forward rotation 3 (top toward you, front-bottom pivot): top→front, front→bottom, bottom→back, back→top. New top = old back = 3. Answer = 3, choice b, index 1.', true),
  ('AO-3D-B7-10', 'AO', 'ao.3d-visualization', 4, 'A rectangular prism has dimensions 1×2×4 (height × width × depth). If you slice it with a horizontal plane halfway up its height, what shape is the cross-section?', '["A 1×2 rectangle","A 2×4 rectangle","A 1×4 rectangle","A square"]'::jsonb, 1, 'A horizontal cut through a rectangular prism reveals a rectangle whose dimensions are width × depth = 2×4, regardless of where vertically the cut is made.', true),
  ('AO-3D-B7-11', 'AO', 'ao.3d-visualization', 3, 'A cube: top = white, bottom = black, front = red, back = green, left = blue, right = yellow. Rotate 90° to the right (vertical axis). What color is now on the left side?', '["Blue","Red","Green","Yellow"]'::jsonb, 1, 'Right rotation (vertical axis): right→front, front→left, left→back, back→right. Original front (red) moves to the left position. Answer: Red.', true),
  ('AO-3D-B7-12', 'AO', 'ao.3d-visualization', 5, 'A regular tetrahedron (4 identical equilateral-triangle faces) rests on one face. You rotate it 120° around the vertical axis passing through the top vertex. How many faces look identical in position to where they started?', '["0","1","2","4"]'::jsonb, 1, 'The top vertex stays fixed during a vertical-axis rotation. The face on the bottom (the base) stays in the same horizontal plane. 120° is exactly one-third of a full rotation, which is a symmetry of the triangular base — the base face maps to itself. The three side faces cycle among themselves. So exactly 1 face (the bottom) is in the same position.', true),
  ('AO-3D-B7-13', 'AO', 'ao.3d-visualization', 5, 'A cube is sliced by a plane that passes through the midpoints of four parallel edges — specifically the four edges running left-to-right on the front and back faces (two on the front face, two on the back). What is the shape of the cross-section?', '["A square","A rectangle that is not a square","A rhombus","A trapezoid"]'::jsonb, 0, 'Cutting through the midpoints of four parallel edges of a cube with a plane parallel to two faces produces a square cross-section, since all four edge midpoints are equidistant and form a square in the plane of the cut.', true),
  ('AO-3D-B7-14', 'AO', 'ao.3d-visualization', 5, 'A solid cylinder is cut by a plane that passes through the cylinder at an angle of 45° to the cylinder''s base (the plane intersects both the top and bottom circles). What shape is the cross-section?', '["A circle","A rectangle","An ellipse","A parabola"]'::jsonb, 2, 'Any plane that cuts a circular cylinder at an angle other than perpendicular (but not parallel to the axis) produces an elliptical cross-section. A perpendicular cut gives a circle; a cut parallel to the axis gives a rectangle.', true),
  ('AO-3D-B7-15', 'AO', 'ao.3d-visualization', 4, 'A cube: top = white, bottom = black, front = red, back = green, left = blue, right = yellow. Rotate the cube 90° backward (top tilts away, pivoting around the back-bottom edge), then 90° to the left (around vertical axis). What color is on the bottom after both rotations?', '["Red","White","Green","Black"]'::jsonb, 0, 'Rotation 1 (90° backward): new top=green(old back), new front=white(old top), new bottom=red(old front), new back=black(old bottom); left/right unchanged (blue/yellow). Rotation 2 (90° left, vertical): top and bottom unchanged. Bottom stays red.', true),
  ('AO-3D-B7-16', 'AO', 'ao.3d-visualization', 3, 'A cube: top = white, bottom = black, front = red, back = green, left = blue, right = yellow. Rotate 90° forward (top toward you, front-bottom pivot). What color is now on the back face?', '["White","Green","Red","Black"]'::jsonb, 0, '90° forward (front-bottom pivot): top→front, front→bottom, bottom→back, back→top. Original top (white) moves to the back position.', true),
  ('AO-PF-B7-2', 'AO', 'ao.paper-folding-nets', 1, 'A net consists of six squares arranged as follows: a row of four squares (labeled 1–4, left to right), square 5 attached to the top edge of square 2, and square 6 attached to the bottom edge of square 3. When this net is folded, what 3D object is formed?', '["An open-top box","A cube","A rectangular prism that is not a cube","A triangular prism"]'::jsonb, 1, 'Verify fold: Square 2 is the base. Square 1 folds up to become the left face. Square 3 folds up to become the right face. Square 4 folds up to become the far face (opposite square 1 would be... let me trace: 1-2-3-4 is the spine. Fold 1 up→left wall. Fold 3 up→right wall. Fold 4 up→back wall. Square 5 (top of 2) folds up→front wall. Square 6 (bottom of 3): when square 3 is already the right wall, square 6 is on its lower edge which becomes the top. So: base=2, walls=1(left),3(right→folds to right wall), 4(back), 5(front), 6(top). All six squares, all same size → cube.', true),
  ('AO-PF-B7-3', 'AO', 'ao.paper-folding-nets', 1, 'A flat net has the shape of a cross: one square in the center, one square above, one below, one to the left, one to the right, and one more square attached to the right edge of the rightmost square (6 squares total, forming a plus sign with an extra square on one arm). When folded, which face is opposite the center square?', '["The extra square on the extended arm","The square directly above the center","The square directly below the center","The square to the left of the center"]'::jsonb, 0, 'Label: center=C, top=T, bottom=B, left=L, right=R, extra=E (right of R). Fold: C is the base. T, B, L, R fold up to become four side walls. E, which is two squares away from center in the right direction, folds over to become the top (opposite C). T and B are adjacent to C, so they fold to be front/back walls — not opposite C.', true),
  ('AO-PF-B7-4', 'AO', 'ao.paper-folding-nets', 2, 'A net consists of a column of four squares numbered 1–4 (top to bottom). Square 5 is attached to the right edge of square 1, and square 6 is attached to the right edge of square 4. When folded into a cube, which square is opposite square 2?', '["Square 4","Square 5","Square 6","Square 3"]'::jsonb, 0, 'Assign square 2 as the base. Square 1 (above 2) folds to become the back wall. Square 3 (below 2) folds to become the front wall. Square 4 (below 3): when 3 is the front wall, 4 folds over it to become the top. Square 5 (right of square 1): when 1 is the back wall, 5 folds along with it to become the right wall. Square 6 (right of square 4): when 4 is the top, 6 folds down to become the left wall. Opposite the base (square 2) is the top = square 4. Answer: square 4, choice a, index 0.', true),
  ('AO-PF-B7-5', 'AO', 'ao.paper-folding-nets', 2, 'A net for a cube is laid out as follows: a row of three squares (A, B, C) from left to right. Square D is above square B. Square E is below square B. Square F is to the right of square C. When folded, which square is opposite square A?', '["Square C","Square F","Square D","Square E"]'::jsonb, 0, 'Assign B as the base. A (left of B) folds up to become the left wall. C (right of B) folds up to become the right wall. F (right of C): when C is the right wall, F continues to become the top. D (above B) folds to become the front wall. E (below B) folds to become the back wall. Face assignments: bottom=B, top=F, left=A, right=C, front=D, back=E. Opposite A (left) = C (right) = choice a, index 0.', true),
  ('AO-PF-B7-6', 'AO', 'ao.paper-folding-nets', 3, 'A net consists of a column of four squares (1 at top, 2, 3, 4 at bottom). Square 5 is attached to the left edge of square 2. Square 6 is attached to the right edge of square 3. When folded into a cube, which two squares are opposite each other?', '["Square 1 and square 4","Square 2 and square 4","Square 5 and square 6","Square 1 and square 3"]'::jsonb, 2, 'Fold step by step with square 2 as base. Square 1 (above 2) folds up → back wall. Square 3 (below 2) folds up → front wall. Square 4 (below 3) continues: it folds over the front wall to become the top (opposite base=2). Square 5 (left of 2): folds up → left wall. Square 6 (right of 3): when square 3 becomes the front wall, square 6 (on its right edge) folds to become the right wall. Opposites: bottom(2) ↔ top(4); back(1) ↔ front(3); left(5) ↔ right(6). Therefore squares 5 and 6 are opposite.', true),
  ('AO-PF-B7-7', 'AO', 'ao.paper-folding-nets', 3, 'A net consists of a row of four squares (W, X, Y, Z from left to right). Square V is attached to the top edge of square X, and square U is attached to the bottom edge of square Y. When folded into a cube, which square is opposite square Z?', '["Square W","Square V","Square U","Square X"]'::jsonb, 3, 'Assign X as the base. W (left of X) folds up to become the left wall. Y (right of X) folds up to become the right wall. Z (right of Y): when Y is the right wall, Z folds over to become the top. V (above X) folds to become the front wall. U (below Y): when Y is the right wall, U is on Y''s bottom edge, folding to become the back wall. Face assignments: bottom=X, top=Z, left=W, right=Y, front=V, back=U. Opposite Z (top) = X (bottom) = choice d, index 3.', true),
  ('AO-PF-B7-8', 'AO', 'ao.paper-folding-nets', 3, 'A T-shaped net of 6 squares: a row of three squares (P, Q, R) forms the top of the T. Square S is below Q. Square T is below S. Square U is below T. When folded into a cube, which square is opposite square P?', '["Square R","Square T","Square U","Square S"]'::jsonb, 0, 'Assign Q as the base. P (left of Q) folds up to become the left wall. R (right of Q) folds up to become the right wall. S (below Q) folds up to become the front wall. T (below S): when S is the front wall, T folds over it to become the top. U (below T): when T is the top, U folds to become the back wall. Face assignments: bottom=Q, top=T, left=P, right=R, front=S, back=U. Opposite P (left) = R (right) = choice a, index 0.', true),
  ('AO-PF-B7-9', 'AO', 'ao.paper-folding-nets', 4, 'A net of 6 squares arranged as: Row 1 has squares A and B (A left, B right). Row 2 has squares C and D (C below A, D below B). Row 3 has squares E and F (E below C, F below D). When folded into a rectangular prism (all squares are the same size, so it is a cube), which square is opposite square B?', '["Square A","Square C","Square E","Square F"]'::jsonb, 2, 'This 2×3 grid net folds as follows: let D be the base. C (left of D) folds up → left wall. B (above D, in row 1) folds up → back wall. A (above C, in row 1) is attached to C; it folds to become the top. E (below C, in row 3) folds up → front wall. F (below D, in row 3) folds up → right wall. Faces: bottom=D, top=A, left=C, right=F, back=B, front=E. Opposite B (back) = E (front) = choice c (index 2).', true),
  ('AO-PF-B7-10', 'AO', 'ao.paper-folding-nets', 4, 'A net consists of: a central square M, square N attached to M''s top edge, square O attached to N''s top edge, square P attached to M''s right edge, square Q attached to M''s bottom edge, and square R attached to Q''s bottom edge. When folded into a cube, which square is opposite square O?', '["Square Q","Square M","Square R","Square N"]'::jsonb, 2, 'Assign M as the base. N (above M) folds to become the back wall. O (above N): when N is the back wall, O folds over it to become the top. P (right of M) folds to become the right wall. Q (below M) folds to become the front wall. R (below Q): when Q is the front wall, R folds over it to become the bottom — but since M is the base, R becomes the additional face; the six faces are M(bottom), O(top), N(back), Q(front), P(right), R(left). Opposite O (top) = M (bottom)? No: each square is a distinct face. The face chain from O downward: O→N→M→Q→R. O and R are two squares apart through the spine, making them opposites. Opposite O = R = choice c, index 2.', true),
  ('AO-PF-B7-11', 'AO', 'ao.paper-folding-nets', 4, 'A cross-shaped net of 5 squares: square 1 in center, squares 2–5 attached to each of its four sides (top, bottom, left, right). A sixth square (6) is attached to the top edge of square 2 (which is above square 1). When folded, which square is opposite square 1 (the center)?', '["Square 2","Square 6","Square 3","Square 4"]'::jsonb, 1, 'Let square 1 = base. Square 3 (bottom of 1) → front wall. Square 4 (right of 1) → right wall. Square 5 (left of 1) → left wall. Square 2 (top of 1) → back wall. Square 6 (top of 2): when 2 is the back wall, 6 is on 2''s top edge — it folds over to become the top (opposite base 1). Opposite square 1 = square 6.', true),
  ('AO-PF-B7-12', 'AO', 'ao.paper-folding-nets', 4, 'A net of 6 squares: square A is the base of a column. Above A are squares B, C (in order from bottom to top). Square D is attached to the right edge of A. Square E is attached to the right edge of B. Square F is attached to the left edge of C. When this net is folded into a cube, which square is opposite square F?', '["Square D","Square A","Square E","Square B"]'::jsonb, 2, 'Assign B as the base. A (below B) folds up to become the front wall. C (above B) folds up to become the back wall. E (right of B) folds to become the right wall. D (right of A): when A is the front wall, D is on A''s right edge and folds to become the bottom. F (left of C): when C is the back wall, F is on C''s left edge and folds to become the left wall. Face assignments: top=B, front=A, back=C, right=E, bottom=D, left=F. Opposite F (left) = E (right) = choice c, index 2.', true),
  ('AO-PF-B7-13', 'AO', 'ao.paper-folding-nets', 3, 'A square sheet is folded once by bringing the left edge to meet the right edge (a vertical fold, creating a rectangle half the original width). A hole is then punched through all layers at the center of the folded rectangle. When the sheet is unfolded, how many holes are there, and where?', '["One hole in the exact center of the original sheet","Two holes symmetrically placed left and right of center, each at the vertical midpoint","Four holes at the four quadrant centers","Two holes — one in the center of each half — stacked vertically"]'::jsonb, 1, 'Folding left-to-right (vertical fold) doubles the layers side by side. Punching the center of the folded rectangle punches through both layers simultaneously. When unfolded, those two punch points are mirror images left and right of the center crease, both at the same vertical height (midpoint).', true),
  ('AO-PF-B7-17', 'AO', 'ao.paper-folding-nets', 5, 'A cube net is arranged as follows: a zigzag row of four squares — square 1, then square 2 to the right of 1, then square 3 above 2, then square 4 to the right of 3. Square 5 is below square 2. Square 6 is to the right of square 4. When folded into a cube, which square is opposite square 1?', '["Square 3","Square 4","Square 6","Square 5"]'::jsonb, 1, 'Assign square 2 as the base. Square 1 (left of 2) folds up to become the left wall. Square 5 (below 2) folds up to become the front wall. Square 3 (above 2) folds up to become the back wall. Square 4 (right of 3): when 3 is the back wall, square 4 is on 3''s right edge and folds to become the right wall. Square 6 (right of 4): when 4 is the right wall, square 6 folds to become the top. Face assignments: bottom=2, top=6, left=1, right=4, front=5, back=3. Opposite left (1) = right (4) = choice b, index 1.', true),
  ('AO-SC-B7-1', 'AO', 'ao.spatial-counting', 1, 'A staircase of cubes is built against a wall: the first column from the left is 1 cube tall, the second is 2 cubes tall, and the third is 3 cubes tall. Each column is 1 cube wide and 1 cube deep. How many total cubes are in the staircase?', '["5","6","7","9"]'::jsonb, 1, 'Total = 1 + 2 + 3 = 6 cubes. The staircase pattern always sums to n(n+1)/2 for n steps, which equals 3(4)/2 = 6.', true),
  ('AO-SC-B7-2', 'AO', 'ao.spatial-counting', 1, 'A rectangular arrangement of cubes is 4 cubes long, 2 cubes wide, and 1 cube tall (a single flat layer). How many cubes are in the arrangement?', '["6","7","8","10"]'::jsonb, 2, 'Total = 4 × 2 × 1 = 8 cubes.', true),
  ('AO-SC-B7-3', 'AO', 'ao.spatial-counting', 1, 'A 2×2×2 cube structure is built from unit cubes. How many unit cubes are used in total?', '["4","6","8","12"]'::jsonb, 2, 'Total = 2 × 2 × 2 = 8 unit cubes.', true),
  ('AO-SC-B7-4', 'AO', 'ao.spatial-counting', 2, 'A structure has a base layer of 3×3 cubes (9 cubes) and a top layer of only the four corner positions of that 3×3 grid (4 cubes at the corners). How many total cubes are in the structure?', '["9","11","13","16"]'::jsonb, 2, 'Bottom layer = 9 cubes. Top layer = 4 corner cubes. Total = 9 + 4 = 13 cubes.', true),
  ('AO-SC-B7-5', 'AO', 'ao.spatial-counting', 2, 'A 3×3×3 large cube is assembled from unit cubes. How many unit cubes have exactly two painted faces if only the outside surface of the large cube is painted?', '["8","12","16","24"]'::jsonb, 1, 'Unit cubes with exactly 2 painted faces sit on the edges of the large cube but not at the corners. A 3×3×3 cube has 12 edges, each with 1 non-corner edge cube. So: 12 × 1 = 12 edge cubes have exactly 2 painted faces.', true),
  ('AO-SC-B7-6', 'AO', 'ao.spatial-counting', 2, 'Looking at a structure from directly above, you see a 3×3 grid with a hole in the center (the center position is empty). All visible squares are exactly 1 cube tall. How many total unit cubes are in the structure?', '["7","8","9","12"]'::jsonb, 1, 'The 3×3 grid has 9 positions. One center position is empty (no cube there). Remaining = 9 − 1 = 8 cubes, all 1 unit tall.', true),
  ('AO-SC-B7-7', 'AO', 'ao.spatial-counting', 3, 'A 3×3×3 large cube is built from unit cubes. All six outer faces are painted red. How many unit cubes have exactly three painted faces?', '["4","6","8","12"]'::jsonb, 2, 'Unit cubes with three painted faces are at the corners of the large cube. A cube has exactly 8 corners, so 8 unit cubes have three painted faces.', true),
  ('AO-SC-B7-8', 'AO', 'ao.spatial-counting', 3, 'A 5×5×5 large cube is assembled from unit cubes. How many unit cubes are completely hidden (touch no outer face)?', '["9","16","27","64"]'::jsonb, 2, 'Interior (hidden) cubes form a (5−2)³ = 3³ = 27 unit cube block inside. Every other unit cube touches at least one outer face.', true),
  ('AO-SC-B7-9', 'AO', 'ao.spatial-counting', 4, 'A 4×4×4 large cube is built from unit cubes and all six outer faces are painted. How many unit cubes have exactly one painted face?', '["16","24","36","48"]'::jsonb, 1, 'Unit cubes with exactly one painted face are in the center of each face (not on any edge). Each face of a 4×4×4 cube has (4−2)² = 4 such cubes. Six faces × 4 = 24 cubes with exactly one painted face.', true),
  ('AO-SC-B7-10', 'AO', 'ao.spatial-counting', 4, 'A tower is built: bottom layer is 4×4 (16 cubes), next layer is 3×3 (9 cubes) centered on the first, next is 2×2 (4 cubes), then 1×1 (1 cube). How many unit cubes are in the tower?', '["25","28","30","32"]'::jsonb, 2, 'Total = 16 + 9 + 4 + 1 = 30 cubes.', true),
  ('AO-SC-B7-11', 'AO', 'ao.spatial-counting', 4, 'A 3×3×3 cube has all six faces painted blue. It is then cut into 27 unit cubes. How many unit cubes have NO painted faces at all?', '["0","1","6","8"]'::jsonb, 1, 'The only unit cube with zero painted faces is the one at the very center of the 3×3×3 cube — it is surrounded on all sides and touches no outer face. There is exactly 1 such cube.', true),
  ('AO-SC-B7-12', 'AO', 'ao.spatial-counting', 4, 'An L-shaped structure is built on a table: one arm is 4 cubes long, 1 cube wide, and 1 cube tall. The other arm is 3 cubes long, 1 cube wide, and 2 cubes tall. The two arms share 1 corner cube. How many total cubes are in the structure?', '["9","10","11","13"]'::jsonb, 0, 'Arm 1 is 4 cubes long × 1 cube wide × 1 cube tall = 4 cubes. Arm 2 is 3 cubes long × 1 cube wide × 2 cubes tall = 6 cubes. The two arms share exactly 1 corner cube at their junction. Total = 4 + 6 − 1 = 9 cubes.', true),
  ('AO-SC-B7-13', 'AO', 'ao.spatial-counting', 3, 'A 4×4×4 large cube is built from unit cubes and all six outer faces are painted. How many unit cubes have exactly two painted faces?', '["12","24","36","48"]'::jsonb, 1, 'Unit cubes with exactly two painted faces lie on the edges of the large cube but not at corners. A cube has 12 edges; each edge of a 4×4×4 cube has (4−2) = 2 non-corner cubes. Total: 12 × 2 = 24 cubes with exactly two painted faces.', true),
  ('AO-SC-B7-14', 'AO', 'ao.spatial-counting', 3, 'From the front, a structure appears as: 3 cubes across on the bottom row, 2 cubes in the middle row (centered), 1 cube on top (centered). Each stack is 1 cube deep. How many total cubes are in this pyramid viewed from the side?', '["4","5","6","9"]'::jsonb, 2, 'Bottom row: 3 cubes. Middle row: 2 cubes. Top: 1 cube. Total = 3 + 2 + 1 = 6 cubes (each 1 cube deep as stated).', true),
  ('AR-B7-D5-1', 'AR', 'ar.word-problems', 5, 'A contractor charges a flat fee of $120 plus $45 per hour. A second contractor charges $60 per hour with no flat fee. For what number of hours will both contractors charge the same total amount?', '["4 hours","6 hours","8 hours","10 hours"]'::jsonb, 2, 'Set equal: 120 + 45h = 60h. 120 = 15h. h = 8 hours.', true),
  ('AR-B7-D5-2', 'AR', 'ar.ratio-proportion', 5, 'A gear with 18 teeth meshes with a gear with 45 teeth. If the smaller gear rotates at 250 rpm, how fast does the larger gear rotate?', '["80 rpm","100 rpm","125 rpm","150 rpm"]'::jsonb, 1, 'Gear speed is inversely proportional to tooth count. Larger gear speed = 250 × (18/45) = 250 × 0.4 = 100 rpm.', true),
  ('AR-B7-D5-3', 'AR', 'ar.percent', 5, 'A soldier''s test score was reduced by 12% due to a grading error. After the error was corrected, the score was increased by 20% of the reduced score. The original score was 250. What is the final corrected score?', '["250.0","264.0","247.2","270.0"]'::jsonb, 1, 'Reduced score = 250 × 0.88 = 220. After 20% increase: 220 × 1.20 = 264. The trap is thinking the two percentages cancel to 8% net gain on the original.', true),
  ('AR-B7-D5-4', 'AR', 'ar.rate-distance-time', 5, 'Two soldiers start at the same point and walk in the same direction. Soldier A walks at 4 mph; Soldier B walks at 6 mph. Soldier B starts 30 minutes after Soldier A. How long after B starts does B catch up with A?', '["45 minutes","1 hour","1 hour 15 minutes","1 hour 30 minutes"]'::jsonb, 1, 'A''s head start = 4 × 0.5 = 2 miles. B closes at 6 − 4 = 2 mph. Catch-up time = 2 ÷ 2 = 1 hour after B starts.', true),
  ('AR-B7-D5-5', 'AR', 'ar.arithmetic-fundamentals', 5, 'A barrel holds 84 gallons. A pump fills it at 7 gallons per minute, but a leak drains it at 1.75 gallons per minute. Starting empty, how many minutes does it take to fill the barrel?', '["12 minutes","14 minutes","16 minutes","18 minutes"]'::jsonb, 2, 'Net fill rate = 7 − 1.75 = 5.25 gal/min. Time = 84 ÷ 5.25 = 16 minutes.', true),
  ('AR-B7-D5-6', 'AR', 'ar.word-problems', 5, 'Three workers can paint a room in 6 hours. Two of the workers leave after 2 hours. The remaining worker finishes alone. How many total hours does the job take?', '["12 hours","14 hours","16 hours","18 hours"]'::jsonb, 1, 'Combined rate of 3 workers = 1/6 room/hour. In 2 hours they complete 2 × (1/6) = 1/3 of the room. Remaining = 2/3. One worker''s rate = 1/18 room/hour. Time for 1 worker to finish 2/3 = (2/3) ÷ (1/18) = 12 hours. Total = 2 + 12 = 14 hours.', true),
  ('AR-B7-D5-7', 'AR', 'ar.rate-distance-time', 5, 'A boat travels 48 miles upstream in 4 hours and the same distance downstream in 3 hours. What is the speed of the current?', '["2 mph","3 mph","4 mph","5 mph"]'::jsonb, 0, 'Upstream speed = 48/4 = 12 mph. Downstream speed = 48/3 = 16 mph. Boat speed in still water = (12+16)/2 = 14 mph. Current speed = (16−12)/2 = 2 mph.', true),
  ('AR-B7-D5-8', 'AR', 'ar.ratio-proportion', 5, 'If 5 machines produce 300 widgets in 4 hours, how many machines are needed to produce 540 widgets in 3 hours?', '["9","10","12","15"]'::jsonb, 2, 'Rate per machine = 300 / (5 × 4) = 15 widgets/machine/hour. In 3 hours one machine makes 15 × 3 = 45 widgets. Machines needed = 540 / 45 = 12.', true),
  ('WK-B7-D5-2', 'WK', 'wk.synonyms', 5, 'INVETERATE most nearly means:', '["Recently reformed","Deeply experienced","Long-established and unlikely to change","Violently opposed"]'::jsonb, 2, 'Inveterate means having a habit or activity deeply embedded by long practice; firmly established. ''Deeply experienced'' is tempting but misses the key meaning of habitual permanence.', true),
  ('WK-B7-D5-3', 'WK', 'wk.context-clues', 5, 'In the sentence ''The diplomat''s ANODYNE speech avoided any statement that might offend either side, leaving the audience with nothing to applaud or protest,'' the word ANODYNE most nearly means:', '["Highly persuasive","Inoffensive to the point of being dull","Deeply critical of both parties","Remarkably brief"]'::jsonb, 1, 'Anodyne means not likely to cause offense or controversy; bland or inoffensive. The context clue ''nothing to applaud or protest'' confirms that the speech provoked neither agreement nor disagreement — it was deliberately dull.', true),
  ('WK-B7-D5-4', 'WK', 'wk.prefixes-suffixes', 5, 'The word PUSILLANIMOUS contains the Latin root ANIM (spirit/soul) and the prefix PUSILL- (very small). PUSILLANIMOUS most nearly means:', '["Extremely generous of spirit","Showing a lack of courage; cowardly","Spiritually enlightened","Overly animated or energetic"]'::jsonb, 1, 'Pusillanimous literally means ''small-souled'' — lacking courage or resolution; timid. The root ANIM (soul/spirit) combined with PUSILL- (tiny) points to a shrunken spirit, i.e., cowardice.', true),
  ('WK-B7-D5-5', 'WK', 'wk.root-words', 5, 'The root PATER (father) appears in PATERNALISTIC. A PATERNALISTIC policy is one that:', '["Grants full autonomy to individuals","Restricts freedom supposedly for people''s own good, like a father deciding for a child","Applies equally to all family members","Traces authority through the maternal line"]'::jsonb, 1, 'Paternalistic describes authority that limits individual freedom in a way a father might control a child''s choices — ostensibly for their benefit. It carries a connotation of over-control rather than equality.', true),
  ('WK-B7-D5-6', 'WK', 'wk.synonyms', 5, 'SANGUINE most nearly means:', '["Pessimistic about the future","Optimistic and positive","Relating to blood or violence","Slow and deliberate"]'::jsonb, 1, 'Sanguine means optimistic, especially in a difficult situation. Although it derives from the Latin word for blood (a sanguine complexion was historically linked to a cheerful temperament), in modern usage it consistently means having a positive outlook. ''Relating to blood'' is the etymological trap.', true),
  ('PC-B7-D5-1', 'PC', 'pc.inference', 5, 'Passage: ''The town council voted unanimously to fund the new water treatment plant, citing both aging infrastructure and rising contaminant levels. However, the project manager noted that costs had already exceeded projections by 40%, and the mayor quietly asked engineers to explore a scaled-back alternative.'' What can most reasonably be inferred from this passage?', '["The council regrets its decision to fund the project","The mayor supports the original project without reservation","Concerns about cost may lead to a modified or reduced project scope","Rising contaminant levels have been resolved by the council vote"]'::jsonb, 2, 'The mayor''s request to ''explore a scaled-back alternative'' combined with costs 40% over budget strongly implies the original plan may be modified. The council vote shows approval in principle, not necessarily for the original scope. Contaminants are not yet resolved — the plant is only approved, not built.', true),
  ('PC-B7-D5-2', 'PC', 'pc.author-tone-purpose', 5, 'Passage: ''Proponents claim the new regulation will protect consumers, but a closer examination reveals that its provisions were drafted almost entirely by the industries it purports to regulate. The oversight committee, composed largely of former industry executives, approved it in a single closed session. Whether this constitutes governance or theater is left as an exercise for the reader.'' What is the author''s tone?', '["Optimistic and encouraging","Objective and purely informational","Sardonic and skeptical","Alarmed and urgent"]'::jsonb, 2, 'The phrase ''left as an exercise for the reader'' is an ironic rhetorical device implying the answer is obvious without stating it. Combined with ''theater'' and the point about industry drafting its own regulations, the tone is sardonic skepticism, not neutral reporting or alarm.', true),
  ('PC-B7-D5-3', 'PC', 'pc.main-idea', 5, 'Passage: ''Urban heat islands form when dense concentrations of pavement, buildings, and human activity replace natural land cover. Cities can be up to 7°F warmer than surrounding rural areas. While tree-planting campaigns are popular, researchers find that highly reflective roof coatings — though less photogenic — reduce surface temperatures more efficiently per dollar invested. Policy makers who overlook this evidence in favor of visible green initiatives may be choosing optics over outcomes.'' What is the main idea?', '["Urban heat islands are caused primarily by industrial pollution","Tree-planting is the most cost-effective solution to urban overheating","Reflective roof coatings are more cost-efficient than tree planting at reducing urban heat, but are less politically appealing","Policy makers should avoid all green initiatives until more research is available"]'::jsonb, 2, 'The passage contrasts the popularity of tree planting with the superior cost-efficiency of reflective coatings, and explicitly criticizes policy makers who prioritize visible green projects. The main idea is that reflective roofs outperform trees economically but lose on optics.', true),
  ('PC-B7-D5-4', 'PC', 'pc.detail-recall', 5, 'Passage: ''The permafrost beneath Siberian tundra holds an estimated 1.5 trillion tons of organic carbon — roughly twice the amount currently in the atmosphere. As average temperatures rise, permafrost thaws and the organic material decomposes, releasing carbon dioxide and methane. Methane is approximately 86 times more potent than CO₂ as a greenhouse gas over a 20-year period, though its atmospheric lifetime is shorter. Scientists warn this feedback loop could accelerate warming in ways that current climate models may underestimate.'' According to the passage, how much more potent is methane than CO₂ as a greenhouse gas over 20 years?', '["20 times","50 times","86 times","100 times"]'::jsonb, 2, 'The passage explicitly states methane is ''approximately 86 times more potent than CO₂ as a greenhouse gas over a 20-year period.'' This is a direct detail-recall question.', true),
  ('PC-B7-D5-5', 'PC', 'pc.inference', 5, 'Passage: ''The pharmaceutical company released its Phase 2 trial results, showing a 34% reduction in symptom severity versus placebo. Analysts noted, however, that the trial enrolled only 80 participants and excluded patients over 65 and those with common comorbidities. The FDA typically requires Phase 3 trials of 300–3,000 participants before approval.'' What can be most reasonably inferred?', '["The drug will likely receive FDA approval within one year","The Phase 2 results are fraudulent","The drug''s effectiveness in the broader population remains uncertain, and further trials are required","Excluding older patients proves the drug is ineffective for them"]'::jsonb, 2, 'The small sample size, exclusion criteria, and the FDA''s Phase 3 requirement together imply the current evidence is insufficient to establish broad effectiveness. Inference C directly follows from the stated facts without overstating.', true),
  ('PC-B7-D5-6', 'PC', 'pc.author-tone-purpose', 5, 'Passage: ''Advocates of universal basic income point to pilot programs in Finland and Kenya as proof of concept. Critics counter that these experiments are too small, too short, and too generously funded to scale globally. Both sides marshal the same limited data to opposite conclusions, a reminder that in policy debates, the evidence rarely speaks for itself.'' What is the author''s primary purpose?', '["To advocate for universal basic income","To discredit the critics of universal basic income","To highlight that the same evidence supports opposing conclusions, illustrating limits of policy data","To explain why pilot programs in Finland and Kenya succeeded"]'::jsonb, 2, 'The author presents both sides neutrally and concludes with ''evidence rarely speaks for itself'' — signaling the purpose is to show how disputed evidence functions in policy debates, not to take a side.', true),
  ('PC-B7-D5-7', 'PC', 'pc.main-idea', 5, 'Passage: ''Sleep deprivation does not merely cause fatigue. Research links chronic short sleep to increased risk of cardiovascular disease, metabolic disorders, and impaired immune response. Cognitive effects include reduced working memory, slower reaction time, and impaired judgment — the last of which may be the most dangerous because sleep-deprived individuals consistently underestimate their own impairment. A person who has slept 6 hours may feel alert while performing at the level of someone legally drunk.'' What is the main idea of this passage?', '["Six hours of sleep is sufficient for most adults","Sleep deprivation causes serious physical and cognitive harm, made worse by impaired self-awareness of that harm","Fatigue is the primary danger of insufficient sleep","Legal intoxication limits should apply to sleep-deprived drivers"]'::jsonb, 1, 'The passage covers multiple harms (cardiovascular, metabolic, cognitive) and emphasizes that the most insidious aspect is that sufferers don''t realize how impaired they are. The main idea is the breadth and self-concealing nature of sleep deprivation''s harms.', true),
  ('MK-B7-D5-1', 'MK', 'mk.algebra-linear', 5, 'A soldier has twice as many push-ups completed as sit-ups. If he does 12 more sit-ups, both totals will be equal. How many push-ups did he complete originally?', '["12","18","24","36"]'::jsonb, 2, 'Let sit-ups = s, push-ups = 2s. Setting equal after 12 more sit-ups: 2s = s + 12. s = 12. Push-ups = 2(12) = 24.', true),
  ('MK-B7-D5-2', 'MK', 'mk.geometry', 5, 'A right triangle has legs of 5 cm and 12 cm. A square is constructed on the hypotenuse. What is the area of that square?', '["60 cm²","119 cm²","144 cm²","169 cm²"]'::jsonb, 3, 'Hypotenuse = √(5² + 12²) = √(25 + 144) = √169 = 13 cm. Area of square on hypotenuse = 13² = 169 cm².', true),
  ('MK-B7-D5-3', 'MK', 'mk.exponents-polynomials', 5, 'Simplify: (2x²y)³ ÷ (4x³y²)', '["2x³y","2x²y","x³y","2xy³"]'::jsonb, 0, 'Numerator: (2x²y)³ = 2³ · x⁶ · y³ = 8x⁶y³. Divide by 4x³y²: (8/4) · x^(6−3) · y^(3−2) = 2x³y.', true),
  ('MK-B7-D5-4', 'MK', 'mk.fractions-decimals', 5, 'A tank is 3/8 full. After adding 45 gallons it is 5/8 full. What is the total capacity of the tank?', '["120 gallons","150 gallons","180 gallons","210 gallons"]'::jsonb, 2, 'The added 45 gallons filled 5/8 − 3/8 = 2/8 = 1/4 of the tank. Total capacity = 45 ÷ (1/4) = 45 × 4 = 180 gallons.', true),
  ('MK-B7-D5-5', 'MK', 'mk.number-properties', 5, 'The sum of three consecutive odd integers is 111. What is the largest of the three integers?', '["35","37","39","41"]'::jsonb, 2, 'Let the integers be n, n+2, n+4. Sum: 3n + 6 = 111. 3n = 105. n = 35. Largest = 35 + 4 = 39.', true),
  ('MK-B7-D5-6', 'MK', 'mk.algebra-linear', 5, 'If 2/3 of a number equals 4/5 of another number, and the first number is 60, what is the second number?', '["40","48","50","72"]'::jsonb, 2, '2/3 × 60 = 40. Set 4/5 × n = 40. n = 40 × 5/4 = 50.', true),
  ('MK-B7-D5-7', 'MK', 'mk.geometry', 5, 'A rectangular room is 15 feet long and 10 feet wide. A diagonal brace runs from one corner to the opposite corner. What is the length of the brace, to the nearest whole foot?', '["16 feet","17 feet","18 feet","19 feet"]'::jsonb, 2, 'Diagonal = √(15² + 10²) = √(225 + 100) = √325 ≈ 18.03 feet, which rounds to 18 feet.', true),
  ('AO-PF-B7-18', 'AO', 'ao.paper-folding-nets', 2, 'A square sheet of paper has its four corners labeled A (top-left), B (top-right), C (bottom-right), and D (bottom-left). The sheet is folded by bringing corner B down to meet corner D (a diagonal fold along the line from A to C). Which shape does the folded paper form?', '["A smaller square","A right triangle with the right angle at corner A","A right triangle with vertices at A, the merged B-D point, and C","A rectangle"]'::jsonb, 2, 'Folding B to meet D folds along the diagonal AC. The two non-diagonal corners (B and D) come together while A and C remain at their positions. The result is a right triangle whose vertices are A, C, and the merged B-D point.', true),
  ('AO-PF-B7-19', 'AO', 'ao.paper-folding-nets', 5, 'Six squares form a cube net in this arrangement: square 1 is in the top-left position. Square 2 is to the right of square 1. Square 6 is to the right of square 2. Square 3 is below square 2. Square 4 is to the right of square 3. Square 5 is above square 4 (same column as 4, sharing square 4''s top edge). When folded into a cube, which square is opposite square 1?', '["Square 4","Square 5","Square 6","Square 3"]'::jsonb, 2, 'Assign square 2 as the base. Square 1 (left of 2) folds up to become the left wall. Square 6 (right of 2) folds up to become the right wall. Square 3 (below 2) folds up to become the front wall. Square 4 (right of 3): when 3 is the front wall, square 4 is on 3''s right edge and folds to become the top. Square 5 (above 4): when 4 is the top, square 5 folds to become the back wall. Face assignments: bottom=2, top=4, left=1, right=6, front=3, back=5. Opposite left (1) = right (6) = choice c, index 2.', true),
  ('AO-PF-B7-20', 'AO', 'ao.paper-folding-nets', 5, 'A rectangular sheet (2 units wide, 4 units tall) is folded in half by bringing the top edge to the bottom edge (horizontal fold → 2×2 square). Then folded again bringing the top edge to the bottom edge (another horizontal fold → 2×1 rectangle, four layers). A hole is punched at the center of this 2×1 rectangle through all layers. When fully unfolded, how many holes appear and how are they arranged?', '["One hole in the center of the sheet","Two holes side by side across the middle of the sheet","Four holes in a vertical column at the sheet''s horizontal center","Four holes in a 2×2 grid"]'::jsonb, 2, 'Fold 1 (top→bottom) stacks top half on bottom half — two layers. Fold 2 (top→bottom of the 2×2 square) stacks upper quarter on lower quarter — four layers. The punch hits four positions that unfold into a vertical column of 4 holes, spaced at equal intervals along the sheet''s vertical axis, all at the horizontal center.', true),
  ('AO-SC-B7-18', 'AO', 'ao.spatial-counting', 5, 'A 5×5×5 large cube is painted on all outer faces and then cut into 125 unit cubes. How many unit cubes have exactly one painted face?', '["36","48","54","72"]'::jsonb, 2, 'Unit cubes with exactly one painted face sit at the center of each outer face (not on any edge). Each face of a 5×5×5 cube has (5−2)² = 9 such cubes. Six faces × 9 = 54 unit cubes with exactly one painted face.', true),
  ('AO-SC-B7-19', 'AO', 'ao.spatial-counting', 5, 'A hollow open-top box is built from unit cubes: outer dimensions are 4 wide × 4 deep × 3 tall, with walls and bottom exactly 1 unit thick and no top face. How many unit cubes make up this box?', '["28","36","40","48"]'::jsonb, 2, 'Bottom layer (solid 4×4) = 16 cubes. Each of the 2 upper layers has walls only (outer 4×4 minus inner hollow 2×2) = 12 cubes per layer. Two upper layers: 12 × 2 = 24 cubes. Total = 16 + 24 = 40 cubes.', true),
  ('AO-SC-B7-20', 'AO', 'ao.spatial-counting', 5, 'A 4×4×4 large cube painted on all six outer faces is cut into 64 unit cubes. How many unit cubes have zero painted faces?', '["0","4","8","16"]'::jsonb, 2, 'The interior of a 4×4×4 cube consists of (4−2)³ = 2³ = 8 unit cubes completely surrounded by other cubes, touching no outer face and therefore having zero painted faces.', true),
  ('AO-3D-B7-18', 'AO', 'ao.3d-visualization', 2, 'A cube: top = silver, bottom = gold, front = red, back = blue, left = green, right = white. The cube is rotated 180° around the vertical axis (spinning a half-turn so the front face goes all the way to the back). What color is now facing you (front)?', '["Red","Blue","Green","White"]'::jsonb, 1, 'A 180° rotation around the vertical axis swaps front and back, and swaps left and right, while top and bottom remain unchanged. The original back face (blue) becomes the new front.', true);
commit;
